-- ----------------------------
-- Table structure for fact_admn_mdc_htr_rcd
-- ----------------------------
DROP TABLE IF EXISTS `fact_admn_mdc_htr_rcd`;
CREATE TABLE `fact_admn_mdc_htr_rcd`  (
  `PRM_KEY` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键，唯一标识一条入院病历记录，可能由多个字段拼接形成',
  `MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '医疗机构代码',
  `MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '医疗机构名称',
  `ADMN_MDC_HTR_RCD_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '入院病历记录编号',
  `INHOS_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '住院号',
  `PTT_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '患者姓名',
  `CHF_COMPLNT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主诉',
  `PST_ILLNS_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '现病史',
  `DSES_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '疾病史(含外伤)',
  `ODNR_HLTH_CDT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '一般健康状况标志',
  `PTT_INFCT_FLG` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '患者传染性标志：0否，1是',
  `INFCT_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '传染病史',
  `PVT_INCLT_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '预防接种史',
  `OPRT_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '手术史',
  `TRSFS_BLD_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '输血史',
  `ALGN_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '过敏史',
  `PSN_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '个人史',
  `MRTL_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '婚育史',
  `MST_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '月经史',
  `FML_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '家族史',
  `FEED_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '喂养史',
  `BTH_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '出生史',
  `OTHR_PAST_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '其他既往史',
  `BRF_DSES_HST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '简要病史',
  `TPR` float NULL DEFAULT NULL COMMENT '体温(℃)',
  `HRT_RATE` float NULL DEFAULT NULL COMMENT '心率(次/min)',
  `PLS_RATE` float NULL DEFAULT NULL COMMENT '脉率(次/分)',
  `BRTH_FRQ` float NULL DEFAULT NULL COMMENT '呼吸频率(次/min)',
  `STLC_PRS` float NULL DEFAULT NULL COMMENT '收缩压(mmHg)',
  `DTLC_PRS` float NULL DEFAULT NULL COMMENT '舒张压(mmHg)',
  `HGT` float NULL DEFAULT NULL COMMENT '身高(cm)',
  `WGT` float NULL DEFAULT NULL COMMENT '体重(kg)',
  `PSQ_EXAM` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '体格检查',
  `PSQ_EXAM_BDY_SLN_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '体格检查-全身浅表淋巴结检查结果',
  `PSQ_EXAM_HEAD_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '体格检查-头部及其器官检查结果',
  `PSQ_EXAM_NRV_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '体格检查-神经系统检查结果',
  `PSQ_EXAM_NECK_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '体格检查-颈部检查结果',
  `PSQ_EXAM_THRX_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '体格检查-胸部检查结果',
  `PSQ_EXAM_ABDM_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '体格检查-腹部检查结果',
  `ODNR_CDT_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '一般状况检查结果',
  `SKIN_MCS_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '皮肤和粘膜检查结果',
  `ANS_TCH_EXAM_RSLT_DSCPT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '肛门指诊检查结果描述',
  `GNT_EXAM_RSLT_DSCPT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '外生殖器检查结果描述',
  `SPN_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '脊柱检查结果',
  `LMBS_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '四肢检查结果',
  `SPCLST_CDT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '专科情况',
  `AXLR_EXAM_RSLT_DSCPT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '辅助检查结果描述',
  `AXLR_EXAM_ESPCL` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '辅助检查-特殊检查',
  `AXLR_EXAM_PTHLG` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '辅助检查-病理检查',
  `OTHR_AXLR_EXAM` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '其他辅助检查',
  `TCM_FOUR_DIAG_OBSV_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '中医“四诊”观察结果',
  `TPAM_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '治则治法代码',
  `TPAM_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '治则治法名称',
  `DOSD_GST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '辨证依据',
  `DOSD_TP_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '辨证分型代码',
  `DOSD_TP_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '辨证分型名称',
  `DSES_HST_RPST_STFF_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '病史陈述者姓名',
  `RPST_STFF_PTT_RLT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '陈述者与患者的关系代码',
  `RPST_STFF_PTT_RLT_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '陈述者与患者的关系名称',
  `RPST_CTT_RLB_FLG` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '陈述内容可靠标志：0否，1是',
  `ADMN_DT_TM` datetime NULL DEFAULT NULL COMMENT '入院日期时间',
  `DSCG_DT_TM` datetime NULL DEFAULT NULL COMMENT '出院日期时间',
  `RCD_DT_TM` datetime NULL DEFAULT NULL COMMENT '记录日期时间',
  `CRT_TM` datetime NOT NULL COMMENT '创建时间',
  `CRT_STFF_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建职工工号',
  `CRT_STFF_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建职工姓名',
  `UPD_DT` datetime NULL DEFAULT NULL COMMENT '更新日期',
  `UPD_MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新医疗机构代码',
  `UPD_MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新医疗机构名称',
  `UPD_STFF_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新职工工号',
  `UPD_STFF_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新职工姓名',
  `INVLD_FLG` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '作废标识：0否，1是，2逻辑删除',
  PRIMARY KEY (`PRM_KEY`) USING BTREE,
  INDEX `IDX_FACT_ADMN_MDC_HTR_RCD_01`(`INHOS_NO` ASC) USING BTREE,
  INDEX `IDX_FACT_ADMN_MDC_HTR_RCD_02`(`ADMN_MDC_HTR_RCD_NO` ASC) USING BTREE,
  INDEX `IDX_FACT_ADMN_MDC_HTR_RCD_03`(`RCD_DT_TM` ASC) USING BTREE,
  INDEX `IDX_FACT_ADMN_MDC_HTR_RCD_04`(`MDC_ORG_CD` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '入院病历记录' ROW_FORMAT = DYNAMIC;

