-- ----------------------------
-- Table structure for fact_cstt_rcd
-- ----------------------------
DROP TABLE IF EXISTS `fact_cstt_rcd`;
CREATE TABLE `fact_cstt_rcd`  (
  `PRM_KEY` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键，可能由多个字段拼接形成，识别唯一记录',
  `MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '医疗机构代码',
  `MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '医疗机构名称',
  `ELCTRNC_APL_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '电子申请单编号',
  `CSTT_RCD_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会诊记录单号',
  `PTT_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '患者姓名',
  `GDR_CD` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '性别代码',
  `GDR_NM` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '性别名称',
  `AGE` int NOT NULL COMMENT '年龄',
  `AGE_UNT` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '年龄单位',
  `OTPT_EMG_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '门急诊号',
  `INHOS_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '住院号',
  `DPT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '科室代码',
  `DPT_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '科室名称',
  `WRD_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '病区代码',
  `WRD_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '病区名称',
  `ROOM_NM` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '病房名称',
  `BED_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '病床号',
  `MDC_HTR_SMRY` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '病历摘要',
  `AXLR_EXAM_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '辅助检查结果',
  `TCM_FOUR_DIAG_OBSV_RSLT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '中医四诊观察结果',
  `WTM_DIAG_NM` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '西医诊断名称',
  `WTM_DIAG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '西医诊断编码',
  `TCM_DSES_NM` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '中医病名名称',
  `TCM_DSES_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '中医病名代码',
  `TCM_SPTM_NM` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '中医证候名称',
  `TCM_SPTM_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '中医证候代码',
  `TPAM_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '治则治法代码',
  `TPAM_NM` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '治则治法名称',
  `DIAG_TRTMT_PRCS_NM` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '诊疗过程名称',
  `DIAG_TRTMT_PRCS_DSCPT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '诊疗过程描述',
  `CSTT_TP` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '会诊类型',
  `CSTT_CAS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '会诊原因',
  `CSTT_PPS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '会诊目的',
  `CSTT_SGST` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '会诊意见',
  `APL_DT_TM` datetime NOT NULL COMMENT '申请日期时间',
  `APL_DCT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请医生工号',
  `APL_DCT_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请医生姓名',
  `APL_DPT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请科室代码',
  `APL_DPT_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请科室名称',
  `APL_MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请医疗机构代码',
  `APL_MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请医疗机构名称',
  `RSVT_CSTT_DT` datetime NULL DEFAULT NULL COMMENT '预会诊日期',
  `CSTT_MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会诊医疗机构代码',
  `CSTT_MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会诊医疗机构名称',
  `CSTT_DPT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会诊科室代码',
  `CSTT_DPT_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会诊科室名称',
  `CSTT_DCT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会诊医生代码',
  `CSTT_DCT_SGNT` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '会诊医师签名',
  `CSTT_DT_TM` datetime NOT NULL COMMENT '会诊日期时间',
  `ADT_TM` datetime NULL DEFAULT NULL COMMENT '审核时间',
  `ADT_STFF_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核职工工号',
  `ADT_STFF_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核职工姓名',
  `ADT_PASS_FLG` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核通过标识：0否，1是',
  `CRT_TM` datetime NOT NULL COMMENT '创建时间',
  `CRT_STFF_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建职工工号',
  `CRT_STFF_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建职工姓名',
  `UPD_DT` datetime NULL DEFAULT NULL COMMENT '更新日期',
  `UPD_MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新医疗机构代码',
  `UPD_MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新医疗机构名称',
  `UPD_STFF_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新职工工号',
  `UPD_STFF_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新职工姓名',
  `INVLD_FLG` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '作废标识：0否，1是，2逻辑删除',
  `DCMT_FMT` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '文档格式',
  `DCMT_CTT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '文档内容',
  PRIMARY KEY (`PRM_KEY`) USING BTREE,
  INDEX `IDX_FACT_CSTT_RCD_01`(`INHOS_NO` ASC) USING BTREE,
  INDEX `IDX_FACT_CSTT_RCD_02`(`ELCTRNC_APL_NO` ASC) USING BTREE,
  INDEX `IDX_FACT_CSTT_RCD_03`(`CSTT_RCD_NO` ASC) USING BTREE,
  INDEX `IDX_FACT_CSTT_RCD_04`(`APL_DT_TM` ASC) USING BTREE,
  INDEX `IDX_FACT_CSTT_RCD_05`(`CSTT_DT_TM` ASC) USING BTREE,
  INDEX `IDX_FACT_CSTT_RCD_06`(`MDC_ORG_CD` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '会诊记录' ROW_FORMAT = DYNAMIC;

