INSERT INTO `fact_cstt_rcd` VALUES ('CSTT001', 'H001', '海南医院', 'APL001', 'CSTR001', '张三', '1', '男', 35, '岁', 'EMG001', 'IN001', 'D01', '内科', 'W01', '一区', 'A座101', '01', '患者发热咳嗽3天，肺部感染可能。', '血常规提示白细胞升高，胸片示右下肺炎症。', '望闻问切示咳嗽、咽红、舌红苔薄黄。', '社区获得性肺炎', 'J18', '咳嗽病', 'TCM001', '风热犯肺证', 'TCMS001', 'TP001', '清热宣肺', '抗感染治疗', '入院后予抗感染、补液及对症治疗，现申请呼吸科会诊进一步指导用药。', '院内会诊', '发热咳嗽持续，影像提示肺炎。', '明确诊断并优化抗感染方案。', '建议继续抗感染治疗，完善痰培养及炎症指标复查。', '2025-01-01 11:00:00', 'DOC101', '林医生', 'D01', '内科', 'H001', '海南医院', '2025-01-01 14:00:00', 'H001', '海南医院', 'D03', '呼吸科', 'DOC201', '陈主任', '2025-01-01 15:30:00', '2025-01-01 16:00:00', 'ADT001', '审核员甲', '1', '2025-01-01 11:00:00', 'CRT001', '创建人甲', '2025-01-01 16:10:00', 'H001', '海南医院', 'UPD001', '更新人甲', '0', 'TEXT', '会诊记录：建议继续头孢类抗感染，必要时行CT复查。');
INSERT INTO `fact_cstt_rcd` VALUES ('CSTT002', 'H001', '海南医院', 'APL002', 'CSTR002', '李四', '1', '男', 37, '岁', 'EMG002', 'IN002', 'D02', '外科', 'W02', '二区', 'B座202', '05', '患者右下腹疼痛伴恶心呕吐。', '腹部彩超提示阑尾区炎性改变。', '舌淡红，苔白，脉弦。', '急性阑尾炎', 'K35', '腹痛病', 'TCM002', '肠痈证', 'TCMS002', 'TP002', '通里攻下', '围手术期评估', '患者拟行手术治疗，申请麻醉及外科联合会诊。', '多学科会诊', '拟行阑尾切除术前评估。', '评估手术及麻醉风险。', '建议完善术前检查后尽快手术，围手术期加强抗感染。', '2025-01-02 09:30:00', 'DOC102', '黄医生', 'D02', '外科', 'H001', '海南医院', '2025-01-02 10:00:00', 'H001', '海南医院', 'D02', '外科', 'DOC202', '周主任', '2025-01-02 11:00:00', '2025-01-02 11:20:00', 'ADT002', '审核员乙', '1', '2025-01-02 09:30:00', 'CRT002', '创建人乙', '2025-01-02 11:30:00', 'H001', '海南医院', 'UPD002', '更新人乙', '0', 'TEXT', '会诊记录：同意手术方案，建议术前禁食禁饮。');
INSERT INTO `fact_cstt_rcd` VALUES ('CSTT003', 'H002', '三亚医院', 'APL003', 'CSTR003', '王五', '2', '女', 30, '岁', 'EMG003', 'IN003', 'D01', '内科', 'W01', '一区', 'C座303', '08', '患者咳嗽咳痰伴胸闷。', '肺部CT提示左下肺感染灶。', '舌红少苔，脉数。', '肺炎', 'J18', '肺胀', 'TCM003', '痰热壅肺证', 'TCMS003', 'TP003', '清肺化痰', '呼吸支持治疗', '患者氧饱和度波动，申请呼吸科会诊。', '院内会诊', '肺部感染伴轻度低氧。', '指导抗感染及吸氧方案。', '建议持续低流量吸氧，调整抗菌药物，动态复查血气。', '2025-01-03 10:00:00', 'DOC103', '王医生', 'D01', '内科', 'H002', '三亚医院', '2025-01-03 13:00:00', 'H002', '三亚医院', 'D03', '呼吸科', 'DOC203', '刘主任', '2025-01-03 14:10:00', '2025-01-03 14:30:00', 'ADT003', '审核员丙', '1', '2025-01-03 10:00:00', 'CRT003', '创建人丙', '2025-01-03 14:40:00', 'H002', '三亚医院', 'UPD003', '更新人丙', '0', 'TEXT', '会诊记录：建议吸氧、化痰、抗感染并监测血氧。');
