-- ----------------------------
-- Table structure for fact_mdc_rcd_hmpg_oprt
-- ----------------------------
DROP TABLE IF EXISTS `fact_mdc_rcd_hmpg_oprt`;
CREATE TABLE `fact_mdc_rcd_hmpg_oprt`  (
  `PRM_KEY` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键，可能由多个字段拼接形成，识别唯一记录',
  `MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '医疗机构代码',
  `MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '医疗机构名称',
  `MDC_RCD_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '病案号',
  `INHOS_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '住院号',
  `INHOS_TMS` int NOT NULL COMMENT '住院次数',
  `OPRT_SQNC_NO` int NOT NULL COMMENT '手术顺序号',
  `MAIN_OPRT_FLG` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主手术标识：0否，1是',
  `OPRT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '手术及操作编码',
  `OPRT_NM` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '手术及操作名称',
  `OPRT_DT` datetime NOT NULL COMMENT '手术及操作日期',
  `OPRT_LVL_CD` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '手术级别代码',
  `OPRT_LVL_NM` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '手术级别名称',
