-- ----------------------------
-- Table structure for fact_rsc_rcd
-- ----------------------------
DROP TABLE IF EXISTS `fact_rsc_rcd`;
CREATE TABLE `fact_rsc_rcd`  (
  `PRM_KEY` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键，可能由多个字段拼接形成，识别唯一记录',
  `MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '医疗机构代码',
  `MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '医疗机构名称',
  `INHOS_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '住院号',
  `RSC_RCD_NO` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '抢救记录号',
  `CDT_CHG_CDT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '病情变化情况',
  `RSC_WAY` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '抢救措施',
  `INTVT_MTRL_NM` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '介入物名称',
  `OPRT_WAY_DSCPT` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '操作方法描述',
  `OPRT_TMS` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '操作次数',
  `RSC_STRT_DT_TM` datetime NULL DEFAULT NULL COMMENT '抢救开始日期时间',
  `RSC_END_DT_TM` datetime NULL DEFAULT NULL COMMENT '抢救结束日期时间',
  `RSC_DT_TM` datetime NULL DEFAULT NULL COMMENT '抢救日期时间',
  `ATNT_ITM` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '注意事项',
  `PTCPT_RSC_STFF` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '参加抢救人员名单',
  `PFS_TCHNLG_FCT_CGY_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '专业技术职务类别代码',
  `PFS_TCHNLG_FCT_CGY_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '专业技术职务类别名称',
  `DCT_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '医师工号',
  `DCT_SGNT` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '医师签名',
  `CRT_TM` datetime NOT NULL COMMENT '创建时间',
  `CRT_STFF_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建职工工号',
  `CRT_STFF_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建职工姓名',
  `UPD_DT` datetime NULL DEFAULT NULL COMMENT '更新日期',
  `UPD_MDC_ORG_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新医疗机构代码',
  `UPD_MDC_ORG_NM` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新医疗机构名称',
  `UPD_STFF_CD` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新职工工号',
  `UPD_STFF_NM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新职工姓名',
  `INVLD_FLG` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '作废标识：0否，1是，2逻辑删除',
  PRIMARY KEY (`PRM_KEY`) USING BTREE,
  INDEX `IDX_FACT_RSC_RCD_01`(`INHOS_NO` ASC) USING BTREE,
  INDEX `IDX_FACT_RSC_RCD_02`(`RSC_RCD_NO` ASC) USING BTREE,
  INDEX `IDX_FACT_RSC_RCD_03`(`RSC_DT_TM` ASC) USING BTREE,
  INDEX `IDX_FACT_RSC_RCD_04`(`MDC_ORG_CD` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '抢救记录' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of fact_rsc_rcd
-- ----------------------------
INSERT INTO `fact_rsc_rcd` VALUES ('RSC001', 'H001', '海南医院', 'IN001', 'RS001', '患者突发高热伴呼吸急促，血氧下降。', '予吸氧、静脉输液、抗感染及退热处理。', '氧气面罩、头孢曲松、葡萄糖注射液', '面罩吸氧，建立静脉通路后给予抗感染及补液治疗。', '3', '2025-01-01 12:00:00', '2025-01-01 12:45:00', '2025-01-01 12:00:00', '密切监测生命体征及血氧饱和度变化。', '林医生,王护士,李护士', '1', '主任医师', 'DOC101', '林医生', '2025-01-01 12:00:00', 'CRT001', '创建人甲', '2025-01-01 13:00:00', 'H001', '海南医院', 'UPD001', '更新人甲', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC002', 'H001', '海南医院', 'IN002', 'RS002', '患者突发腹痛加重伴呕吐，考虑急腹症进展。', '禁食、补液、抗感染，完善术前准备。', '乳酸林格液、头孢噻肟', '建立静脉通路并快速补液，准备急诊手术。', '2', '2025-01-02 11:30:00', '2025-01-02 12:10:00', '2025-01-02 11:30:00', '注意腹膜刺激征变化，评估手术指征。', '黄医生,周医生,张护士', '2', '主治医师', 'DOC102', '黄医生', '2025-01-02 11:30:00', 'CRT002', '创建人乙', '2025-01-02 12:20:00', 'H001', '海南医院', 'UPD002', '更新人乙', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC003', 'H002', '三亚医院', 'IN003', 'RS003', '患者咳嗽加重伴胸闷，血氧一过性下降。', '给予吸氧、雾化吸入、抗感染治疗。', '雾化器、布地奈德、沙丁胺醇', '持续低流量吸氧，雾化吸入改善气道症状。', '3', '2025-01-03 14:00:00', '2025-01-03 14:40:00', '2025-01-03 14:00:00', '监测呼吸频率、血氧和体温。', '王医生,刘医生,陈护士', '2', '主治医师', 'DOC103', '王医生', '2025-01-03 14:00:00', 'CRT003', '创建人丙', '2025-01-03 15:00:00', 'H002', '三亚医院', 'UPD003', '更新人丙', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC004', 'H002', '三亚医院', 'IN004', 'RS004', '患者气促明显加重，伴喘息。', '吸氧、雾化平喘、静脉激素治疗。', '氧气面罩、甲泼尼龙、异丙托溴铵', '实施面罩吸氧并给予静脉激素及雾化治疗。', '4', '2025-01-04 09:20:00', '2025-01-04 10:10:00', '2025-01-04 09:20:00', '注意监测呼吸困难是否缓解及心率变化。', '赵医生,孙医生,何护士', '1', '主任医师', 'DOC104', '赵医生', '2025-01-04 09:20:00', 'CRT004', '创建人丁', '2025-01-04 10:20:00', 'H002', '三亚医院', 'UPD004', '更新人丁', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC005', 'H003', '海口医院', 'IN005', 'RS005', '患者胸痛突发加重，伴出汗、心率增快。', '予心电监护、吸氧、抗血小板及扩冠治疗。', '硝酸甘油、阿司匹林、氧气面罩', '持续心电监护，舌下含服硝酸甘油并予吸氧处理。', '3', '2025-01-05 10:40:00', '2025-01-05 11:30:00', '2025-01-05 10:40:00', '注意观察胸痛缓解情况及血压变化。', '吴医生,郑医生,刘护士', '1', '主任医师', 'DOC105', '吴医生', '2025-01-05 10:40:00', 'CRT005', '创建人戊', '2025-01-05 11:40:00', 'H003', '海口医院', 'UPD005', '更新人戊', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC006', 'H003', '海口医院', 'IN006', 'RS006', '患者上腹痛明显，伴反酸呕吐。', '补液、抑酸、止吐治疗。', '奥美拉唑、昂丹司琼、葡萄糖氯化钠', '建立静脉通路后给予抑酸、止吐及补液支持。', '3', '2025-01-06 13:10:00', '2025-01-06 13:50:00', '2025-01-06 13:10:00', '观察呕吐次数及腹痛缓解情况。', '孙医生,何医生,周护士', '2', '主治医师', 'DOC106', '孙医生', '2025-01-06 13:10:00', 'CRT006', '创建人己', '2025-01-06 14:00:00', 'H003', '海口医院', 'UPD006', '更新人己', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC007', 'H001', '海南医院', 'IN007', 'RS007', '患者头晕乏力加重，面色苍白。', '补液、吸氧，完善血常规及交叉配血。', '氧气鼻导管、葡萄糖注射液', '鼻导管吸氧并给予补液，准备进一步输血评估。', '2', '2025-01-07 10:20:00', '2025-01-07 11:00:00', '2025-01-07 10:20:00', '注意血压及心率变化，防止晕厥。', '钱医生,冯医生,王护士', '2', '主治医师', 'DOC107', '钱医生', '2025-01-07 10:20:00', 'CRT007', '创建人庚', '2025-01-07 11:10:00', 'H001', '海南医院', 'UPD007', '更新人庚', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC008', 'H002', '三亚医院', 'IN008', 'RS008', '患者高热持续，伴全身酸痛。', '物理降温、补液、抗病毒治疗。', '奥司他韦、冰袋、葡萄糖氯化钠', '给予冰敷降温，静脉补液，并继续抗病毒治疗。', '3', '2025-01-08 11:10:00', '2025-01-08 11:55:00', '2025-01-08 11:10:00', '监测体温变化，警惕惊厥。', '李医生,高医生,陈护士', '2', '主治医师', 'DOC108', '李医生', '2025-01-08 11:10:00', 'CRT008', '创建人辛', '2025-01-08 12:05:00', 'H002', '三亚医院', 'UPD008', '更新人辛', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC009', 'H003', '海口医院', 'IN009', 'RS009', '患者腹泻频繁伴轻度脱水，精神差。', '快速补液、纠正电解质紊乱、抗感染处理。', '氯化钠注射液、左氧氟沙星、口服补液盐', '建立静脉通路快速补液，同时给予抗感染及口服补液。', '4', '2025-01-09 14:10:00', '2025-01-09 15:00:00', '2025-01-09 14:10:00', '观察尿量、精神状态及腹泻次数。', '陈医生,梁医生,林护士', '2', '主治医师', 'DOC109', '陈医生', '2025-01-09 14:10:00', 'CRT009', '创建人壬', '2025-01-09 15:10:00', 'H003', '海口医院', 'UPD009', '更新人壬', '0');
INSERT INTO `fact_rsc_rcd` VALUES ('RSC010', 'H001', '海南医院', 'IN010', 'RS010', '患者血糖明显升高，伴乏力口渴。', '补液、胰岛素降糖、监测血糖。', '门冬胰岛素、葡萄糖仪、生理盐水', '静脉补液后皮下注射胰岛素，并动态监测血糖变化。', '3', '2025-01-10 09:40:00', '2025-01-10 10:30:00', '2025-01-10 09:40:00', '警惕低血糖发生，注意复查电解质。', '何医生,马医生,张护士', '1', '主任医师', 'DOC110', '何医生', '2025-01-10 09:40:00', 'CRT010', '创建人癸', '2025-01-10 10:40:00', 'H001', '海南医院', 'UPD010', '更新人癸', '0');

-- ----------------------------
-- Table structure for four_elements_monitoring_record
-- ----------------------------
DROP TABLE IF EXISTS `four_elements_monitoring_record`;
CREATE TABLE `four_elements_monitoring_record`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `hospital_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `factor` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `record_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `severity` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `alert_time` datetime NULL DEFAULT NULL,
  `resolved_time` datetime NULL DEFAULT NULL,
  `handler` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `handler_comment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `related_indicator_id` int NULL DEFAULT NULL,
  `extra_data` json NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of four_elements_monitoring_record
-- ----------------------------

-- ----------------------------
-- Table structure for hospital
-- ----------------------------
DROP TABLE IF EXISTS `hospital`;
CREATE TABLE `hospital`  (
  `id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `hospital_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `hospital_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `region` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `address` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `contact` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `bed_count` int NULL DEFAULT NULL,
  `is_active` int NULL DEFAULT 1,
  `created_at` datetime NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of hospital
