) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of hospital_admission_standard
-- ----------------------------

-- ----------------------------
-- Table structure for indicator
-- ----------------------------
DROP TABLE IF EXISTS `indicator`;
CREATE TABLE `indicator`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `indicator_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `seq` int NULL DEFAULT NULL,
  `scope` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `work_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `rule_logic` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `formula` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `calc_method` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `sql_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `prompt_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `involved_tables` json NULL,
  `numerator_desc` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `denominator_desc` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `numerator_sql` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `denominator_sql` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `is_computable` tinyint(1) NULL DEFAULT NULL,
  `use_llm` tinyint(1) NULL DEFAULT NULL,
  `platform_data_ready` tinyint(1) NULL DEFAULT NULL,
  `priority` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `regex_match` tinyint(1) NULL DEFAULT NULL,
  `regex_rule` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `calc_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  `date_field` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'discharge' COMMENT 'discharge=出院时间, admission=入院时间',
  `template_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'STRUCTURE | STRUCTURE-special | RATE | RATE-special | COMPOSITE',
  `subitem_config` json NULL COMMENT '复合指标子项配置',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 64 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of indicator
-- ----------------------------
INSERT INTO `indicator` VALUES (2, '时空轨迹异常', 'four', '人员要素', 2, '时间阈值：半小时。审核范围：住院', '在系统中维护医师操作记录，设定「同一医师短时间内在不同医疗机构中出现诊疗记录」匹配规则，对超范围业务自动报警。', '某个时间段内医生在不同机构内容开了医嘱信息', '', '', 'sql', '-- 规则：同一医师（身份证号）30分钟内，在不同医疗机构出现诊疗记录\nWITH \n-- 1. 基础职工信息\nstaff AS ( \n    SELECT MDC_ORG_CD,\n           STFF_CD,\n           STFF_NM,\n           ID_CRD_NO\n    FROM DWD_DIM_STFF\n    WHERE INVLD_FLG = \'0\' \n),\n\n-- 2. 门诊处方事件\noutpatient AS ( \n    SELECT PSCP_NO          AS record_id,\n           MDC_ORG_CD,\n           PSCP_OPN_DCT_CD  AS stff_cd,\n           PSCP_OPN_DT      AS event_time,\n           \'门急诊\'         AS source_type,\n           OTPT_EMG_NO      AS otpt_emg_no,\n           PSCP_TP_NM       AS pscp_tp_nm,   -- 处方类型\n           PSCP_NO          AS pscp_no,\n           NULL             AS inhos_no,     -- 住院字段置空\n           NULL             AS odr_itm_nm    -- 医嘱内容置空\n    FROM DWD_FACT_OTPT_PSCP_INFMT\n    WHERE PSCP_OPN_DT >= \'2026-04-01 00:00:00\'\n      AND PSCP_OPN_DT <  \'2026-04-10 00:00:00\'\n      -- AND INVLD_FLG = \'0\'\n      AND RTRN_DRG_FLG = \'0\'                -- 排除退药处方\n),\n\n-- 3. 住院医嘱事件\ninpatient AS ( \n    SELECT ODR_NO          AS record_id,\n           MDC_ORG_CD,\n           ODR_OPN_DCT_CD  AS stff_cd,\n           ODR_OPN_DT_TM   AS event_time,\n           \'住院\'          AS source_type,\n           NULL            AS otpt_emg_no,\n           NULL            AS pscp_tp_nm,\n           NULL            AS pscp_no,\n           INHOS_NO        AS inhos_no,     -- 住院流水号\n           ODR_ITM_NM      AS odr_itm_nm    -- 医嘱内容\n    FROM FACT_INHOS_ODR_INFMT\n    WHERE ODR_OPN_DT_TM >= \'2026-04-01 00:00:00\'\n      AND ODR_OPN_DT_TM <  \'2026-04-10 00:00:00\'\n      -- AND INVLD_FLG = \'0\'\n      -- AND (ODR_CCL_FLG IS NULL OR ODR_CCL_FLG = \'0\')\n),\n\n-- 4. 合并所有事件，并关联职工表获取姓名和身份证号\nall_events AS ( \n    SELECT e.record_id,\n           e.MDC_ORG_CD,\n           e.stff_cd, \n           s.STFF_NM,\n           s.ID_CRD_NO,\n           e.event_time,\n           e.source_type,\n           e.otpt_emg_no,\n           e.pscp_tp_nm,\n           e.pscp_no,\n           e.inhos_no,\n           e.odr_itm_nm\n    FROM ( \n        SELECT * FROM outpatient\n        UNION ALL\n        SELECT * FROM inpatient \n    ) e\n    INNER JOIN staff s \n        ON e.MDC_ORG_CD = s.MDC_ORG_CD\n       AND e.stff_cd   = s.STFF_CD\n),\n\n-- 5. 主执业机构（备案表 t_docter）\nmain_practice AS ( \n    SELECT DOCTOR_IDCARD,\n           DOCTOR_UNITNAME AS main_org_name\n    FROM t_docter \n),\n\n-- 6. 事件关联主执业机构\nevents_with_practice AS ( \n    SELECT ae.*,\n           COALESCE(mp.main_org_name, \'/\') AS main_org_name\n    FROM all_events ae\n    LEFT JOIN main_practice mp \n        ON ae.ID_CRD_NO = mp.DOCTOR_IDCARD \n),\n\n-- 7. 使用窗口函数获取每个医生的上一条记录\nevents_with_prev AS ( \n    SELECT *,\n           LAG(MDC_ORG_CD)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_mdc_org_cd,\n           LAG(event_time)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_event_time,\n           LAG(stff_cd)     OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_stff_cd,    -- 上次开单医师工号\n           LAG(source_type) OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_source_type,\n           LAG(otpt_emg_no) OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_otpt_emg_no,\n           LAG(pscp_tp_nm)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_pscp_tp_nm, -- 上次处方分类类型\n           LAG(pscp_no)     OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_pscp_no\n    FROM events_with_practice \n)\n\n-- 8. 最终筛选违规记录，关联机构名称，输出目标字段\nSELECT e.ID_CRD_NO          AS 开单医师身份证号码,\n       e.STFF_NM            AS 开单医师姓名,\n       e.main_org_name      AS 主执业机构,\n       o1.MDC_ORG_NM        AS 本次开单机构名称,\n       e.stff_cd            AS 本次开单医师工号,\n       e.event_time         AS 本次开单时间,\n       e.source_type        AS 本次诊疗环节,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.otpt_emg_no  ELSE NULL END AS 本次门急诊编号,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.pscp_tp_nm   ELSE NULL END AS 本次处方分类类型,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.pscp_no      ELSE NULL END AS 本次处方编号,\n       o2.MDC_ORG_NM        AS 上次开单机构名称,\n       e.prev_event_time    AS 上次开单时间,\n       e.prev_stff_cd       AS 上次开单医师工号,\n       e.prev_source_type   AS 上次诊疗环节,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_otpt_emg_no ELSE NULL END AS 上次门急诊编号,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_pscp_no     ELSE NULL END AS 上次处方编号,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_pscp_tp_nm  ELSE NULL END AS 上次处方分类类型,\n       TIMESTAMPDIFF(MINUTE, e.prev_event_time, e.event_time) AS 两次时间差分钟\nFROM events_with_prev e\nLEFT JOIN DIM_MDC_ORG o1 ON e.MDC_ORG_CD      = o1.MDC_ORG_CD\nLEFT JOIN DIM_MDC_ORG o2 ON e.prev_mdc_org_cd = o2.MDC_ORG_CD\nWHERE e.event_time >= \'2026-04-07 00:00:00\'\n  AND e.event_time <  \'2026-04-10 00:00:00\'\n  AND e.prev_event_time IS NOT NULL\n  AND e.MDC_ORG_CD <> e.prev_mdc_org_cd\n  AND TIMESTAMPDIFF(MINUTE, e.prev_event_time, e.event_time) <= 30\nORDER BY e.ID_CRD_NO, e.event_time;', '', '[]', '', '', '-- 规则：同一医师（身份证号）30分钟内，在不同医疗机构出现诊疗记录\nWITH \n-- 1. 基础职工信息\nstaff AS ( \n    SELECT MDC_ORG_CD,\n           STFF_CD,\n           STFF_NM,\n           ID_CRD_NO\n    FROM DWD_DIM_STFF\n    WHERE INVLD_FLG = \'0\' \n),\n\n-- 2. 门诊处方事件\noutpatient AS ( \n    SELECT PSCP_NO          AS record_id,\n           MDC_ORG_CD,\n           PSCP_OPN_DCT_CD  AS stff_cd,\n           PSCP_OPN_DT      AS event_time,\n           \'门急诊\'         AS source_type,\n           OTPT_EMG_NO      AS otpt_emg_no,\n           PSCP_TP_NM       AS pscp_tp_nm,   -- 处方类型\n           PSCP_NO          AS pscp_no,\n           NULL             AS inhos_no,     -- 住院字段置空\n           NULL             AS odr_itm_nm    -- 医嘱内容置空\n    FROM DWD_FACT_OTPT_PSCP_INFMT\n    WHERE PSCP_OPN_DT >= \'2026-04-01 00:00:00\'\n      AND PSCP_OPN_DT <  \'2026-04-10 00:00:00\'\n      -- AND INVLD_FLG = \'0\'\n      AND RTRN_DRG_FLG = \'0\'                -- 排除退药处方\n),\n\n-- 3. 住院医嘱事件\ninpatient AS ( \n    SELECT ODR_NO          AS record_id,\n           MDC_ORG_CD,\n           ODR_OPN_DCT_CD  AS stff_cd,\n           ODR_OPN_DT_TM   AS event_time,\n           \'住院\'          AS source_type,\n           NULL            AS otpt_emg_no,\n           NULL            AS pscp_tp_nm,\n           NULL            AS pscp_no,\n           INHOS_NO        AS inhos_no,     -- 住院流水号\n           ODR_ITM_NM      AS odr_itm_nm    -- 医嘱内容\n    FROM FACT_INHOS_ODR_INFMT\n    WHERE ODR_OPN_DT_TM >= \'2026-04-01 00:00:00\'\n      AND ODR_OPN_DT_TM <  \'2026-04-10 00:00:00\'\n      -- AND INVLD_FLG = \'0\'\n      -- AND (ODR_CCL_FLG IS NULL OR ODR_CCL_FLG = \'0\')\n),\n\n-- 4. 合并所有事件，并关联职工表获取姓名和身份证号\nall_events AS ( \n    SELECT e.record_id,\n           e.MDC_ORG_CD,\n           e.stff_cd, \n           s.STFF_NM,\n           s.ID_CRD_NO,\n           e.event_time,\n           e.source_type,\n           e.otpt_emg_no,\n           e.pscp_tp_nm,\n           e.pscp_no,\n           e.inhos_no,\n           e.odr_itm_nm\n    FROM ( \n        SELECT * FROM outpatient\n        UNION ALL\n        SELECT * FROM inpatient \n    ) e\n    INNER JOIN staff s \n        ON e.MDC_ORG_CD = s.MDC_ORG_CD\n       AND e.stff_cd   = s.STFF_CD\n),\n\n-- 5. 主执业机构（备案表 t_docter）\nmain_practice AS ( \n    SELECT DOCTOR_IDCARD,\n           DOCTOR_UNITNAME AS main_org_name\n    FROM t_docter \n),\n\n-- 6. 事件关联主执业机构\nevents_with_practice AS ( \n    SELECT ae.*,\n           COALESCE(mp.main_org_name, \'/\') AS main_org_name\n    FROM all_events ae\n    LEFT JOIN main_practice mp \n        ON ae.ID_CRD_NO = mp.DOCTOR_IDCARD \n),\n\n-- 7. 使用窗口函数获取每个医生的上一条记录\nevents_with_prev AS ( \n    SELECT *,\n           LAG(MDC_ORG_CD)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_mdc_org_cd,\n           LAG(event_time)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_event_time,\n           LAG(stff_cd)     OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_stff_cd,    -- 上次开单医师工号\n           LAG(source_type) OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_source_type,\n           LAG(otpt_emg_no) OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_otpt_emg_no,\n           LAG(pscp_tp_nm)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_pscp_tp_nm, -- 上次处方分类类型\n           LAG(pscp_no)     OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_pscp_no\n    FROM events_with_practice \n)\n\n-- 8. 最终筛选违规记录，关联机构名称，输出目标字段\nSELECT e.ID_CRD_NO          AS 开单医师身份证号码,\n       e.STFF_NM            AS 开单医师姓名,\n       e.main_org_name      AS 主执业机构,\n       o1.MDC_ORG_NM        AS 本次开单机构名称,\n       e.stff_cd            AS 本次开单医师工号,\n       e.event_time         AS 本次开单时间,\n       e.source_type        AS 本次诊疗环节,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.otpt_emg_no  ELSE NULL END AS 本次门急诊编号,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.pscp_tp_nm   ELSE NULL END AS 本次处方分类类型,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.pscp_no      ELSE NULL END AS 本次处方编号,\n       o2.MDC_ORG_NM        AS 上次开单机构名称,\n       e.prev_event_time    AS 上次开单时间,\n       e.prev_stff_cd       AS 上次开单医师工号,\n       e.prev_source_type   AS 上次诊疗环节,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_otpt_emg_no ELSE NULL END AS 上次门急诊编号,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_pscp_no     ELSE NULL END AS 上次处方编号,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_pscp_tp_nm  ELSE NULL END AS 上次处方分类类型,\n       TIMESTAMPDIFF(MINUTE, e.prev_event_time, e.event_time) AS 两次时间差分钟\nFROM events_with_prev e\nLEFT JOIN DIM_MDC_ORG o1 ON e.MDC_ORG_CD      = o1.MDC_ORG_CD\nLEFT JOIN DIM_MDC_ORG o2 ON e.prev_mdc_org_cd = o2.MDC_ORG_CD\nWHERE e.event_time >= \'2026-04-07 00:00:00\'\n  AND e.event_time <  \'2026-04-10 00:00:00\'\n  AND e.prev_event_time IS NOT NULL\n  AND e.MDC_ORG_CD <> e.prev_mdc_org_cd\n  AND TIMESTAMPDIFF(MINUTE, e.prev_event_time, e.event_time) <= 30\nORDER BY e.ID_CRD_NO, e.event_time;', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-05-17 17:29:03', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (3, '多点执业冲突', 'four', '人员要素', 3, '审核范围：住院', '在系统中维护医师多点执业记录，设定「对主执业机构在公立医院的发生民营医院多点执业或诊疗记录」匹配规则，对超范围业务自动报警。', '同一个患者，先后在公立以及民营医院诊治，由同一个医生在公立医院也在民营医院开了医嘱', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (4, '超范围经营', 'four', '机构要素', 4, '审核范围：住院', '资质方面：在系统中维护医疗机构诊疗科目信息，设定「诊断治疗-诊疗科目」匹配规则，对超范围业务自动报警。', '医生开了与该医疗机构诊疗科目不符的诊断', '', '', 'sql', '/* \n前提：\n1）需要将《科目vs诊断代码_v2.xlsx》导入为映射表 MAP_SUBJECT_DIAG_V2\n2）字段设置如下：\n   PROF_CD, LV1_SUBJ_CD, LV1_SUBJ_NM, LV2_SUBJ_CD, LV2_SUBJ_NM, DIAG_CD, DIAG_NM, FREQ\n*/\n\nWITH dept_base AS (\n    SELECT\n        d.MDC_ORG_CD,\n        d.MDC_ORG_NM,\n        d.HSPTL_DPT_CD,\n        d.HSPTL_DPT_NM,\n        d.STDRD_DPT_CD,\n        d.STDRD_DPT_NM\n    FROM DIM_DPT d\n    WHERE (d.STP_USE_FLG IS NULL OR d.STP_USE_FLG <> \'1\')\n),\ndiag_base AS (\n    SELECT\n        i.MDC_ORG_CD,\n        i.MDC_ORG_NM,\n        i.INHOS_NO,\n        i.PID,\n        i.MAIN_DIAG_FLG,\n        i.DIAG_DPT_CD,\n        i.DIAG_DPT_NM,\n        i.DIAG_DCT_CD,\n        i.DIAG_DCT_NM,\n        i.DIAG_CD,\n        i.DIAG_ICD10_CD,\n        i.DIAG_ICD10_NM,\n        i.DIAG_DT\n    FROM FACT_INHOS_DIAG_INFMT i\n    WHERE i.DIAG_ICD10_CD IS NOT NULL\n      AND i.DIAG_ICD10_CD <> \'\'\n),\ndiag_with_dept AS (\n    SELECT\n        b.*,\n        dp.STDRD_DPT_CD,\n        dp.STDRD_DPT_NM\n    FROM diag_base b\n    LEFT JOIN dept_base dp\n        ON b.MDC_ORG_CD = dp.MDC_ORG_CD\n       AND b.DIAG_DPT_CD = dp.HSPTL_DPT_CD\n),\ndiag_match AS (\n    SELECT\n        dwd.*,\n        CASE\n            WHEN EXISTS (\n                SELECT 1\n                FROM MAP_SUBJECT_DIAG_V2 m\n                WHERE m.DIAG_CD = dwd.DIAG_ICD10_CD\n                  AND (\n                        m.PROF_CD = dwd.STDRD_DPT_CD\n                     OR m.LV1_SUBJ_CD = dwd.STDRD_DPT_CD\n                     OR m.LV2_SUBJ_CD = dwd.STDRD_DPT_CD\n                  )\n            ) THEN 1\n            ELSE 0\n        END AS IS_MATCHED\n    FROM diag_with_dept dwd\n)\nSELECT\n    dm.MDC_ORG_CD,\n    dm.MDC_ORG_NM,\n    dm.INHOS_NO,\n    dm.PID,\n    dm.DIAG_DPT_CD,\n    dm.DIAG_DPT_NM,\n    dm.STDRD_DPT_CD,\n    dm.STDRD_DPT_NM,\n    dm.DIAG_DCT_CD,\n    dm.DIAG_DCT_NM,\n    dm.DIAG_CD,\n    dm.DIAG_ICD10_CD,\n    dm.DIAG_ICD10_NM,\n    dm.DIAG_DT,\n    \'诊断代码与机构诊疗科目映射不匹配\' AS ALERT_REASON\nFROM diag_match dm\nWHERE dm.IS_MATCHED = 0;', '', '[]', '', '', '/* \n前提：\n1）需要将《科目vs诊断代码_v2.xlsx》导入为映射表 MAP_SUBJECT_DIAG_V2\n2）字段设置如下：\n   PROF_CD, LV1_SUBJ_CD, LV1_SUBJ_NM, LV2_SUBJ_CD, LV2_SUBJ_NM, DIAG_CD, DIAG_NM, FREQ\n*/\n\nWITH dept_base AS (\n    SELECT\n        d.MDC_ORG_CD,\n        d.MDC_ORG_NM,\n        d.HSPTL_DPT_CD,\n        d.HSPTL_DPT_NM,\n        d.STDRD_DPT_CD,\n        d.STDRD_DPT_NM\n    FROM DIM_DPT d\n    WHERE (d.STP_USE_FLG IS NULL OR d.STP_USE_FLG <> \'1\')\n),\ndiag_base AS (\n    SELECT\n        i.MDC_ORG_CD,\n        i.MDC_ORG_NM,\n        i.INHOS_NO,\n        i.PID,\n        i.MAIN_DIAG_FLG,\n        i.DIAG_DPT_CD,\n        i.DIAG_DPT_NM,\n        i.DIAG_DCT_CD,\n        i.DIAG_DCT_NM,\n        i.DIAG_CD,\n        i.DIAG_ICD10_CD,\n        i.DIAG_ICD10_NM,\n        i.DIAG_DT\n    FROM FACT_INHOS_DIAG_INFMT i\n    WHERE i.DIAG_ICD10_CD IS NOT NULL\n      AND i.DIAG_ICD10_CD <> \'\'\n),\ndiag_with_dept AS (\n    SELECT\n        b.*,\n        dp.STDRD_DPT_CD,\n        dp.STDRD_DPT_NM\n    FROM diag_base b\n    LEFT JOIN dept_base dp\n        ON b.MDC_ORG_CD = dp.MDC_ORG_CD\n       AND b.DIAG_DPT_CD = dp.HSPTL_DPT_CD\n),\ndiag_match AS (\n    SELECT\n        dwd.*,\n        CASE\n            WHEN EXISTS (\n                SELECT 1\n                FROM MAP_SUBJECT_DIAG_V2 m\n                WHERE m.DIAG_CD = dwd.DIAG_ICD10_CD\n                  AND (\n                        m.PROF_CD = dwd.STDRD_DPT_CD\n                     OR m.LV1_SUBJ_CD = dwd.STDRD_DPT_CD\n                     OR m.LV2_SUBJ_CD = dwd.STDRD_DPT_CD\n                  )\n            ) THEN 1\n            ELSE 0\n        END AS IS_MATCHED\n    FROM diag_with_dept dwd\n)\nSELECT\n    dm.MDC_ORG_CD,\n    dm.MDC_ORG_NM,\n    dm.INHOS_NO,\n    dm.PID,\n    dm.DIAG_DPT_CD,\n    dm.DIAG_DPT_NM,\n    dm.STDRD_DPT_CD,\n    dm.STDRD_DPT_NM,\n    dm.DIAG_DCT_CD,\n    dm.DIAG_DCT_NM,\n    dm.DIAG_CD,\n    dm.DIAG_ICD10_CD,\n    dm.DIAG_ICD10_NM,\n    dm.DIAG_DT,\n    \'诊断代码与机构诊疗科目映射不匹配\' AS ALERT_REASON\nFROM diag_match dm\nWHERE dm.IS_MATCHED = 0;', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-05-17 17:30:57', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (5, '收治能力超限', 'four', '机构要素', 5, '审核范围：住院', '在系统中设定「面积-床位-住院收治上限」联动模型，超限自动拦截，通报医保拒绝结算、直至取消机构资质。', '机构面积以及床位数之间的逻辑关系；机构床位数与当日在院患者人数', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (6, '科目零业务监测', 'four', '机构要素', 6, '审核范围：住院', '在系统中设定「机构-诊疗科目-业务量」匹配规则，对单一诊疗科目连续3个月「零」业务量的自动报警。', '医疗机构连续3月无诊疗科目对应的诊断', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (7, '限制类技术核查', 'four', '技术要素', 7, '审核技术来源：国家限制性目录；审核范围：住院', '限制类技术备案情况与系统进一步关联，建立「限制类技术备案记录-备案医师-技术开展」匹配规则，对超范围业务自动报警。', '对开展限制性技术的机构、医生的范围进行审核', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (8, '诊疗异常聚集', 'four', '技术要素', 8, '审核指标：主诊和主手；审核范围：住院；审核粒度：最细粒度', '在系统中维护医疗机构诊断、手术等统计功能，建立「连续三个月内单一医疗机构单一诊断和单一术式占比超过全院50%」统计报警规则。', '在一定时间范围内，对医院开展的诊断、手术频率进行统计。', '', '', 'sql', 'WITH all_data AS (\n    SELECT\n        DATE_FORMAT(CRT_TM, \'%Y-%m-01\') AS month,\n        DIAG_CD AS category,\n        \'diag\' AS type\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    UNION ALL\n    SELECT\n        DATE_FORMAT(OPRT_DT, \'%Y-%m-01\') AS month,\n        OPRT_CD AS category,\n        \'op\' AS type\n    FROM FACT_MDC_RCD_HMPG_OPRT\n),\ndetail AS (\n    SELECT\n        month,\n        type,\n        category,\n        COUNT(*) AS cnt\n    FROM all_data\n    GROUP BY month, type, category\n),\nratio AS (\n    SELECT\n        month,\n        type,\n        cnt * 1.0 / SUM(cnt) OVER (PARTITION BY month, type) AS ratio\n    FROM detail\n),\nmax_ratio AS (\n    SELECT\n        month,\n        type,\n        MAX(ratio) AS max_ratio\n    FROM ratio\n    GROUP BY month, type\n),\nflagged AS (\n    SELECT\n        month,\n        MAX(CASE WHEN max_ratio > 0.5 THEN 1 ELSE 0 END) AS flag\n    FROM max_ratio\n    GROUP BY month\n)\nSELECT *\nFROM (\n    SELECT\n        month,\n        SUM(flag) OVER (\n            ORDER BY month\n            ROWS BETWEEN 2 PRECEDING AND CURRENT ROW\n        ) AS sum_flag_3m\n    FROM flagged\n) t\nWHERE sum_flag_3m = 3;', '', '[]', '', '', 'WITH all_data AS (\n    SELECT\n        DATE_FORMAT(CRT_TM, \'%Y-%m-01\') AS month,\n        DIAG_CD AS category,\n        \'diag\' AS type\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    UNION ALL\n    SELECT\n        DATE_FORMAT(OPRT_DT, \'%Y-%m-01\') AS month,\n        OPRT_CD AS category,\n        \'op\' AS type\n    FROM FACT_MDC_RCD_HMPG_OPRT\n),\ndetail AS (\n    SELECT\n        month,\n        type,\n        category,\n        COUNT(*) AS cnt\n    FROM all_data\n    GROUP BY month, type, category\n),\nratio AS (\n    SELECT\n        month,\n        type,\n        cnt * 1.0 / SUM(cnt) OVER (PARTITION BY month, type) AS ratio\n    FROM detail\n),\nmax_ratio AS (\n    SELECT\n        month,\n        type,\n        MAX(ratio) AS max_ratio\n    FROM ratio\n    GROUP BY month, type\n),\nflagged AS (\n    SELECT\n        month,\n        MAX(CASE WHEN max_ratio > 0.5 THEN 1 ELSE 0 END) AS flag\n    FROM max_ratio\n    GROUP BY month\n)\nSELECT *\nFROM (\n    SELECT\n        month,\n        SUM(flag) OVER (\n            ORDER BY month\n            ROWS BETWEEN 2 PRECEDING AND CURRENT ROW\n        ) AS sum_flag_3m\n    FROM flagged\n) t\nWHERE sum_flag_3m = 3;', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-05-17 17:31:37', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (9, '公立患者流失', 'four', '技术要素', 9, '公立医院门诊就诊时间；民营医院住院就诊时间', '在系统中维护患者流动统计功能建立「民营医院收治患者来源于公立医院情况」数据分析功能，统计公立医院及医师个人患者流失数据。', '在一定的时间范围内，统计患者前后两次的不同机构入院情况。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (10, '未成年人高危预警', 'four', '技术要素', 10, '审核范围：未成年人', '在系统中构建未成年人受侵害风险监测预警功能，建立「高风险诊断识别与线索溯源」数据分析模型，通过匹配门诊及住院全量诊疗数据，统计并预警疑似侵害未成年人线索。', '在一定的时间范围内，监测未成年人患者就诊主诊断及次诊断 ICD10 编码匹配「侵害未成年人高风险诊断编码库」。', '', '', 'sql', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;', '', '[]', '', '', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;', '', 'pending', 1, 0, 0, '', '', 0, '', 'count', '2026-04-14 11:00:17', '2026-05-19 13:39:00', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (11, '麻精药品异常', 'four', '技术要素', 11, '审核范围：门急诊', '在系统中建立「麻醉、精神类药品处方超量及重复购药」监测预警功能。关联患者诊疗信息，针对门急诊普通患者执行控缓释制剂 7 天量、癌痛及慢性痛患者执行 15 天量的校验规则，实时识别并命中短时间内异常购麻醉、精神类药品行为。', '在一定时间范围内，监测门急诊患者异常购麻醉、精神类药品行为。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (12, '限制类技术超范围', 'four', '技术要素', 12, '—', '在系统中构建「限制类技术开展情况」监测功能，从机构权限、医师权限、患者转归、培训质量四个层面进行核查与分析', '核查限制类技术是否超出机构可开展范围、是否超出医师个人可开展范围。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (13, '抗肿瘤药物规范', 'four', '技术要素', 13, '审核范围：抗肿瘤药物', '对医疗机构开具的抗肿瘤药物，联合疾病诊断、TNM分期、病理诊断等数据进行分析，规范肿瘤诊疗行为', '结合需先行基因检测的药物目录，识别抗肿瘤药物使用是否存在无分子靶点检测依据的疑点行为。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (14, '肿瘤分期规范率', 'four', '技术要素', 14, '审核范围：肿瘤患者', '监测首次治疗前临床TNM分期诊断情况。', '结合肿瘤患者病例，识别首次治疗前是否完成临床TNM分期评估，统计分期诊断率。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (15, '人机资质不符', 'four', '设备要素', 15, '审核范围：手术患者', '建立「手术分级-医生授权-设备配置」匹配规则，对超范围业务自动报警。', '以手术分级为基准，医生授权对应资质等级，设备配置满足技术需求。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (16, '设备账实不符', 'four', '设备要素', 16, '—', '在系统中对设备基本信息、数量及品种与医疗机构设置申请及校验验证是否一致。', '验证设备对申请和使用是否一致。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (17, '检查阳性率异常', 'four', '设备要素', 17, '—', '在系统中维护医疗机构设备出具检查检验结果统计分析功能，建立「连续三个月内单一医疗机构特定检查或检验结果阳性率超过80%且该检查或检验总量占全院总量的80%」统计报警规则。', '在一定的时间范围内，统计机构检验项目频次、检验结果阳性占比。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-21 01:20:34', '2026-04-21 01:20:34', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (18, '重点药品耗材超限', 'four', '设备要素', 18, '国家三级公立医院绩效考核操作手册中耗材', '开展重点药品、耗材日常监测。', '开具的重点药品、耗材，超过阈值。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-21 01:20:34', '2026-04-21 01:20:34', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (19, '设备负荷与闲置', 'four', '设备要素', 19, '—', '诊断/治疗设备年平均服务患者数量。', '患者的检查报告数量/设备数量。', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-21 01:20:34', '2026-04-21 01:20:34', 'discharge', NULL, NULL);
INSERT INTO `indicator` VALUES (20, '患者入院 48 小时内转科的比例', 'core18', '', 1, '', '', '', '', '本指标不包括患者转入/转出ICU的情况。\n【分母口径】同期入院患者总人次数\n分母采集方案：入院记录病例数（来源：入院记录）\n【分子口径】入院48小时内转科患者人次数\n分子采集方案：满足下列条件的转科记录：转科时间-入院时间<48H；转出/转入科室均不含重症医学科（来源：转科记录）', 'none', '', '', '[]', '入院48小时内转科患者人次数', '同期入院患者总人次数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (21, '患者入院 8 小时内查房率', 'core18', '', 2, '', '', '', '【分母口径】同期入院患者总人次数\n分母采集方案：入院记录病例数（来源：入院记录）\n【分子口径】入院8小时内开具检查或治疗医嘱的患者人次数\n分子采集方案：最早的医嘱下达时间-入院时间<8H（来源：医嘱）', '【分母口径】同期入院患者总人次数\n分母采集方案：入院记录病例数（来源：入院记录）\n【分子口径】入院8小时内开具检查或治疗医嘱的患者人次数\n分子采集方案：最早的医嘱下达时间-入院时间<8H（来源：医嘱）', 'sql', '-- 分子 SQL\nSELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;\n\n-- 分母 SQL\nSELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', '', '[\"FACT_ADMN_MDC_HTR_RCD\", \"FACT_INHOS_ODR_INFMT\", \"FACT_ADMN_MDC_HTR_RCD\", \"FACT_INHOS_ODR_INFMT\", \"FACT_ADMN_MDC_HTR_RCD\", \"FACT_INHOS_ODR_INFMT\", \"FACT_ADMN_MDC_HTR_RCD\", \"FACT_INHOS_ODR_INFMT\"]', '入院8小时内开具检查或治疗医嘱的患者人次数', '同期入院患者总人次数', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', 'pending', 1, 1, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-05-16 00:19:37', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (22, '上级医师查房记录规范率', 'core18', '', 3, '', '', '', '', '【分母口径】同期住院患者病例总数量\n分母采集方案：入院记录病例数（来源：入院记录）\n【分子口径】住院患者病历中上级医师查房记录规范、完整的病例数量\n分子采集方案：上级医师查房记录含病史补充、体格检查新发现、诊疗意见、病情评估、48H内完成、分析讨论与鉴别诊断（来源：主治医师首次查房记录）', 'none', '', '', '[]', '住院患者病历中上级医师查房记录规范、完整的病例数量', '同期住院患者病例总数量', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (23, '住院患者非计划手术率', 'core18', '', 4, '', '', '', '', '【分母口径】同期住院患者总人次数\n分母采集方案：入院记录病例数（来源：入院记录）\n【分子口径】行非计划手术的住院患者人次数\n分子采集方案：手术类型=「非计划」（来源：手术记录/手术申请单）', 'none', '', '', '[]', '行非计划手术的住院患者人次数', '同期住院患者总人次数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (24, '急会诊及时到位率', 'core18', '', 5, '', '', '', '', '急会诊范围：患者疾病超出本科室处置能力且可能随时危及生命，需要其他科室立刻协助诊疗、参与抢救的会诊申请。\n【分母口径】同期急会诊总次数\n分母采集方案：出院患者中急会诊文书数量；医嘱中有「急会诊」（来源：急会诊申请单/急会诊记录）\n【分子口径】急会诊记录中10分钟内到位的急会诊次数\n分子采集方案：达到时间-申请时间 < 10min（来源：急会诊申请单）', 'none', '', '', '[]', '急会诊记录中10分钟内到位的急会诊次数', '同期急会诊总次数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (25, '急会诊有效率', 'core18', '', 6, '', '', '', '', '申请急会诊后40分钟内开具相关医嘱。\n【分母口径】同期急会诊总次数\n分母采集方案：急会诊病例数或医嘱中包含「急会诊」的数量（来源：急会诊申请单）\n【分子口径】急会诊后开具相关医嘱的次数\n分子采集方案：医嘱下达时间-急会诊申请时间<40min（来源：医嘱；急会诊申请单）', 'none', '', '', '[]', '急会诊后开具相关医嘱的次数', '同期急会诊总次数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (26, '普通会诊及时完成率', 'core18', '', 7, '', '', '', '分子 ÷ 分母 × 100%', '会诊医师电子签章时间即为会诊完成时间。\n【分母口径】同期普通会诊总次数\n分母采集方案：会诊记录数量（来源：会诊记录）\n【分子口径】普通会诊24小时内完成次数\n分子采集方案：会诊时间-申请时间<24H（来源：会诊记录）', 'none', '', '', '[]', '普通会诊24小时内完成次数', '普通会诊文书数量', 'SELECT\n    COUNT(DISTINCT c.INHOS_NO, c.MDC_ORG_CD) AS numerator_cnt\nFROM FACT_CSTT_RCD c\nJOIN FACT_MDC_RCD_HMPG h\n    ON c.INHOS_NO = h.INHOS_NO\n   AND c.MDC_ORG_CD = h.MDC_ORG_CD\nWHERE c.CSTT_TP LIKE \'%普通会诊\'\n  AND TIMESTAMPDIFF(HOUR, c.APL_DT_TM, c.CRT_TM) < 24\n  AND h.DSCG_DT_TM IS NOT NULL', 'SELECT\n    COUNT(DISTINCT c.INHOS_NO, c.MDC_ORG_CD) AS denominator_cnt\nFROM FACT_CSTT_RCD c\nJOIN FACT_MDC_RCD_HMPG h\n    ON c.INHOS_NO = h.INHOS_NO\n   AND c.MDC_ORG_CD = h.MDC_ORG_CD\nWHERE c.CSTT_TP LIKE \'%普通会诊\'\n  AND h.DSCG_DT_TM IS NOT NULL', 'success', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (27, '普通会诊有效率', 'core18', '', 8, '', '', '', '分子 ÷ 分母 × 100%', '申请普通会诊后24小时内开具相关医嘱。\n【分母口径】同期普通会诊患者总次数\n分母采集方案：会诊记录数量（来源：会诊记录）\n【分子口径】普通会诊结束后开具相关医嘱的次数\n分子采集方案：会诊时间+24H内医嘱数量（来源：医嘱）', 'none', '', '', '[]', '普通会诊结束后1小时内开具相关医嘱的次数', '普通会诊文书数量', 'SELECT COUNT(DISTINCT t.INHOS_NO, t.MDC_ORG_CD, t.ODR_OPN_DT_TM, t.ODR_ITM_TP_NM, t.ODR_CGY_NM) AS numerator_cnt\nFROM (\n    SELECT\n        od.INHOS_NO,\n        od.MDC_ORG_CD,\n        od.ODR_OPN_DT_TM,\n        od.ODR_ITM_TP_NM,\n        od.ODR_CGY_NM,\n        c.CSTT_TP,\n        c.CSTT_DT_TM AS CSTT_END_TIME,\n        TIMESTAMPDIFF(MINUTE, c.CSTT_DT_TM, od.ODR_OPN_DT_TM) AS MINUTES_DIFF,\n        ROW_NUMBER() OVER (\n            PARTITION BY od.INHOS_NO, od.MDC_ORG_CD, od.ODR_OPN_DT_TM, od.ODR_ITM_TP_NM, od.ODR_CGY_NM\n            ORDER BY c.CSTT_DT_TM DESC\n        ) AS rn\n    FROM FACT_INHOS_ODR_INFMT od\n    JOIN FACT_CSTT_RCD c\n        ON od.INHOS_NO = c.INHOS_NO\n       AND od.MDC_ORG_CD = c.MDC_ORG_CD\n    WHERE c.CSTT_TP = \'普通会诊\'\n      AND c.CSTT_DT_TM IS NOT NULL\n      AND od.ODR_OPN_DT_TM > c.CSTT_DT_TM\n      AND TIMESTAMPDIFF(MINUTE, c.CSTT_DT_TM, od.ODR_OPN_DT_TM) <= 60\n      AND od.ODR_ITM_TP_NM NOT LIKE \'%嘱托%\'\n      AND od.ODR_CGY_NM NOT LIKE \'%出院%\'\n) t\nJOIN FACT_MDC_RCD_HMPG h\n    ON t.INHOS_NO = h.INHOS_NO\n   AND t.MDC_ORG_CD = h.MDC_ORG_CD\nWHERE t.rn = 1\n  AND h.DSCG_DT_TM IS NOT NULL', 'SELECT\n    COUNT(DISTINCT c.INHOS_NO, c.MDC_ORG_CD) AS denominator_cnt\nFROM FACT_CSTT_RCD c\nJOIN FACT_MDC_RCD_HMPG h\n    ON c.INHOS_NO = h.INHOS_NO\n   AND c.MDC_ORG_CD = h.MDC_ORG_CD\nWHERE c.CSTT_TP LIKE \'%普通会诊\'\n  AND h.DSCG_DT_TM IS NOT NULL', 'success', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (28, '手术患者特级护理/一级护理出院率', 'core18', '', 9, '', '', '', '', '【分母口径】同期手术患者总数量\n分母采集方案：病案首页手术编码不空（来源：病案首页）\n【分子口径】手术患者出院时为特级护理/一级护理级别的患者数量\n分子采集方案：护理等级代码=\'1\' or \'2\'（来源：一般护理记录）', 'none', '', '', '[]', '手术患者出院时为特级护理/一级护理级别的患者数量', '同期手术患者总数量', '', '', 'pending', 1, 0, 0, '', '护理记录采集口径为%级护理%', 1, '%级护理%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (29, '非计划再次住院/手术患者疑难病例讨论完成率', 'core18', '', 10, '', '', '', '', '【分母口径】同期非计划再次住院/手术的数量\n分母采集方案：非计划再入院/非计划再次手术规则见HQMS（来源：病案首页）\n【分子口径】对非计划再次住院/手术患者进行疑难病例讨论的数量\n分子采集方案：疑难病例讨论记录不空（来源：疑难病例讨论记录）', 'none', '', '', '[]', '对非计划再次住院/手术患者进行疑难病例讨论的数量', '同期非计划再次住院/手术的数量', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (30, '非计划再次住院/手术患者疑难病例讨论记录完整率', 'core18', '', 11, '', '', '', '', '【分母口径】同期对非计划再次住院/手术患者进行疑难病例讨论的数量\n分母采集方案：病案首页+存在疑难病例讨论记录（来源：病案首页）\n【分子口径】讨论并将讨论结论记入病历的数量\n分子采集方案：讨论记录内容要素完整、结论记入病历（来源：疑难病例讨论记录）', 'none', '', '', '[]', '讨论并将讨论结论记入病历的数量', '同期对非计划再次住院/手术患者进行疑难病例讨论的数量', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (31, '高额异常费用患者进行疑难病例讨论的占比', 'core18', '', 12, '', '', '', '', '高额异常费用：一个住院周期内医疗费用20万元以上（各地可调整）。\n【分母口径】同期高额异常费用患者数量\n分母采集方案：住院期间总费用>20万的病例数量（来源：）\n【分子口径】对产生高额异常费用患者进行疑难病例讨论的数量\n分子采集方案：包含疑难病例讨论（来源：疑难病例讨论）', 'none', '', '', '[]', '对产生高额异常费用患者进行疑难病例讨论的数量', '同期高额异常费用患者数量', '', '', 'pending', 1, 0, 0, '', '采集口径为%疑难%讨论%', 1, '%疑难%讨论%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (32, '急危重症患者抢救成功率', 'core18', '', 13, '', '', '', '', '抢救成功指经抢救后存活超过24小时或存活至下一次抢救开始。\n【分母口径】同期急危重症患者抢救的总例次数\n【分子口径】急危重症患者抢救成功的例次数', 'none', '', '', '[]', '急危重症患者抢救成功的例次数', '同期急危重症患者抢救的总例次数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (33, '术前讨论完成率', 'core18', '', 14, '', '', '', '', '除抢救生命为目的的急诊手术外，术前讨论完成时间晚于手术医嘱和同意书签署视为未完成。\n【分母口径】同期手术总例数\n分母采集方案：病案首页中手术编码不空（来源：）\n【分子口径】完成术前讨论的手术例数', 'none', '', '', '[]', '完成术前讨论的手术例数', '同期手术总例数', '', '', 'pending', 1, 0, 0, '', '采集口径为%术前%讨论%', 1, '%术前%讨论%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (34, '术者参加术前讨论率', 'core18', '', 15, '', '', '', '', '术者指手术的主要完成人。\n【分母口径】同期进行术前讨论手术总例数\n分母采集方案：病案首页手术+存在术前讨论（来源：术前讨论）\n【分子口径】术者参加术前讨论的手术例数\n分子采集方案：术前讨论参加人员名单包含手术记录中术者（来源：术前讨论；手术记录）', 'none', '', '', '[]', '术者参加术前讨论的手术例数', '同期进行术前讨论手术总例数', '', '', 'pending', 1, 0, 0, '', '采集口径为%术前%讨论%', 1, '%术前%讨论%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (35, '术前讨论计划手术一致率', 'core18', '', 16, '', '', '', '', '【分母口径】同期手术总例数\n分母采集方案：病案首页手术为国临版3.0手术与介入治疗（来源：病案首页）\n【分子口径】实际开展手术与术前讨论计划手术一致的手术例数\n分子采集方案：「术前讨论」和「手术记录」中手术名称相同（来源：术前讨论；手术记录）', 'none', '', '', '[]', '实际开展手术与术前讨论计划手术一致的手术例数', '同期手术总例数', '', '', 'pending', 1, 0, 0, '', '采集口径为%术前%讨论%', 1, '%术前%讨论%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (36, '实际手术术者与计划手术术者一致率', 'core18', '', 17, '', '', '', '', '【分母口径】同期手术总例数\n分母采集方案：病案首页手术为国临版3.0（来源：病案首页）\n【分子口径】实际开展手术术者与计划手术术者一致的手术例数\n分子采集方案：「术前讨论」和「手术记录」中术者名称或编码相同（来源：术前讨论；手术记录）', 'none', '', '', '[]', '实际开展手术术者与计划手术术者一致的手术例数', '同期手术总例数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (37, '死亡病例讨论 5 日完成率', 'core18', '', 18, '', '', '', '', '【分母口径】同期死亡病例总数量\n分母采集方案：死亡记录数量（来源：死亡记录）\n【分子口径】患者死亡5个工作日内完成死亡病例讨论的病例数量\n分子采集方案：死亡病例讨论记录.讨论日期时间-死亡记录.死亡日期时间<5D（来源：死亡病例讨论记录）', 'none', '', '', '[]', '患者死亡5个工作日内完成死亡病例讨论的病例数量', '同期死亡病例总数量', '', '', 'pending', 1, 0, 0, '', '采集口径为%死亡%讨论%', 1, '%死亡%讨论%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (38, '科主任主持死亡病例讨论率', 'core18', '', 19, '', '', '', '', '【分母口径】同期死亡病例总数量\n分母采集方案：死亡记录数量（来源：死亡记录）\n【分子口径】死亡病例讨论由科主任主持的病例数量\n分子采集方案：专业技术职务类别代码=\'1\'或\'2\'（来源：死亡病例讨论记录）', 'none', '', '', '[]', '死亡病例讨论由科主任主持的病例数量', '同期死亡病例总数量', '', '', 'pending', 1, 0, 0, '', '采集口径为%死亡%讨论%', 1, '%死亡%讨论%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (39, '长期医嘱当日终止率', 'core18', '', 20, '', '', '', '', '【分母口径】同期开具长期医嘱总数量\n【分子口径】开具长期医嘱后当日终止执行的医嘱数量', 'sql', '-- 分子 SQL\nSELECT t1.MDC_ORG_CD, t1.INHOS_NO, t1.ODR_CGY_NM, t1.ODR_OPN_DT_TM, t1.ODR_STRT_DT, t1.ODR_EXEC_STTS_NM, t1.ODR_STP_DT_TM FROM FACT_INHOS_ODR_INFMT t1 WHERE t1.ODR_CGY_NM LIKE \'%长期医嘱%\' AND t1.ODR_STP_DT_TM IS NOT NULL AND DATE(t1.ODR_OPN_DT_TM) = DATE(t1.ODR_STP_DT_TM);\n\n-- 分母 SQL\nSELECT t1.MDC_ORG_CD, t1.INHOS_NO, t1.ODR_CGY_NM, t1.ODR_OPN_DT_TM, t1.ODR_STRT_DT, t1.ODR_EXEC_STTS_NM, t1.ODR_STP_DT_TM FROM FACT_INHOS_ODR_INFMT t1 WHERE t1.ODR_CGY_NM LIKE \'%长期医嘱%\';', '', '[\"FACT_INHOS_ODR_INFMT\", \"FACT_INHOS_ODR_INFMT\"]', '开具长期医嘱后当日终止执行的医嘱数量', '同期开具长期医嘱总数量', 'SELECT t1.MDC_ORG_CD, t1.INHOS_NO, t1.ODR_CGY_NM, t1.ODR_OPN_DT_TM, t1.ODR_STRT_DT, t1.ODR_EXEC_STTS_NM, t1.ODR_STP_DT_TM FROM FACT_INHOS_ODR_INFMT t1 WHERE t1.ODR_CGY_NM LIKE \'%长期医嘱%\' AND t1.ODR_STP_DT_TM IS NOT NULL AND DATE(t1.ODR_OPN_DT_TM) = DATE(t1.ODR_STP_DT_TM);', 'SELECT t1.MDC_ORG_CD, t1.INHOS_NO, t1.ODR_CGY_NM, t1.ODR_OPN_DT_TM, t1.ODR_STRT_DT, t1.ODR_EXEC_STTS_NM, t1.ODR_STP_DT_TM FROM FACT_INHOS_ODR_INFMT t1 WHERE t1.ODR_CGY_NM LIKE \'%长期医嘱%\';', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-23 03:51:33', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (40, '手术医师手术时间重合率', 'core18', '', 21, '', '', '', '', '「同一时间」指手术未结束时间与其他手术开始时间重合。\n【分母口径】同期住院患者手术总例数\n分母采集方案：病案首页手术记录为国临版3.0（来源：病案首页）\n【分子口径】同一时间内手术医师为同一人的手术例数\n分子采集方案：手术开始/结束时间重合同一术者（来源：手术记录）', 'none', '', '', '[]', '同一时间内手术医师为同一人的手术例数', '同期住院患者手术总例数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (41, '麻醉医师手术时间重合率', 'core18', '', 22, '', '', '', '', '【分母口径】同期住院患者手术总例数\n分母采集方案：病案首页手术记录为国临版3.0（来源：病案首页）\n【分子口径】同一时间内手术麻醉医师为同一人的手术例数\n分子采集方案：手术开始/结束时间重合同一麻醉师（来源：手术记录）', 'none', '', '', '[]', '同一时间内手术麻醉医师为同一人的手术例数', '同期住院患者手术总例数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (42, '四级手术与三级手术并发症发生率比', 'core18', '', 23, '', '', '', '三、四级手术按本机构手术分级目录；并发症范围见规范。\n【分母口径】三级手术并发症发生率\n分母采集方案：病案首页+手术级别3+并发症记录（来源：病案首页；手术记录/术后首次病程）\n【分子口径】四级手术并发症发生率\n分子采集方案：手术级别4+记录并发症（来源：病案首页；手术记录/术后首次病程）', '三、四级手术按本机构手术分级目录；并发症范围见规范。\n【分母口径】三级手术并发症发生率\n分母采集方案：病案首页+手术级别3+并发症记录（来源：病案首页；手术记录/术后首次病程）\n【分子口径】四级手术并发症发生率\n分子采集方案：手术级别4+记录并发症（来源：病案首页；手术记录/术后首次病程）', 'sql', '-- 分子 SQL\nWITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'4\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g4_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO\n\n-- 分母 SQL\nWITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'3\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g3_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', '', '[\"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_MDC_RCD_HMPG_DIAG\"]', '四级手术并发症发生率', '三级手术并发症发生率', 'WITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'4\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g4_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', 'WITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'3\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g3_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', 'pending', 1, 1, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-22 16:58:00', 'discharge', 'RATE-special', NULL);
INSERT INTO `indicator` VALUES (43, '四级手术与三级手术患者死亡率比', 'core18', '', 24, '', '', '', '各级手术患者死亡率为死亡人数占同期各级手术患者人数的比例。\n【分母口径】三级手术患者死亡率\n分母采集方案：手术级别3+死亡记录（来源：病案首页/手术执行信息；死亡记录）\n【分子口径】四级手术患者死亡率\n分子采集方案：手术级别4+死亡记录（来源：病案首页/手术记录；死亡记录）', '各级手术患者死亡率为死亡人数占同期各级手术患者人数的比例。\n【分母口径】三级手术患者死亡率\n分母采集方案：手术级别3+死亡记录（来源：病案首页/手术执行信息；死亡记录）\n【分子口径】四级手术患者死亡率\n分子采集方案：手术级别4+死亡记录（来源：病案首页/手术记录；死亡记录）', 'sql', '-- 分子 SQL\nSELECT \n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \n    / \n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g4_death_rate\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \n    AND h.INHOS_NO = o.INHOS_NO\nWHERE o.OPRT_LVL_CD = \'4\'\n  AND h.DSCG_DT_TM IS NOT NULL\n  AND h.INVLD_FLG = \'0\' \n  AND o.INVLD_FLG = \'0\';\n\n-- 分母 SQL\nSELECT \n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \n    / \n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g3_death_rate\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \n    AND h.INHOS_NO = o.INHOS_NO\nWHERE o.OPRT_LVL_CD = \'3\'\n  AND h.DSCG_DT_TM IS NOT NULL\n  AND h.INVLD_FLG = \'0\' \n  AND o.INVLD_FLG = \'0\';', '', '[\"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_MDC_RCD_HMPG_DIAG\"]', '四级手术患者死亡率', '三级手术患者死亡率', 'SELECT \n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \n    / \n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g4_death_rate\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \n    AND h.INHOS_NO = o.INHOS_NO\nWHERE o.OPRT_LVL_CD = \'4\'\n  AND h.DSCG_DT_TM IS NOT NULL\n  AND h.INVLD_FLG = \'0\' \n  AND o.INVLD_FLG = \'0\';', 'SELECT \n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \n    / \n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g3_death_rate\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \n    AND h.INHOS_NO = o.INHOS_NO\nWHERE o.OPRT_LVL_CD = \'3\'\n  AND h.DSCG_DT_TM IS NOT NULL\n  AND h.INVLD_FLG = \'0\' \n  AND o.INVLD_FLG = \'0\';', 'pending', 1, 1, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-22 17:06:44', 'discharge', 'RATE-special', NULL);
INSERT INTO `indicator` VALUES (44, '四级手术术前多学科讨论完成率', 'core18', '', 25, '', '', '', '', '限制类技术按照四级手术进行管理。\n【分母口径】同期四级手术总例数\n分母采集方案：病案首页手术级别代码=4（来源：病案首页）\n【分子口径】术前完成多学科讨论的四级手术例数\n分子采集方案：术前讨论中包含多学科讨论内容（来源：术前讨论）', 'none', '', '', '[]', '术前完成多学科讨论的四级手术例数', '同期四级手术总例数', '', '', 'pending', 1, 0, 0, '', '采集口径为%四级%术前%多学科%讨论%', 1, '%四级%术前%多学科%讨论%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (45, '三、四级手术实际开展率', 'core18', '', 26, '', '', '', '', '三、四级手术备案按《医疗机构手术分级管理办法》报送目录信息。\n【分母口径】同期备案的三、四级手术术种数\n【分子口径】实际开展的三、四级手术术种数', 'none', '', '', '[]', '实际开展的三、四级手术术种数', '同期备案的三、四级手术术种数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (46, '危急值报告时间', 'core18', '', 27, '', '', '', '', 'X为出现危急值到临床科室获取危急值的时间；分别统计住院/门诊/急诊。\n【分母口径】n为实际报告的危急值项目数\n分母采集方案：病程记录/护理记录「危急值」（来源：）\n【分子口径】X(n+1)/2 或中位数公式', 'none', '', '', '[]', 'X(n+1)/2 或中位数公式', 'n为实际报告的危急值项目数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (47, '住院患者危急值当日及时处置率', 'core18', '', 28, '', '', '', '', '仅统计住院；当日处置以当日病程记录为准，无记录视为未处置。\n【分母口径】同期临床科室接获住院患者危急值项目数\n分母采集方案：病程记录/护理记录「危急值」（来源：）\n【分子口径】当日处置的住院患者危急值项目数', 'none', '', '', '[]', '当日处置的住院患者危急值项目数', '同期临床科室接获住院患者危急值项目数', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (48, '特殊使用级抗菌药物使用会诊率', 'core18', '', 29, '', '', '', '', '会诊同意后按程序合理使用。\n【分母口径】同期特殊使用级抗菌药物使用医嘱总数量\n分母采集方案：医嘱中包含特殊抗菌用药（来源：医嘱）\n【分子口径】使用医嘱与会诊记录相对应的医嘱数量\n分子采集方案：会诊意见含同意使用特殊使用级含义（来源：会诊记录）', 'none', '', '', '[]', '使用医嘱与会诊记录相对应的医嘱数量', '同期特殊使用级抗菌药物使用医嘱总数量', '', '', 'pending', 1, 0, 0, '', '抗菌药采集口径为%抗菌药%', 1, '%抗菌药%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (49, '临床用血后评估记录率', 'core18', '', 30, '', '', '', '', '【分母口径】同期临床输血治疗病例总例次数\n分母采集方案：输血记录不空（来源：输血记录）\n【分子口径】输血治疗后规范书写评估输血记录例次数\n分子采集方案：输血病程记录完整详细（含原因、成分、量、血型、观察、不良反应及处置）（来源：输血记录）', 'none', '', '', '[]', '输血治疗后规范书写评估输血记录例次数', '同期临床输血治疗病例总例次数', '', '', 'pending', 1, 0, 0, '', '采集口径为%输血%评估%', 1, '%输血%评估%', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (50, '术中自体血回输率', 'core18', '', 31, '', '', '', '', '【分母口径】同期术中进行输血患者总数量\n分母采集方案：输血记录不空（来源：输血记录）\n【分子口径】术中使用自体血回输的患者数量\n分子采集方案：洗涤式自体血回输或病程/手术记录相关信息（来源：输血记录/手术记录/医嘱/病程记录）', 'none', '', '', '[]', '术中使用自体血回输的患者数量', '同期术中进行输血患者总数量', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (51, '主要诊断ICD-10编码亚目种类数', 'core18', '', 32, '', '', '', 'COUNT(DISTINCT sub_category)', '主要诊断ICD-10编码亚目（前5位）的种类数及分布', 'sql', 'SELECT\n    UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 5)) AS sub_category,\n    COUNT(DISTINCT UPPER(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'))) AS disease_cnt\nFROM FACT_MDC_RCD_HMPG t1\nINNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n    ON t1.INHOS_NO = t2.INHOS_NO\n   AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t2.MAIN_DIAG_FLG = \'1\'\n  AND t2.DIAG_CD NOT IN (\'\', \'-\')\n  AND t1.DSCG_DT_TM IS NOT NULL\nGROUP BY sub_category\nORDER BY disease_cnt DESC\nLIMIT 50', '', '[\"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\"]', '主要诊断ICD-10编码亚目种类数', '—', 'SELECT\n    UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 5)) AS sub_category,\n    COUNT(DISTINCT UPPER(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'))) AS disease_cnt\nFROM FACT_MDC_RCD_HMPG t1\nINNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n    ON t1.INHOS_NO = t2.INHOS_NO\n   AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t2.MAIN_DIAG_FLG = \'1\'\n  AND t2.DIAG_CD NOT IN (\'\', \'-\')\n  AND t1.DSCG_DT_TM IS NOT NULL\nGROUP BY sub_category\nORDER BY disease_cnt DESC\nLIMIT 50', '', 'success', 1, 1, 0, '', '统计类拓展指标', 0, '', 'count', '2026-04-14 11:00:17', '2026-05-27 21:04:24', 'discharge', 'STRUCTURE', '{\"type\": \"COMPOSITE_RANKING\", \"limit\": 20, \"ranking_key_field\": \"sub_category\", \"ranking_value_field\": \"disease_cnt\", \"total_aggregation_field\": \"disease_cnt\"}');
INSERT INTO `indicator` VALUES (52, '主要手术ICD-9-CM-3四位码种类数', 'core18', '', 33, '', '', '', 'COUNT(DISTINCT four_digit_code)', '主要手术ICD-9-CM-3四位码种类数，区分治疗性与诊断性操作', 'sql', 'SELECT\n    four_digit_code,\n    SUM(disease_cnt) AS surgery_cnt\nFROM (\n    SELECT\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.OPRT_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS four_digit_code,\n        COUNT(DISTINCT UPPER(REPLACE(REPLACE(REPLACE(t2.OPRT_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'))) AS disease_cnt\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT t2\n        ON t1.INHOS_NO = t2.INHOS_NO\n       AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n    WHERE t1.DSCG_DT_TM IS NOT NULL\n      AND t2.MAIN_OPRT_FLG = \'1\'\n      AND t2.OPRT_CD NOT IN (\'\',\'-\')\n    GROUP BY four_digit_code\n) AS all_surgeries\nGROUP BY four_digit_code\nORDER BY surgery_cnt DESC\nLIMIT 50', '', '[\"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\"]', '主要手术ICD-9-CM-3四位码种类数', '—', 'SELECT\n    four_digit_code,\n    SUM(disease_cnt) AS surgery_cnt\nFROM (\n    SELECT\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.OPRT_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS four_digit_code,\n        COUNT(DISTINCT UPPER(REPLACE(REPLACE(REPLACE(t2.OPRT_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'))) AS disease_cnt\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT t2\n        ON t1.INHOS_NO = t2.INHOS_NO\n       AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n    WHERE t1.DSCG_DT_TM IS NOT NULL\n      AND t2.MAIN_OPRT_FLG = \'1\'\n      AND t2.OPRT_CD NOT IN (\'\',\'-\')\n    GROUP BY four_digit_code\n) AS all_surgeries\nGROUP BY four_digit_code\nORDER BY surgery_cnt DESC\nLIMIT 50', '', 'success', 1, 1, 0, '', '统计类拓展指标', 0, '', 'count', '2026-04-14 11:00:17', '2026-04-22 07:56:12', 'discharge', 'STRUCTURE-special', '{\"type\": \"COMPOSITE_RANKING\", \"limit\": 20, \"ranking_key_field\": \"four_digit_code\", \"ranking_value_field\": \"surgery_cnt\", \"total_aggregation_field\": \"surgery_cnt\"}');
INSERT INTO `indicator` VALUES (53, '死亡或出院预期转归不良患者', 'core18', '', 34, '', '', '', '', '', 'sql', 'SELECT \n    INHOS_NO AS \'住院号\',\n    DSCG_DT_TM AS \'出院日期时间\',\n    DSCG_WAY_NM AS \'离院方式名称\',\n    TNOVR_CDT_NM AS \'转归情况名称\',\n    CASE \n        WHEN DSCG_WAY_CD = \'5\' OR DSCG_WAY_NM LIKE \'%死亡%\' THEN \'是\' \n        ELSE \'否\' \n    END AS \'情况1：离院方式死亡\',\n    CASE \n        WHEN (TNOVR_CDT_CD = \'5\' OR TNOVR_CDT_NM LIKE \'%死亡%\') \n             AND (DSCG_WAY_NM = \'非医嘱离院\' OR DSCG_WAY_CD = \'4\')\n        THEN \'是\' \n        ELSE \'否\' \n    END AS \'情况2：转归死亡且非医嘱离院\'\nFROM FACT_MDC_RCD_HMPG\nWHERE (DSCG_WAY_CD = \'5\' OR DSCG_WAY_NM LIKE \'%死亡%\')\n   OR ((TNOVR_CDT_CD = \'5\' OR TNOVR_CDT_NM LIKE \'%死亡%\') \n       AND (DSCG_WAY_NM = \'非医嘱离院\' OR DSCG_WAY_CD = \'4\'))\nORDER BY DSCG_DT_TM;', '', '[\"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG\"]', '', '', 'SELECT \n    INHOS_NO AS \'住院号\',\n    DSCG_DT_TM AS \'出院日期时间\',\n    DSCG_WAY_NM AS \'离院方式名称\',\n    TNOVR_CDT_NM AS \'转归情况名称\',\n    CASE \n        WHEN DSCG_WAY_CD = \'5\' OR DSCG_WAY_NM LIKE \'%死亡%\' THEN \'是\' \n        ELSE \'否\' \n    END AS \'情况1：离院方式死亡\',\n    CASE \n        WHEN (TNOVR_CDT_CD = \'5\' OR TNOVR_CDT_NM LIKE \'%死亡%\') \n             AND (DSCG_WAY_NM = \'非医嘱离院\' OR DSCG_WAY_CD = \'4\')\n        THEN \'是\' \n        ELSE \'否\' \n    END AS \'情况2：转归死亡且非医嘱离院\'\nFROM FACT_MDC_RCD_HMPG\nWHERE (DSCG_WAY_CD = \'5\' OR DSCG_WAY_NM LIKE \'%死亡%\')\n   OR ((TNOVR_CDT_CD = \'5\' OR TNOVR_CDT_NM LIKE \'%死亡%\') \n       AND (DSCG_WAY_NM = \'非医嘱离院\' OR DSCG_WAY_CD = \'4\'))\nORDER BY DSCG_DT_TM;', '', 'pending', 1, 0, 0, '', '', 0, '', 'count', '2026-04-14 11:00:17', '2026-04-22 07:23:07', 'discharge', 'STRUCTURE', NULL);
INSERT INTO `indicator` VALUES (54, '住院患者死亡疾病谱', 'core18', '', 35, '', '', '', 'COUNT(DISTINCT INHOS_NO)', '住院患者死亡疾病谱TOP20，区分离院方式死亡与转归死亡', 'sql', 'SELECT\n    UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 5)) AS sub_category,\n    CASE\n        WHEN t1.DSCG_WAY_NM LIKE \'%死亡%\' THEN \'离院方式死亡\'\n        WHEN t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱%\' THEN \'转归死亡\'\n        ELSE NULL\n    END AS death_type,\n    COUNT(DISTINCT t1.INHOS_NO) AS death_patient_cnt\nFROM FACT_MDC_RCD_HMPG t1\nINNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n    ON t1.INHOS_NO = t2.INHOS_NO\n   AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t2.MAIN_DIAG_FLG = \'1\'\n  AND t2.DIAG_CD NOT IN (\'\',\'-\')\n  AND (\n      t1.DSCG_WAY_NM LIKE \'%死亡%\'\n      OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱%\')\n  )\nGROUP BY sub_category, death_type\nHAVING death_type IS NOT NULL\nORDER BY death_patient_cnt DESC\nLIMIT 50', '', '[\"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_DIAG\"]', '各死亡类型对应的患者人数', '—', 'SELECT\n    UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 5)) AS sub_category,\n    CASE\n        WHEN t1.DSCG_WAY_NM LIKE \'%死亡%\' THEN \'离院方式死亡\'\n        WHEN t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱%\' THEN \'转归死亡\'\n        ELSE NULL\n    END AS death_type,\n    COUNT(DISTINCT t1.INHOS_NO) AS death_patient_cnt\nFROM FACT_MDC_RCD_HMPG t1\nINNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n    ON t1.INHOS_NO = t2.INHOS_NO\n   AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t2.MAIN_DIAG_FLG = \'1\'\n  AND t2.DIAG_CD NOT IN (\'\',\'-\')\n  AND (\n      t1.DSCG_WAY_NM LIKE \'%死亡%\'\n      OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱%\')\n  )\nGROUP BY sub_category, death_type\nHAVING death_type IS NOT NULL\nORDER BY death_patient_cnt DESC\nLIMIT 50', '', 'success', 1, 1, 0, '', '', 0, '', 'count', '2026-04-14 11:00:17', '2026-05-25 22:53:59', 'discharge', 'STRUCTURE', '{\"type\": \"COMPOSITE_RANKING\", \"limit\": 20, \"ranking_key_field\": \"sub_category\", \"ranking_value_field\": \"death_patient_cnt\", \"total_aggregation_field\": \"death_patient_cnt\"}');
INSERT INTO `indicator` VALUES (55, '住院患者死亡手术谱', 'core18', '', 36, '', '', '', '', '', 'sql', 'SELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    o.OPRT_NM AS \'手术名称\',\n    COUNT(DISTINCT CASE \n        WHEN (h.DSCG_WAY_CD = \'5\' OR h.DSCG_WAY_NM LIKE \'%死亡%\') \n        THEN h.INHOS_NO \n    END) AS \'离院方式死亡人数\',\n    COUNT(DISTINCT CASE \n        WHEN (h.TNOVR_CDT_CD = \'5\' OR h.TNOVR_CDT_NM LIKE \'%死亡%\') \n             AND (h.DSCG_WAY_NM = \'非医嘱离院\' OR h.DSCG_WAY_CD = \'4\')\n        THEN h.INHOS_NO \n    END) AS \'转归死亡且非医嘱离院人数\'\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o ON h.INHOS_NO = o.INHOS_NO\nWHERE \n    -- 筛选死亡患者（满足任意一种死亡定义）\n    ((h.DSCG_WAY_CD = \'5\' OR h.DSCG_WAY_NM LIKE \'%死亡%\')\n     OR ((h.TNOVR_CDT_CD = \'5\' OR h.TNOVR_CDT_NM LIKE \'%死亡%\') \n         AND (h.DSCG_WAY_NM = \'非医嘱离院\' OR h.DSCG_WAY_CD = \'4\')))\n    AND o.OPRT_NM IS NOT NULL\n    AND o.OPRT_NM != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM, o.OPRT_NM\nORDER BY h.MDC_ORG_CD, o.OPRT_NM;', '', '[\"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_MDC_RCD_HMPG\"]', '', '', 'SELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    o.OPRT_NM AS \'手术名称\',\n    COUNT(DISTINCT CASE \n        WHEN (h.DSCG_WAY_CD = \'5\' OR h.DSCG_WAY_NM LIKE \'%死亡%\') \n        THEN h.INHOS_NO \n    END) AS \'离院方式死亡人数\',\n    COUNT(DISTINCT CASE \n        WHEN (h.TNOVR_CDT_CD = \'5\' OR h.TNOVR_CDT_NM LIKE \'%死亡%\') \n             AND (h.DSCG_WAY_NM = \'非医嘱离院\' OR h.DSCG_WAY_CD = \'4\')\n        THEN h.INHOS_NO \n    END) AS \'转归死亡且非医嘱离院人数\'\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o ON h.INHOS_NO = o.INHOS_NO\nWHERE \n    -- 筛选死亡患者（满足任意一种死亡定义）\n    ((h.DSCG_WAY_CD = \'5\' OR h.DSCG_WAY_NM LIKE \'%死亡%\')\n     OR ((h.TNOVR_CDT_CD = \'5\' OR h.TNOVR_CDT_NM LIKE \'%死亡%\') \n         AND (h.DSCG_WAY_NM = \'非医嘱离院\' OR h.DSCG_WAY_CD = \'4\')))\n    AND o.OPRT_NM IS NOT NULL\n    AND o.OPRT_NM != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM, o.OPRT_NM\nORDER BY h.MDC_ORG_CD, o.OPRT_NM;', '', 'pending', 1, 0, 0, '', '', 0, '', 'count', '2026-04-14 11:00:17', '2026-04-22 17:08:48', 'discharge', 'STRUCTURE', NULL);
INSERT INTO `indicator` VALUES (56, '患者住院、新生儿、手术患者住院总死亡率', 'core18', '', 37, '', '', '', '统计各医疗机构的患者住院总死亡率。分母为所有有效（INVLD_FLG=\'0\'）且已出院（DSCG_DT_TM 不为空）的住院患者人数。分子为满足以下任一条件的患者人数：① 离院方式名称包含\"死亡\"；② 转归情况名称包含\"死亡\"且离院方式包含\"非医嘱离院\"。最终计算比值 = 分子 ÷ 分母 × 100%。', '', 'textToSql', '-- 分子\nSELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOVR_CDT_NM FROM FACT_MDC_RCD_HMPG AS t1 WHERE t1.INVLD_FLG = \'0\' AND t1.DSCG_DT_TM IS NOT NULL AND (t1.DSCG_WAY_NM LIKE \'%死亡%\' OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱离院%\'))\n\n-- 分母\nSELECT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM, t1.DSCG_DT_TM, t1.DSCG_WAY_NM, t1.TNOVR_CDT_NM FROM FACT_MDC_RCD_HMPG AS t1 WHERE t1.INVLD_FLG = \'0\' AND t1.DSCG_DT_TM IS NOT NULL', '', '[\"FACT_MDC_RCD_HMPG\"]', '在分母范围内，离院方式含\"死亡\"，或（转归含\"死亡\"且离院方式含\"非医嘱离院\"）', '所有有效且已出院患者的住院人数（去重方式：COUNT DISTINCT INHOS_NO）', '', '', 'pending', 1, 1, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-22 08:07:29', 'discharge', 'COMPOSITE', NULL);
INSERT INTO `indicator` VALUES (57, '非预期再住院情况分析', 'core18', '', 38, '', '', '', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'COMPOSITE', NULL);
INSERT INTO `indicator` VALUES (58, '非计划重返手术室再手术分析', 'core18', '', 39, '', '', '', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'COMPOSITE', NULL);
INSERT INTO `indicator` VALUES (59, '住院患者围手术期死亡率', 'core18', '', 40, '', '', '', '分子 ÷ 分母 × 100%', '住院患者围手术期各时间窗口的死亡率，区分离院方式死亡与转归死亡', 'sql', 'WITH\ndenominator_base AS (\n    SELECT DISTINCT h.INHOS_NO, h.MDC_ORG_CD\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL\n      AND TRIM(o.OPRT_CD) <> \'\'\n),\ndeath_record_time AS (\n    SELECT\n        s.INHOS_NO,\n        s.MDC_ORG_CD,\n        STR_TO_DATE(\n            REGEXP_REPLACE(\n                REGEXP_REPLACE(\n                    REGEXP_REPLACE(\n                        REGEXP_REPLACE(\n                            REGEXP_REPLACE(\n                                REGEXP_SUBSTR(s.ITM_VLU,\n                                    \'死亡时间[:：][[:space:]]*[0-9]{4}年[0-9]{1,2}月[0-9]{1,2}日[[:space:]]*[0-9]{1,2}时[0-9]{2}分|死亡时间[:：][[:space:]]*[0-9]{4}-[0-9]{1,2}-[0-9]{1,2}[[:space:]]+[0-9]{1,2}:[0-9]{2}\'),\n                                \'日[[:space:]]*\', \' \'\n                            ),\n                            \'[年月]\', \'-\'\n                        ),\n                        \'死亡时间[:：][[:space:]]*\', \'\'\n                    ),\n                    \'时\', \':\'\n                ),\n                \'分\', \'\'\n            ),\n            \'%Y-%m-%d %H:%i\'\n        ) AS DEATH_DT_TM\n    FROM FACT_INHOS_CRS_RCD_S s\n    WHERE s.RCD_TP_NM LIKE \'%死亡记录%\'\n      AND s.ITM_NM = \'文本主体\'\n      AND s.ITM_VLU LIKE \'%死亡时间%\'\n),\nclear_death_with_surgery AS (\n    SELECT\n        h.INHOS_NO,\n        h.MDC_ORG_CD,\n        o.OPRT_DT,\n        d.DEATH_DT_TM,\n        CASE WHEN DATE(d.DEATH_DT_TM) = DATE(o.OPRT_DT) THEN 1 ELSE 0 END AS death_same_day,\n        CASE WHEN d.DEATH_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, d.DEATH_DT_TM) <= 24\n            THEN 1 ELSE 0 END AS death_within_24h,\n        CASE WHEN d.DEATH_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, d.DEATH_DT_TM) <= 48\n            THEN 1 ELSE 0 END AS death_within_48h\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    INNER JOIN death_record_time d\n        ON h.INHOS_NO = d.INHOS_NO AND h.MDC_ORG_CD = d.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL AND TRIM(o.OPRT_CD) <> \'\'\n      AND h.DSCG_WAY_NM = \'死亡\'\n      AND d.DEATH_DT_TM IS NOT NULL\n      AND o.OPRT_DT IS NOT NULL\n),\nproxy_death_with_surgery AS (\n    SELECT\n        h.INHOS_NO,\n        h.MDC_ORG_CD,\n        o.OPRT_DT,\n        h.DSCG_DT_TM AS DEATH_DT_TM,\n        CASE WHEN DATE(h.DSCG_DT_TM) = DATE(o.OPRT_DT) THEN 1 ELSE 0 END AS death_same_day,\n        CASE WHEN h.DSCG_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, h.DSCG_DT_TM) <= 24\n            THEN 1 ELSE 0 END AS death_within_24h,\n        CASE WHEN h.DSCG_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, h.DSCG_DT_TM) <= 48\n            THEN 1 ELSE 0 END AS death_within_48h\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL AND TRIM(o.OPRT_CD) <> \'\'\n      AND h.TNOVR_CDT_NM = \'死亡\'\n      AND h.DSCG_WAY_NM = \'非医嘱离院\'\n      AND o.OPRT_DT IS NOT NULL\n),\npatient_flags AS (\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        MAX(death_same_day) AS clear_death_same_day,\n        MAX(death_within_24h) AS clear_death_within_24h,\n        MAX(death_within_48h) AS clear_death_within_48h,\n        0 AS proxy_death_same_day,\n        0 AS proxy_death_within_24h,\n        0 AS proxy_death_within_48h\n    FROM clear_death_with_surgery\n    GROUP BY INHOS_NO, MDC_ORG_CD\n    UNION ALL\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        0, 0, 0,\n        MAX(death_same_day),\n        MAX(death_within_24h),\n        MAX(death_within_48h)\n    FROM proxy_death_with_surgery\n    GROUP BY INHOS_NO, MDC_ORG_CD\n),\npatient_agg AS (\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        MAX(clear_death_same_day) AS clear_same_day,\n        MAX(clear_death_within_24h) AS clear_24h,\n        MAX(clear_death_within_48h) AS clear_48h,\n        MAX(proxy_death_same_day) AS proxy_same_day,\n        MAX(proxy_death_within_24h) AS proxy_24h,\n        MAX(proxy_death_within_48h) AS proxy_48h\n    FROM patient_flags\n    GROUP BY INHOS_NO, MDC_ORG_CD\n)\nSELECT\n    COUNT(DISTINCT d.INHOS_NO, d.MDC_ORG_CD) AS denominator_surgery_patients,\n\n    SUM(COALESCE(a.clear_same_day, 0)) AS numerator_clear_death_same_day,\n    SUM(COALESCE(a.clear_24h, 0))       AS numerator_clear_death_24h,\n    SUM(COALESCE(a.clear_48h, 0))       AS numerator_clear_death_48h,\n\n    SUM(COALESCE(a.proxy_same_day, 0))  AS numerator_proxy_death_same_day,\n    SUM(COALESCE(a.proxy_24h, 0))       AS numerator_proxy_death_24h,\n    SUM(COALESCE(a.proxy_48h, 0))       AS numerator_proxy_death_48h\nFROM denominator_base d\nLEFT JOIN patient_agg a\n    ON d.INHOS_NO = a.INHOS_NO AND d.MDC_ORG_CD = a.MDC_ORG_CD', '', '[\"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_OPRT_EXEC_INFMT\", \"FACT_INHOS_CRS_RCD_S\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_OPRT_EXEC_INFMT\", \"FACT_INHOS_CRS_RCD_S\"]', '术后各时间窗口死亡患者数', '出院手术患者总数', 'WITH\ndenominator_base AS (\n    SELECT DISTINCT h.INHOS_NO, h.MDC_ORG_CD\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL\n      AND TRIM(o.OPRT_CD) <> \'\'\n),\ndeath_record_time AS (\n    SELECT\n        s.INHOS_NO,\n        s.MDC_ORG_CD,\n        STR_TO_DATE(\n            REGEXP_REPLACE(\n                REGEXP_REPLACE(\n                    REGEXP_REPLACE(\n                        REGEXP_REPLACE(\n                            REGEXP_REPLACE(\n                                REGEXP_SUBSTR(s.ITM_VLU,\n                                    \'死亡时间[:：][[:space:]]*[0-9]{4}年[0-9]{1,2}月[0-9]{1,2}日[[:space:]]*[0-9]{1,2}时[0-9]{2}分|死亡时间[:：][[:space:]]*[0-9]{4}-[0-9]{1,2}-[0-9]{1,2}[[:space:]]+[0-9]{1,2}:[0-9]{2}\'),\n                                \'日[[:space:]]*\', \' \'\n                            ),\n                            \'[年月]\', \'-\'\n                        ),\n                        \'死亡时间[:：][[:space:]]*\', \'\'\n                    ),\n                    \'时\', \':\'\n                ),\n                \'分\', \'\'\n            ),\n            \'%Y-%m-%d %H:%i\'\n        ) AS DEATH_DT_TM\n    FROM FACT_INHOS_CRS_RCD_S s\n    WHERE s.RCD_TP_NM LIKE \'%死亡记录%\'\n      AND s.ITM_NM = \'文本主体\'\n      AND s.ITM_VLU LIKE \'%死亡时间%\'\n),\nclear_death_with_surgery AS (\n    SELECT\n        h.INHOS_NO,\n        h.MDC_ORG_CD,\n        o.OPRT_DT,\n        d.DEATH_DT_TM,\n        CASE WHEN DATE(d.DEATH_DT_TM) = DATE(o.OPRT_DT) THEN 1 ELSE 0 END AS death_same_day,\n        CASE WHEN d.DEATH_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, d.DEATH_DT_TM) <= 24\n            THEN 1 ELSE 0 END AS death_within_24h,\n        CASE WHEN d.DEATH_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, d.DEATH_DT_TM) <= 48\n            THEN 1 ELSE 0 END AS death_within_48h\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    INNER JOIN death_record_time d\n        ON h.INHOS_NO = d.INHOS_NO AND h.MDC_ORG_CD = d.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL AND TRIM(o.OPRT_CD) <> \'\'\n      AND h.DSCG_WAY_NM = \'死亡\'\n      AND d.DEATH_DT_TM IS NOT NULL\n      AND o.OPRT_DT IS NOT NULL\n),\nproxy_death_with_surgery AS (\n    SELECT\n        h.INHOS_NO,\n        h.MDC_ORG_CD,\n        o.OPRT_DT,\n        h.DSCG_DT_TM AS DEATH_DT_TM,\n        CASE WHEN DATE(h.DSCG_DT_TM) = DATE(o.OPRT_DT) THEN 1 ELSE 0 END AS death_same_day,\n        CASE WHEN h.DSCG_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, h.DSCG_DT_TM) <= 24\n            THEN 1 ELSE 0 END AS death_within_24h,\n        CASE WHEN h.DSCG_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, h.DSCG_DT_TM) <= 48\n            THEN 1 ELSE 0 END AS death_within_48h\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL AND TRIM(o.OPRT_CD) <> \'\'\n      AND h.TNOVR_CDT_NM = \'死亡\'\n      AND h.DSCG_WAY_NM = \'非医嘱离院\'\n      AND o.OPRT_DT IS NOT NULL\n),\npatient_flags AS (\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        MAX(death_same_day) AS clear_death_same_day,\n        MAX(death_within_24h) AS clear_death_within_24h,\n        MAX(death_within_48h) AS clear_death_within_48h,\n        0 AS proxy_death_same_day,\n        0 AS proxy_death_within_24h,\n        0 AS proxy_death_within_48h\n    FROM clear_death_with_surgery\n    GROUP BY INHOS_NO, MDC_ORG_CD\n    UNION ALL\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        0, 0, 0,\n        MAX(death_same_day),\n        MAX(death_within_24h),\n        MAX(death_within_48h)\n    FROM proxy_death_with_surgery\n    GROUP BY INHOS_NO, MDC_ORG_CD\n),\npatient_agg AS (\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        MAX(clear_death_same_day) AS clear_same_day,\n        MAX(clear_death_within_24h) AS clear_24h,\n        MAX(clear_death_within_48h) AS clear_48h,\n        MAX(proxy_death_same_day) AS proxy_same_day,\n        MAX(proxy_death_within_24h) AS proxy_24h,\n        MAX(proxy_death_within_48h) AS proxy_48h\n    FROM patient_flags\n    GROUP BY INHOS_NO, MDC_ORG_CD\n)\nSELECT\n    COUNT(DISTINCT d.INHOS_NO, d.MDC_ORG_CD) AS denominator_surgery_patients,\n\n    SUM(COALESCE(a.clear_same_day, 0)) AS numerator_clear_death_same_day,\n    SUM(COALESCE(a.clear_24h, 0))       AS numerator_clear_death_24h,\n    SUM(COALESCE(a.clear_48h, 0))       AS numerator_clear_death_48h,\n\n    SUM(COALESCE(a.proxy_same_day, 0))  AS numerator_proxy_death_same_day,\n    SUM(COALESCE(a.proxy_24h, 0))       AS numerator_proxy_death_24h,\n    SUM(COALESCE(a.proxy_48h, 0))       AS numerator_proxy_death_48h\nFROM denominator_base d\nLEFT JOIN patient_agg a\n    ON d.INHOS_NO = a.INHOS_NO AND d.MDC_ORG_CD = a.MDC_ORG_CD', 'SELECT t1.INHOS_NO, t1.MDC_ORG_CD, t2.OPRT_DT, t1.DSCG_DT_TM\nFROM FACT_MDC_RCD_HMPG t1\nJOIN (\n    SELECT INHOS_NO, MDC_ORG_CD, OPRT_DT\n    FROM (\n        SELECT INHOS_NO, MDC_ORG_CD, OPRT_DT, ROW_NUMBER() OVER (PARTITION BY INHOS_NO ORDER BY OPRT_DT DESC) rn\n        FROM FACT_MDC_RCD_HMPG_OPRT\n        WHERE INVLD_FLG = \'0\'\n    ) t_sub\n    WHERE rn = 1\n) t2 ON t1.INHOS_NO = t2.INHOS_NO AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t1.INVLD_FLG = \'0\'\n  AND t1.DSCG_DT_TM IS NOT NULL', 'success', 1, 1, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-24 01:47:23', 'discharge', 'COMPOSITE', '{\"type\": \"COMPOSITE_RATE\", \"items\": [{\"key\": \"clear_same_day\", \"name\": \"术后当日死亡（离院）\", \"numerator_col\": \"numerator_clear_death_same_day\", \"denominator_col\": \"denominator_surgery_patients\"}, {\"key\": \"clear_24h\", \"name\": \"术后24h死亡（离院）\", \"numerator_col\": \"numerator_clear_death_24h\", \"denominator_col\": \"denominator_surgery_patients\"}, {\"key\": \"clear_48h\", \"name\": \"术后48h死亡（离院）\", \"numerator_col\": \"numerator_clear_death_48h\", \"denominator_col\": \"denominator_surgery_patients\"}, {\"key\": \"proxy_same_day\", \"name\": \"术后当日死亡（转归）\", \"numerator_col\": \"numerator_proxy_death_same_day\", \"denominator_col\": \"denominator_surgery_patients\"}, {\"key\": \"proxy_24h\", \"name\": \"术后24h死亡（转归）\", \"numerator_col\": \"numerator_proxy_death_24h\", \"denominator_col\": \"denominator_surgery_patients\"}, {\"key\": \"proxy_48h\", \"name\": \"术后48h死亡（转归）\", \"numerator_col\": \"numerator_proxy_death_48h\", \"denominator_col\": \"denominator_surgery_patients\"}]}');
INSERT INTO `indicator` VALUES (60, '手术并发症发生率', 'core18', '', 41, '', '', '', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (61, 'I类切口手术抗菌药物预防使用率', 'core18', '', 42, '', '', '', '', '', 'none', '', '', '[]', '', '', '', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-14 11:00:17', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (62, '住院手术患者VTE发生率', 'core18', '', 43, '', '', '', '统计各医疗机构住院患者的 VTE（静脉血栓栓塞症）发生率。VTE 包括：深静脉血栓形成、肺动脉栓塞。分母为所有有效（INVLD_FLG=\'0\'）且关联了手术记录的住院患者（按 INHOS_NO 去重）。分子为在分母患者中，同时满足以下条件的患者：① 存在诊断为\"深静脉血栓形成\"或\"肺动脉栓塞\"的诊断记录（DIAG_NM LIKE \'深静脉血栓形成\' OR DIAG_NM LIKE \'肺动脉栓塞\'）；② 该诊断的入院病情代码为 4（入院时不存在，为入院后新发生）。最终计算比值 = 分子 ÷ 分母 × 100%。', '', 'sql', '-- 分子 SQL\nSELECT DISTINCT t1.INHOS_NO\nFROM FACT_MDC_RCD_HMPG t1\nWHERE t1.INVLD_FLG = \'0\'\nAND EXISTS (\n    SELECT 1\n    FROM FACT_MDC_RCD_HMPG_OPRT t2\n    WHERE t1.INHOS_NO = t2.INHOS_NO\n      AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n      AND t2.INVLD_FLG = \'0\'\n)\nAND EXISTS (\n    SELECT 1\n    FROM FACT_MDC_RCD_HMPG_DIAG t3\n    WHERE t1.INHOS_NO = t3.INHOS_NO\n      AND t1.MDC_ORG_CD = t3.MDC_ORG_CD\n      AND t3.INVLD_FLG = \'0\'\n      AND (\n          t3.DIAG_NM LIKE \'深静脉血栓形成\'\n          OR t3.DIAG_NM LIKE \'肺动脉栓塞\'\n      )\n      AND t3.INHOS_CDT_CD = \'4\'\n)\n\n-- 分母 SQL\nSELECT DISTINCT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM\nFROM FACT_MDC_RCD_HMPG t1 \nJOIN FACT_MDC_RCD_HMPG_OPRT t2 \nON t1.INHOS_NO = t2.INHOS_NO AND t1.MDC_ORG_CD = t2.MDC_ORG_CD \nWHERE t1.INVLD_FLG = \'0\' AND t2.INVLD_FLG = \'0\'', '', '[\"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_INHOS_DIAG_INFMT\", \"FACT_MDC_RCD_HMPG\", \"FACT_MDC_RCD_HMPG_OPRT\", \"FACT_MDC_RCD_HMPG_DIAG\", \"FACT_INHOS_DIAG_INFMT\"]', '诊断（深静脉血栓形成 OR 肺动脉栓塞）且入院病情代码为\"4\"（入院后新发生）的患者', '有手术记录的出院患者，有效状态，去重方式：COUNT DISTINCT INHOS_NO', 'SELECT DISTINCT t1.INHOS_NO\nFROM FACT_MDC_RCD_HMPG t1\nWHERE t1.INVLD_FLG = \'0\'\nAND EXISTS (\n    SELECT 1\n    FROM FACT_MDC_RCD_HMPG_OPRT t2\n    WHERE t1.INHOS_NO = t2.INHOS_NO\n      AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n      AND t2.INVLD_FLG = \'0\'\n)\nAND EXISTS (\n    SELECT 1\n    FROM FACT_MDC_RCD_HMPG_DIAG t3\n    WHERE t1.INHOS_NO = t3.INHOS_NO\n      AND t1.MDC_ORG_CD = t3.MDC_ORG_CD\n      AND t3.INVLD_FLG = \'0\'\n      AND (\n          t3.DIAG_NM LIKE \'深静脉血栓形成\'\n          OR t3.DIAG_NM LIKE \'肺动脉栓塞\'\n      )\n      AND t3.INHOS_CDT_CD = \'4\'\n)', 'SELECT DISTINCT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM\nFROM FACT_MDC_RCD_HMPG t1 \nJOIN FACT_MDC_RCD_HMPG_OPRT t2 \nON t1.INHOS_NO = t2.INHOS_NO AND t1.MDC_ORG_CD = t2.MDC_ORG_CD \nWHERE t1.INVLD_FLG = \'0\' AND t2.INVLD_FLG = \'0\'', 'pending', 1, 1, 0, '', '', 0, '', 'ratio', '2026-04-14 11:00:17', '2026-04-23 03:53:18', 'discharge', 'RATE', NULL);
INSERT INTO `indicator` VALUES (63, '越权开具抗生素', 'four', '人员要素', 1, '审核范围：住院', '在系统中维护医师职称，设定「职称-限制级、特殊级抗生素」匹配规则，对超范围业务自动报警。', '医生开了与自己职称不符的限制级或者特殊级抗生素', '', '', 'sql', '/*\n1、通过职工表DIM_STFF中TTL_LVL_NM字段判断抗生素使用权限——\n    可使用限制级抗生素的职称：医师、住院医师、主治中医师、中医师、医士、主治医师、副主任医师、主任医师；\n    可使用特殊级抗生素的职称：副主任医师、主任医师。\n2、直接从医嘱表 FACT_INHOS_ODR_INFMT 的ODR_ITM_NM 获取药品名称（DRG_DOSG_FOM_CD 非空时，该字段为药品名称）\n3、通过给药途径进行细致区分，匹配时需结合 DRG_DOSG_FOM_NM 字段，即除了药品名称模糊匹配之外，还需要通过DRG_DOSG_FOM_NM字段匹配：\n    口服药：剂型模糊包含“片”、“缓释”、“混悬”、“胶囊”、“颗粒”\n    注射药：剂型模糊包含“注射”、“冻干”、“针剂”、“粉剂”\n    复方药：（形如A/B，例如“亚胺培南/西司他丁”的药）使用“%A%B%”模糊匹配，不限制剂型\n    无特殊标记的药物：按原名称匹配，不限制剂型\n4、注意：有些药物不同的用药途径是不同的使用级\n\n限制级：\n口服：奥马环素、法罗培南、奈诺沙星、粘菌素、对于利奈唑胺、磷酸特地唑胺、伏立康唑、泊沙康唑、艾沙康唑\n注射：克林霉素、莫西沙星、氟康唑\n复方：氨苄西林/舒巴坦、哌拉西林/他唑巴坦、替卡西林/克拉维酸、头孢哌酮/舒巴坦\n\n特殊级：\n口服：西他沙星\n注射：奥马环素、法罗培南、奈诺沙星、粘菌素、利奈唑胺、伊曲康唑、伏立康唑、艾沙康唑、泊沙康唑\n复方：头孢他啶/阿维巴坦、亚胺培南/西司他丁\n*/\nWITH drug_scope AS (\n    -- ==================== 通用药物（不区分剂型） ====================\n    -- 限制使用级\n    SELECT \'限制使用级\' AS drg_lvl, \'米诺环素\' AS drg_nm, NULL AS route_type FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'氯霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'甲砜霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'阿洛西林\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'美洛西林\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'氯唑西林\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'舒巴坦\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'苯唑西林\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢硫脒\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢丙烯\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢替安\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢噻肟\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢他啶\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢唑肟\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢地尼\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢哌酮\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢地嗪钠\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢泊肟酯\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢卡品酯\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢美唑\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢西丁\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢米诺\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'拉氧头孢\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'氨曲南\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'厄他培南\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'磺胺多辛\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'环酯红霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'林可霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'依替米星\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'妥布霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'奈替米星\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'大观霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'加替沙星\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'奥硝唑\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'左旋奥硝唑\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'吗啉硝唑\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'利福平\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'利福霉素\', NULL FROM DUAL\n    -- 特殊使用级（通用）\n    UNION ALL SELECT \'特殊使用级\', \'替加环素\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'头孢匹罗\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'头孢吡肟\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'头孢托仑匹酯\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'头孢噻肟钠他唑巴坦钠\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'美罗培南\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'比阿培南\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'万古霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'去甲万古霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'替考拉宁\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'多粘菌素B\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'夫西地酸\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'康替唑胺\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'达托霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'两性霉素B\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'米卡芬净\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'卡泊芬净\', NULL FROM DUAL\n\n    UNION ALL\n    -- ==================== 区分给药途径的药物 ====================\n    -- 1. 限制级口服\n    SELECT \'限制使用级\', \'奥马环素\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'法罗培南\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'奈诺沙星\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'粘菌素\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'利奈唑胺\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'磷酸特地唑胺\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'伏立康唑\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'泊沙康唑\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'艾沙康唑\', \'口服\' FROM DUAL\n\n    -- 2. 限制级注射\n    UNION ALL SELECT \'限制使用级\', \'克林霉素\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'莫西沙星\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'氟康唑\', \'注射\' FROM DUAL\n\n    -- 3. 限制级复方制剂\n    UNION ALL SELECT \'限制使用级\', \'氨苄西林/舒巴坦\', \'复方\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'哌拉西林/他唑巴坦\', \'复方\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'替卡西林/克拉维酸\', \'复方\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢哌酮/舒巴坦\', \'复方\' FROM DUAL\n\n    -- 4. 特殊级口服\n    UNION ALL SELECT \'特殊使用级\', \'西他沙星\', \'口服\' FROM DUAL\n\n    -- 5. 特殊级注射\n    UNION ALL SELECT \'特殊使用级\', \'奥马环素\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'法罗培南\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'奈诺沙星\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'粘菌素\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'利奈唑胺\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'伊曲康唑\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'伏立康唑\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'艾沙康唑\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'泊沙康唑\', \'注射\' FROM DUAL\n\n    -- 6. 特殊级复方制剂\n    UNION ALL SELECT \'特殊使用级\', \'头孢他啶/阿维巴坦\', \'复方\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'亚胺培南/西司他丁\', \'复方\' FROM DUAL\n),\nodr_base AS (\n    -- 提取有效药品类医嘱，关联开嘱医生职称，并清洗名称/剂型字段\n    SELECT\n        o.MDC_ORG_CD,\n        o.MDC_ORG_NM,\n        o.INHOS_NO,\n        o.ODR_ITM_CD,\n        o.ODR_ITM_NM,\n        o.DRG_DOSG_FOM_NM AS dosg_fom_nm,   -- 剂型名称\n        o.ODR_OPN_DCT_CD,\n        o.ODR_OPN_DCT_NM,\n        o.ODR_OPN_DPT_CD,\n        o.ODR_OPN_DPT_NM,\n        o.ODR_OPN_DT_TM,\n        s.TTL_LVL_NM,\n        -- 清洗药品名称（去#、*、全角/半角空格）供模糊匹配\n        REPLACE(REPLACE(REPLACE(REPLACE(o.ODR_ITM_NM, \'#\', \'\'), \'*\', \'\'), \' \', \'\'), \' \', \'\') AS norm_drg_nm\n    FROM FACT_INHOS_ODR_INFMT o\n    LEFT JOIN DIM_STFF s\n        ON o.MDC_ORG_CD = s.MDC_ORG_CD\n       AND o.ODR_OPN_DCT_CD = s.STFF_CD\n    WHERE (o.INVLD_FLG IS NULL OR o.INVLD_FLG <> \'1\')\n      AND o.DRG_DOSG_FOM_CD IS NOT NULL\n),\nscope_match AS (\n    -- 将医嘱与抗生素目录关联，结合剂型/给药途径判定最终抗生素级别\n    SELECT\n        b.*,\n        ds.drg_lvl\n    FROM odr_base b\n    INNER JOIN drug_scope ds\n        ON (\n            -- 条件1：药品名称匹配\n            CASE\n                -- 联系（复方）类：将“/”替换为“%”，形成“%成分A%成分B%”模糊模式\n                WHEN ds.route_type = \'联系\'\n                THEN b.norm_drg_nm LIKE \'%\' || REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(ds.drg_nm, \'#\', \'\'), \'*\', \'\'), \' \', \'\'), \' \', \'\'), \'/\', \'%\') || \'%\'\n                -- 其他类型（含通用）直接模糊包含\n                ELSE b.norm_drg_nm LIKE \'%\' || REPLACE(REPLACE(REPLACE(REPLACE(ds.drg_nm, \'#\', \'\'), \'*\', \'\'), \' \', \'\'), \' \', \'\') || \'%\'\n            END\n            AND\n            -- 条件2：给药途径匹配（如有限制）\n            CASE\n                WHEN ds.route_type IS NULL THEN 1\n                WHEN ds.route_type = \'口服\' THEN\n                    CASE WHEN b.dosg_fom_nm LIKE \'%剂%\'    OR\n                              b.dosg_fom_nm LIKE \'%缓释%\'  OR\n                              b.dosg_fom_nm LIKE \'%混悬%\'  OR\n                              b.dosg_fom_nm LIKE \'%胶囊%\'  OR\n                              b.dosg_fom_nm LIKE \'%颗粒%\'\n                         THEN 1 ELSE 0 END\n                WHEN ds.route_type = \'注射\' THEN\n                    CASE WHEN b.dosg_fom_nm LIKE \'%注射%\'  OR\n                              b.dosg_fom_nm LIKE \'%冻干%\'  OR\n                              b.dosg_fom_nm LIKE \'%针剂%\'  OR\n                              b.dosg_fom_nm LIKE \'%粉剂%\'\n                         THEN 1 ELSE 0 END\n                WHEN ds.route_type = \'联系\' THEN 1   -- 复方药物不限制剂型\n                ELSE 0\n            END = 1\n        )\n)\n-- 最终输出：违反职称权限的抗生素使用记录\nSELECT\n    m.MDC_ORG_CD,\n    m.MDC_ORG_NM,\n    m.INHOS_NO,\n    m.ODR_ITM_CD,\n    m.ODR_ITM_NM AS DRG_NM,\n    m.drg_lvl AS ANTBTC_SCOPE_LVL,\n    m.ODR_OPN_DCT_CD,\n    m.ODR_OPN_DCT_NM,\n    m.ODR_OPN_DPT_CD,\n    m.ODR_OPN_DPT_NM,\n    m.TTL_LVL_NM,\n    m.ODR_OPN_DT_TM,\n    CASE\n        WHEN m.drg_lvl = \'特殊使用级\'\n             AND m.TTL_LVL_NM NOT IN (\'副主任医师\', \'主任医师\')\n            THEN \'职称与特殊级抗生素不匹配\'\n        WHEN m.drg_lvl = \'限制使用级\'\n             AND m.TTL_LVL_NM NOT IN (\n                    \'医师\',\'住院医师\',\'主治中医师\',\'中医师\',\n                    \'医士\',\'主治医师\',\'副主任医师\',\'主任医师\'\n                 )\n            THEN \'职称与限制级抗生素不匹配\'\n    END AS ALERT_REASON\nFROM scope_match m\nWHERE\n    ( m.drg_lvl = \'特殊使用级\'\n      AND m.TTL_LVL_NM NOT IN (\'副主任医师\', \'主任医师\') )\n    OR\n    ( m.drg_lvl = \'限制使用级\'\n      AND m.TTL_LVL_NM NOT IN (\n            \'医师\',\'住院医师\',\'主治中医师\',\'中医师\',\n            \'医士\',\'主治医师\',\'副主任医师\',\'主任医师\'\n          ) )', '', '[]', '', '', '/*\n1、通过职工表DIM_STFF中TTL_LVL_NM字段判断抗生素使用权限——\n    可使用限制级抗生素的职称：医师、住院医师、主治中医师、中医师、医士、主治医师、副主任医师、主任医师；\n    可使用特殊级抗生素的职称：副主任医师、主任医师。\n2、直接从医嘱表 FACT_INHOS_ODR_INFMT 的ODR_ITM_NM 获取药品名称（DRG_DOSG_FOM_CD 非空时，该字段为药品名称）\n3、通过给药途径进行细致区分，匹配时需结合 DRG_DOSG_FOM_NM 字段，即除了药品名称模糊匹配之外，还需要通过DRG_DOSG_FOM_NM字段匹配：\n    口服药：剂型模糊包含“片”、“缓释”、“混悬”、“胶囊”、“颗粒”\n    注射药：剂型模糊包含“注射”、“冻干”、“针剂”、“粉剂”\n    复方药：（形如A/B，例如“亚胺培南/西司他丁”的药）使用“%A%B%”模糊匹配，不限制剂型\n    无特殊标记的药物：按原名称匹配，不限制剂型\n4、注意：有些药物不同的用药途径是不同的使用级\n\n限制级：\n口服：奥马环素、法罗培南、奈诺沙星、粘菌素、对于利奈唑胺、磷酸特地唑胺、伏立康唑、泊沙康唑、艾沙康唑\n注射：克林霉素、莫西沙星、氟康唑\n复方：氨苄西林/舒巴坦、哌拉西林/他唑巴坦、替卡西林/克拉维酸、头孢哌酮/舒巴坦\n\n特殊级：\n口服：西他沙星\n注射：奥马环素、法罗培南、奈诺沙星、粘菌素、利奈唑胺、伊曲康唑、伏立康唑、艾沙康唑、泊沙康唑\n复方：头孢他啶/阿维巴坦、亚胺培南/西司他丁\n*/\nWITH drug_scope AS (\n    -- ==================== 通用药物（不区分剂型） ====================\n    -- 限制使用级\n    SELECT \'限制使用级\' AS drg_lvl, \'米诺环素\' AS drg_nm, NULL AS route_type FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'氯霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'甲砜霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'阿洛西林\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'美洛西林\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'氯唑西林\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'舒巴坦\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'苯唑西林\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢硫脒\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢丙烯\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢替安\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢噻肟\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢他啶\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢唑肟\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢地尼\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢哌酮\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢地嗪钠\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢泊肟酯\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢卡品酯\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢美唑\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢西丁\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢米诺\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'拉氧头孢\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'氨曲南\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'厄他培南\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'磺胺多辛\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'环酯红霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'林可霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'依替米星\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'妥布霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'奈替米星\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'大观霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'加替沙星\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'奥硝唑\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'左旋奥硝唑\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'吗啉硝唑\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'利福平\', NULL FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'利福霉素\', NULL FROM DUAL\n    -- 特殊使用级（通用）\n    UNION ALL SELECT \'特殊使用级\', \'替加环素\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'头孢匹罗\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'头孢吡肟\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'头孢托仑匹酯\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'头孢噻肟钠他唑巴坦钠\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'美罗培南\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'比阿培南\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'万古霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'去甲万古霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'替考拉宁\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'多粘菌素B\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'夫西地酸\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'康替唑胺\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'达托霉素\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'两性霉素B\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'米卡芬净\', NULL FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'卡泊芬净\', NULL FROM DUAL\n\n    UNION ALL\n    -- ==================== 区分给药途径的药物 ====================\n    -- 1. 限制级口服\n    SELECT \'限制使用级\', \'奥马环素\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'法罗培南\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'奈诺沙星\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'粘菌素\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'利奈唑胺\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'磷酸特地唑胺\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'伏立康唑\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'泊沙康唑\', \'口服\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'艾沙康唑\', \'口服\' FROM DUAL\n\n    -- 2. 限制级注射\n    UNION ALL SELECT \'限制使用级\', \'克林霉素\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'莫西沙星\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'氟康唑\', \'注射\' FROM DUAL\n\n    -- 3. 限制级复方制剂\n    UNION ALL SELECT \'限制使用级\', \'氨苄西林/舒巴坦\', \'复方\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'哌拉西林/他唑巴坦\', \'复方\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'替卡西林/克拉维酸\', \'复方\' FROM DUAL\n    UNION ALL SELECT \'限制使用级\', \'头孢哌酮/舒巴坦\', \'复方\' FROM DUAL\n\n    -- 4. 特殊级口服\n    UNION ALL SELECT \'特殊使用级\', \'西他沙星\', \'口服\' FROM DUAL\n\n    -- 5. 特殊级注射\n    UNION ALL SELECT \'特殊使用级\', \'奥马环素\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'法罗培南\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'奈诺沙星\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'粘菌素\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'利奈唑胺\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'伊曲康唑\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'伏立康唑\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'艾沙康唑\', \'注射\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'泊沙康唑\', \'注射\' FROM DUAL\n\n    -- 6. 特殊级复方制剂\n    UNION ALL SELECT \'特殊使用级\', \'头孢他啶/阿维巴坦\', \'复方\' FROM DUAL\n    UNION ALL SELECT \'特殊使用级\', \'亚胺培南/西司他丁\', \'复方\' FROM DUAL\n),\nodr_base AS (\n    -- 提取有效药品类医嘱，关联开嘱医生职称，并清洗名称/剂型字段\n    SELECT\n        o.MDC_ORG_CD,\n        o.MDC_ORG_NM,\n        o.INHOS_NO,\n        o.ODR_ITM_CD,\n        o.ODR_ITM_NM,\n        o.DRG_DOSG_FOM_NM AS dosg_fom_nm,   -- 剂型名称\n        o.ODR_OPN_DCT_CD,\n        o.ODR_OPN_DCT_NM,\n        o.ODR_OPN_DPT_CD,\n        o.ODR_OPN_DPT_NM,\n        o.ODR_OPN_DT_TM,\n        s.TTL_LVL_NM,\n        -- 清洗药品名称（去#、*、全角/半角空格）供模糊匹配\n        REPLACE(REPLACE(REPLACE(REPLACE(o.ODR_ITM_NM, \'#\', \'\'), \'*\', \'\'), \' \', \'\'), \' \', \'\') AS norm_drg_nm\n    FROM FACT_INHOS_ODR_INFMT o\n    LEFT JOIN DIM_STFF s\n        ON o.MDC_ORG_CD = s.MDC_ORG_CD\n       AND o.ODR_OPN_DCT_CD = s.STFF_CD\n    WHERE (o.INVLD_FLG IS NULL OR o.INVLD_FLG <> \'1\')\n      AND o.DRG_DOSG_FOM_CD IS NOT NULL\n),\nscope_match AS (\n    -- 将医嘱与抗生素目录关联，结合剂型/给药途径判定最终抗生素级别\n    SELECT\n        b.*,\n        ds.drg_lvl\n    FROM odr_base b\n    INNER JOIN drug_scope ds\n        ON (\n            -- 条件1：药品名称匹配\n            CASE\n                -- 联系（复方）类：将“/”替换为“%”，形成“%成分A%成分B%”模糊模式\n                WHEN ds.route_type = \'联系\'\n                THEN b.norm_drg_nm LIKE \'%\' || REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(ds.drg_nm, \'#\', \'\'), \'*\', \'\'), \' \', \'\'), \' \', \'\'), \'/\', \'%\') || \'%\'\n                -- 其他类型（含通用）直接模糊包含\n                ELSE b.norm_drg_nm LIKE \'%\' || REPLACE(REPLACE(REPLACE(REPLACE(ds.drg_nm, \'#\', \'\'), \'*\', \'\'), \' \', \'\'), \' \', \'\') || \'%\'\n            END\n            AND\n            -- 条件2：给药途径匹配（如有限制）\n            CASE\n                WHEN ds.route_type IS NULL THEN 1\n                WHEN ds.route_type = \'口服\' THEN\n                    CASE WHEN b.dosg_fom_nm LIKE \'%剂%\'    OR\n                              b.dosg_fom_nm LIKE \'%缓释%\'  OR\n                              b.dosg_fom_nm LIKE \'%混悬%\'  OR\n                              b.dosg_fom_nm LIKE \'%胶囊%\'  OR\n                              b.dosg_fom_nm LIKE \'%颗粒%\'\n                         THEN 1 ELSE 0 END\n                WHEN ds.route_type = \'注射\' THEN\n                    CASE WHEN b.dosg_fom_nm LIKE \'%注射%\'  OR\n                              b.dosg_fom_nm LIKE \'%冻干%\'  OR\n                              b.dosg_fom_nm LIKE \'%针剂%\'  OR\n                              b.dosg_fom_nm LIKE \'%粉剂%\'\n                         THEN 1 ELSE 0 END\n                WHEN ds.route_type = \'联系\' THEN 1   -- 复方药物不限制剂型\n                ELSE 0\n            END = 1\n        )\n)\n-- 最终输出：违反职称权限的抗生素使用记录\nSELECT\n    m.MDC_ORG_CD,\n    m.MDC_ORG_NM,\n    m.INHOS_NO,\n    m.ODR_ITM_CD,\n    m.ODR_ITM_NM AS DRG_NM,\n    m.drg_lvl AS ANTBTC_SCOPE_LVL,\n    m.ODR_OPN_DCT_CD,\n    m.ODR_OPN_DCT_NM,\n    m.ODR_OPN_DPT_CD,\n    m.ODR_OPN_DPT_NM,\n    m.TTL_LVL_NM,\n    m.ODR_OPN_DT_TM,\n    CASE\n        WHEN m.drg_lvl = \'特殊使用级\'\n             AND m.TTL_LVL_NM NOT IN (\'副主任医师\', \'主任医师\')\n            THEN \'职称与特殊级抗生素不匹配\'\n        WHEN m.drg_lvl = \'限制使用级\'\n             AND m.TTL_LVL_NM NOT IN (\n                    \'医师\',\'住院医师\',\'主治中医师\',\'中医师\',\n                    \'医士\',\'主治医师\',\'副主任医师\',\'主任医师\'\n                 )\n            THEN \'职称与限制级抗生素不匹配\'\n    END AS ALERT_REASON\nFROM scope_match m\nWHERE\n    ( m.drg_lvl = \'特殊使用级\'\n      AND m.TTL_LVL_NM NOT IN (\'副主任医师\', \'主任医师\') )\n    OR\n    ( m.drg_lvl = \'限制使用级\'\n      AND m.TTL_LVL_NM NOT IN (\n            \'医师\',\'住院医师\',\'主治中医师\',\'中医师\',\n            \'医士\',\'主治医师\',\'副主任医师\',\'主任医师\'\n          ) )', '', 'pending', 1, 0, 0, '', '', 0, '', 'ratio', '2026-04-21 02:49:00', '2026-05-17 17:30:01', 'discharge', NULL, NULL);

-- ----------------------------
-- Table structure for indicator_execution
-- ----------------------------
DROP TABLE IF EXISTS `indicator_execution`;
CREATE TABLE `indicator_execution`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `indicator_id` int NULL DEFAULT NULL,
  `indicator_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `execution_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `kind` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `run_mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `time_range` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `result_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `calc_method` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `scope` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `logs` json NULL,
  `numerator_sql` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `denominator_sql` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `sql` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `numerator_count` int NULL DEFAULT NULL,
  `denominator_count` int NULL DEFAULT NULL,
  `count` int NULL DEFAULT NULL,
  `rate_percent` double NULL DEFAULT NULL,
  `rate_formula` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `result_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `preview_data` json NULL,
  `denominator_preview_data` json NULL,
  `error` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `numerator_error` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `denominator_error` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `attempts` json NULL,
  `llm_thinking` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `llm_raw` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `cache_hit` tinyint(1) NULL DEFAULT NULL,
  `request_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `conversation_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `execution_time` datetime NULL DEFAULT NULL,
  `duration_seconds` double NULL DEFAULT NULL,
  `hospital_codes` json NULL COMMENT '执行时选中的医院代码列表',
  `time_mode` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'monthly=月度, quarterly=季度',
  `time_value` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '如 2026-04 或 2026-Q1',
  `date_field` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `group_by_hospital` tinyint(1) NULL DEFAULT 0,
  `hospital_results` json NULL,
  `subitem_data` json NULL COMMENT '复合指标子项详细数据',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `ix_execution_time`(`execution_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 301 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = DYNAMIC;

