INSERT INTO `indicator_execution` VALUES (11, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"02:59:39\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"02:59:39\", \"level\": \"info\", \"message\": \"分子结果：5 条记录。\"}, {\"time\": \"02:59:39\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"02:59:39\", \"level\": \"info\", \"message\": \"分母结果：10 条记录。\"}, {\"time\": \"02:59:39\", \"level\": \"info\", \"message\": \"执行完成。指标值：50.0%（5/10）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM\nFROM (\n    SELECT\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', '', 5, 10, NULL, 50, '5/10=50.0%', '', '{\"rows\": [], \"columns\": []}', '{}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM\\nFROM (\\n    SELECT\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1\", \"count\": 5, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 02:59:39', 0.055, NULL, NULL, NULL, NULL, 0, NULL, NULL);
INSERT INTO `indicator_execution` VALUES (12, 42, '四级手术与三级手术并发症发生率比', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"03:25:31\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"03:25:31\", \"level\": \"info\", \"message\": \"分子结果：1 条记录。\"}, {\"time\": \"03:25:31\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"03:25:31\", \"level\": \"info\", \"message\": \"分母结果：1 条记录。\"}, {\"time\": \"03:25:31\", \"level\": \"info\", \"message\": \"执行完成。指标值：100.0%（1/1）\"}]', 'WITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'4\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g4_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', 'WITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'3\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g3_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', '', 1, 1, NULL, 100, '1/1=100.0%', '', '{\"rows\": [], \"columns\": []}', '{}', '', '', '', '[{\"sql\": \"WITH Target_Complications AS (\\n    SELECT DIAG_CD\\n    FROM FACT_MDC_RCD_HMPG_DIAG\\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\\n),\\nBase_Surgery_Patients AS (\\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\\n    FROM FACT_MDC_RCD_HMPG h\\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \\n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \\n        AND h.INHOS_NO = o.INHOS_NO\\n    WHERE o.OPRT_LVL_CD = \'4\'\\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\\n      AND h.DSCG_DT_TM IS NOT NULL\\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\\n),\\nComplication_Patients AS (\\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\\n    FROM FACT_MDC_RCD_HMPG_DIAG d\\n    INNER JOIN Target_Complications tc \\n        ON d.DIAG_CD = tc.DIAG_CD\\n    WHERE d.INVLD_FLG = \'0\' \\n      AND d.INHOS_CDT_CD != \'1\'\\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\\n)\\nSELECT \\n    COUNT(b.INHOS_NO) AS total_cnt,\\n    COUNT(c.INHOS_NO) AS comp_cnt,\\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \\n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \\n    END AS g4_comp_rate\\nFROM Base_Surgery_Patients b\\nLEFT JOIN Complication_Patients c \\n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \\n    AND b.INHOS_NO = c.INHOS_NO\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 03:25:31', 0.662, NULL, NULL, NULL, NULL, 0, NULL, NULL);
INSERT INTO `indicator_execution` VALUES (13, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"03:31:12\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"03:31:12\", \"level\": \"info\", \"message\": \"查询结果：2 条记录。\"}, {\"time\": \"03:31:12\", \"level\": \"info\", \"message\": \"执行完成，共 2 条记录。\"}]', '', '', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', NULL, NULL, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{}', '', '', '', '[{\"sql\": \"WITH \\n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\\nmain_diag_sub AS (\\n    SELECT \\n        MDC_ORG_CD,\\n        MDC_ORG_NM,\\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\\n    FROM FACT_MDC_RCD_HMPG_DIAG\\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\\n        AND DIAG_CD IS NOT NULL\\n        AND DIAG_CD != \'\'\\n)\\n-- 按医疗机构分组，统计不同亚目数量\\nSELECT \\n    MDC_ORG_CD AS \'医疗机构代码\',\\n    MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\\nFROM main_diag_sub\\nWHERE sub_category IS NOT NULL \\n    AND sub_category != \'\'\\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\\nORDER BY MDC_ORG_CD;\", \"count\": 2, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 03:31:12', 0.052, NULL, NULL, NULL, NULL, 0, NULL, NULL);
INSERT INTO `indicator_execution` VALUES (14, 52, '主要手术ICD-9-CM-3四位码种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"03:31:19\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"03:31:19\", \"level\": \"info\", \"message\": \"查询结果：1 条记录。\"}, {\"time\": \"03:31:19\", \"level\": \"info\", \"message\": \"执行完成，共 1 条记录。\"}]', '', '', 'WITH \nmain_surgery AS (\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\n    SELECT \n        s.INHOS_NO,\n        s.OPRT_CD,\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\n    FROM FACT_MDC_RCD_HMPG_OPRT s\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\n        AND s.OPRT_CD IS NOT NULL\n        AND s.OPRT_CD != \'\'\n)\nSELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\nFROM main_surgery ms\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\nWHERE ms.surgery_4code IS NOT NULL \n    AND ms.surgery_4code != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\nORDER BY h.MDC_ORG_CD;', NULL, NULL, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{}', '', '', '', '[{\"sql\": \"WITH \\nmain_surgery AS (\\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\\n    SELECT \\n        s.INHOS_NO,\\n        s.OPRT_CD,\\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\\n    FROM FACT_MDC_RCD_HMPG_OPRT s\\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\\n        AND s.OPRT_CD IS NOT NULL\\n        AND s.OPRT_CD != \'\'\\n)\\nSELECT \\n    h.MDC_ORG_CD AS \'医疗机构代码\',\\n    h.MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\\nFROM main_surgery ms\\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\\nWHERE ms.surgery_4code IS NOT NULL \\n    AND ms.surgery_4code != \'\'\\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\\nORDER BY h.MDC_ORG_CD;\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 03:31:19', 0.045, NULL, NULL, NULL, NULL, 0, NULL, NULL);
