ND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1\", \"count\": 3, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 03:34:04', 0.094, NULL, NULL, NULL, NULL, 0, NULL, NULL);
INSERT INTO `indicator_execution` VALUES (16, 62, '住院手术患者VTE发生率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"03:53:26\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"03:53:26\", \"level\": \"info\", \"message\": \"分子结果：2 条记录。\"}, {\"time\": \"03:53:26\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"03:53:26\", \"level\": \"info\", \"message\": \"分母结果：12 条记录。\"}, {\"time\": \"03:53:26\", \"level\": \"info\", \"message\": \"执行完成。指标值：16.6667%（2/12）\"}]', 'SELECT DISTINCT t1.INHOS_NO\nFROM FACT_MDC_RCD_HMPG t1\nWHERE t1.INVLD_FLG = \'0\'\nAND EXISTS (\n    SELECT 1\n    FROM FACT_MDC_RCD_HMPG_OPRT t2\n    WHERE t1.INHOS_NO = t2.INHOS_NO\n      AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n      AND t2.INVLD_FLG = \'0\'\n)\nAND EXISTS (\n    SELECT 1\n    FROM FACT_MDC_RCD_HMPG_DIAG t3\n    WHERE t1.INHOS_NO = t3.INHOS_NO\n      AND t1.MDC_ORG_CD = t3.MDC_ORG_CD\n      AND t3.INVLD_FLG = \'0\'\n      AND (\n          t3.DIAG_NM LIKE \'深静脉血栓形成\'\n          OR t3.DIAG_NM LIKE \'肺动脉栓塞\'\n      )\n      AND t3.INHOS_CDT_CD = \'4\'\n)', 'SELECT DISTINCT t1.INHOS_NO, t1.MDC_ORG_CD, t1.NM\nFROM FACT_MDC_RCD_HMPG t1 \nJOIN FACT_MDC_RCD_HMPG_OPRT t2 \nON t1.INHOS_NO = t2.INHOS_NO AND t1.MDC_ORG_CD = t2.MDC_ORG_CD \nWHERE t1.INVLD_FLG = \'0\' AND t2.INVLD_FLG = \'0\'', '', 2, 12, NULL, 16.6667, '2/12=16.6667%', '', '{\"rows\": [], \"columns\": []}', '{}', '', '', '', '[{\"sql\": \"SELECT DISTINCT t1.INHOS_NO\\nFROM FACT_MDC_RCD_HMPG t1\\nWHERE t1.INVLD_FLG = \'0\'\\nAND EXISTS (\\n    SELECT 1\\n    FROM FACT_MDC_RCD_HMPG_OPRT t2\\n    WHERE t1.INHOS_NO = t2.INHOS_NO\\n      AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\\n      AND t2.INVLD_FLG = \'0\'\\n)\\nAND EXISTS (\\n    SELECT 1\\n    FROM FACT_MDC_RCD_HMPG_DIAG t3\\n    WHERE t1.INHOS_NO = t3.INHOS_NO\\n      AND t1.MDC_ORG_CD = t3.MDC_ORG_CD\\n      AND t3.INVLD_FLG = \'0\'\\n      AND (\\n          t3.DIAG_NM LIKE \'深静脉血栓形成\'\\n          OR t3.DIAG_NM LIKE \'肺动脉栓塞\'\\n      )\\n      AND t3.INHOS_CDT_CD = \'4\'\\n)\", \"count\": 2, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 03:53:26', 0.113, NULL, NULL, NULL, NULL, 0, NULL, NULL);
