INSERT INTO `indicator_execution` VALUES (21, 43, '四级手术与三级手术患者死亡率比', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"分子结果：1 条记录。\"}, {\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"分母结果：1 条记录。\"}, {\"time\": \"07:42:23\", \"level\": \"info\", \"message\": \"执行完成。指标值：100.0%（1/1）\"}]', 'SELECT \n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \n    / \n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g4_death_rate\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \n    AND h.INHOS_NO = o.INHOS_NO\nWHERE o.OPRT_LVL_CD = \'4\'\n  AND h.DSCG_DT_TM IS NOT NULL\n  AND h.INVLD_FLG = \'0\' \n  AND o.INVLD_FLG = \'0\';', 'SELECT \n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \n    / \n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g3_death_rate\nFROM FACT_MDC_RCD_HMPG h\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \n    AND h.INHOS_NO = o.INHOS_NO\nWHERE o.OPRT_LVL_CD = \'3\'\n  AND h.DSCG_DT_TM IS NOT NULL\n  AND h.INVLD_FLG = \'0\' \n  AND o.INVLD_FLG = \'0\';', '', 1, 1, NULL, 100, '1/1=100.0%', '', '{\"rows\": [], \"columns\": []}', '{}', '', '', '', '[{\"sql\": \"SELECT \\n    CAST(COUNT(DISTINCT CASE WHEN h.DSCG_WAY_CD = \'5\' THEN h.INHOS_NO END) AS DECIMAL(18,4)) \\n    / \\n    NULLIF(COUNT(DISTINCT h.INHOS_NO), 0) AS g4_death_rate\\nFROM FACT_MDC_RCD_HMPG h\\nINNER JOIN FACT_MDC_RCD_HMPG_OPRT o \\n    ON h.MDC_ORG_CD = o.MDC_ORG_CD \\n    AND h.INHOS_NO = o.INHOS_NO\\nWHERE o.OPRT_LVL_CD = \'4\'\\n  AND h.DSCG_DT_TM IS NOT NULL\\n  AND h.INVLD_FLG = \'0\' \\n  AND o.INVLD_FLG = \'0\';\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 07:42:23', 0.197, NULL, NULL, NULL, NULL, 0, NULL, NULL);
INSERT INTO `indicator_execution` VALUES (22, 42, '四级手术与三级手术并发症发生率比', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"07:46:21\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"07:46:21\", \"level\": \"info\", \"message\": \"分子结果：1 条记录。\"}, {\"time\": \"07:46:21\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"07:46:21\", \"level\": \"info\", \"message\": \"分母结果：1 条记录。\"}, {\"time\": \"07:46:21\", \"level\": \"info\", \"message\": \"执行完成。指标值：100.0%（1/1）\"}]', 'WITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'4\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g4_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', 'WITH Target_Complications AS (\n    SELECT DIAG_CD\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\n),\nBase_Surgery_Patients AS (\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \n        AND h.INHOS_NO = o.INHOS_NO\n    WHERE o.OPRT_LVL_CD = \'3\'\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\n      AND h.DSCG_DT_TM IS NOT NULL\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\n),\nComplication_Patients AS (\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\n    FROM FACT_MDC_RCD_HMPG_DIAG d\n    INNER JOIN Target_Complications tc \n        ON d.DIAG_CD = tc.DIAG_CD\n    WHERE d.INVLD_FLG = \'0\' \n      AND d.INHOS_CDT_CD != \'1\'\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\n)\nSELECT \n    COUNT(b.INHOS_NO) AS total_cnt,\n    COUNT(c.INHOS_NO) AS comp_cnt,\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \n    END AS g3_comp_rate\nFROM Base_Surgery_Patients b\nLEFT JOIN Complication_Patients c \n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \n    AND b.INHOS_NO = c.INHOS_NO', '', 1, 1, NULL, 100, '1/1=100.0%', '', '{\"rows\": [], \"columns\": []}', '{}', '', '', '', '[{\"sql\": \"WITH Target_Complications AS (\\n    SELECT DIAG_CD\\n    FROM FACT_MDC_RCD_HMPG_DIAG\\n    WHERE DIAG_NM REGEXP \'肺栓塞|深静脉血栓|脓毒症|出血|血肿|伤口裂开|呼吸衰竭|生理紊乱|代谢紊乱|感染|异物遗留|麻醉并发症|肺部感染|肺机能不全|穿刺伤|撕裂伤|急性肾衰竭\'\\n),\\nBase_Surgery_Patients AS (\\n    SELECT h.MDC_ORG_CD, h.INHOS_NO\\n    FROM FACT_MDC_RCD_HMPG h\\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o \\n        ON h.MDC_ORG_CD = o.MDC_ORG_CD \\n        AND h.INHOS_NO = o.INHOS_NO\\n    WHERE o.OPRT_LVL_CD = \'4\'\\n      AND h.INVLD_FLG = \'0\' AND o.INVLD_FLG = \'0\'\\n      AND h.DSCG_DT_TM IS NOT NULL\\n    GROUP BY h.MDC_ORG_CD, h.INHOS_NO\\n),\\nComplication_Patients AS (\\n    SELECT d.MDC_ORG_CD, d.INHOS_NO\\n    FROM FACT_MDC_RCD_HMPG_DIAG d\\n    INNER JOIN Target_Complications tc \\n        ON d.DIAG_CD = tc.DIAG_CD\\n    WHERE d.INVLD_FLG = \'0\' \\n      AND d.INHOS_CDT_CD != \'1\'\\n    GROUP BY d.MDC_ORG_CD, d.INHOS_NO\\n)\\nSELECT \\n    COUNT(b.INHOS_NO) AS total_cnt,\\n    COUNT(c.INHOS_NO) AS comp_cnt,\\n    CASE WHEN COUNT(b.INHOS_NO) = 0 THEN 0 \\n         ELSE CAST(COUNT(c.INHOS_NO) AS DECIMAL(18,4)) / COUNT(b.INHOS_NO) \\n    END AS g4_comp_rate\\nFROM Base_Surgery_Patients b\\nLEFT JOIN Complication_Patients c \\n    ON b.MDC_ORG_CD = c.MDC_ORG_CD \\n    AND b.INHOS_NO = c.INHOS_NO\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-04-23 07:46:21', 0.129, NULL, NULL, NULL, NULL, 0, NULL, NULL);
