INSERT INTO `indicator_execution` VALUES (24, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"00:28:48\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"00:28:48\", \"level\": \"info\", \"message\": \"分子结果：0 条记录。\"}, {\"time\": \"00:28:48\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"00:28:48\", \"level\": \"info\", \"message\": \"分母结果：0 条记录。\"}, {\"time\": \"00:28:48\", \"level\": \"error\", \"message\": \"执行失败：(2003, \\\"Can\'t connect to MySQL server on \'localhost\' ([Errno 111] Connection refused)\\\")\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM\nFROM (\n    SELECT\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', '', 0, 0, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '(2003, \"Can\'t connect to MySQL server on \'localhost\' ([Errno 111] Connection refused)\")', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM\\nFROM (\\n    SELECT\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NU