 \"ODR_OPN_DT_TM\": \"2026-04-02 08:00:00\", \"ODR_STP_DT_TM\": \"2026-04-05 08:00:00\", \"ODR_EXEC_STTS_NM\": \"执行\"}, {\"inhos_no\": \"INH_20260405_049\", \"ODR_CGY_NM\": \"长期医嘱\", \"mdc_org_cd\": \"HOS_001\", \"ODR_STRT_DT\": \"2026-04-04 16:00:00\", \"ODR_OPN_DT_TM\": \"2026-04-04 16:00:00\", \"ODR_STP_DT_TM\": \"2026-04-06 16:00:00\", \"ODR_EXEC_STTS_NM\": \"执行\"}], \"columns\": [\"mdc_org_cd\", \"inhos_no\", \"ODR_CGY_NM\", \"ODR_OPN_DT_TM\", \"ODR_STRT_DT\", \"ODR_EXEC_STTS_NM\", \"ODR_STP_DT_TM\"]}', '', '', '', '[{\"sql\": \"SELECT t1.MDC_ORG_CD, t1.INHOS_NO, t1.ODR_CGY_NM, t1.ODR_OPN_DT_TM, t1.ODR_STRT_DT, t1.ODR_EXEC_STTS_NM, t1.ODR_STP_DT_TM FROM FACT_INHOS_ODR_INFMT t1 WHERE t1.ODR_CGY_NM LIKE \'%长期医嘱%\' AND t1.ODR_STP_DT_TM IS NOT NULL AND DATE(t1.ODR_OPN_DT_TM) = DATE(t1.ODR_STP_DT_TM);\", \"count\": 2, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-16 19:44:35', 0.485, '[]', NULL, NULL, 'discharge', 0, NULL, NULL);
INSERT INTO `indicator_execution` VALUES (117, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"19:57:00\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"19:57:00\", \"level\": \"info\", \"message\": \"分子结果：864 条记录。\"}, {\"time\": \"19:57:00\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"19:57:00\", \"level\": \"info\", \"message\": \"分母结果：19056 条记录。\"}, {\"time\": \"19:57:00\", \"level\": \"info\", \"message\": \"执行完成。指标值：4.534%（864/19056）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\';', '', 864, 19056, NULL, 4.534, '864/19056=4.534%', '', '{\"rows\": [{\"prm_key\": \"HMPG_20260405_14\", \"inhos_no\": \"INH_20260405_004\", \"admn_dt_tm\": \"2026-04-04 11:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\", \"ODR_ITM_TP_NM\": \"检查类医嘱\", \"ODR_OPN_DT_TM\"