INSERT INTO `indicator_execution` VALUES (165, 52, '主要手术ICD-9-CM-3四位码种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"16:39:11\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"16:39:11\", \"level\": \"info\", \"message\": \"查询结果：1 条记录。\"}, {\"time\": \"16:39:11\", \"level\": \"info\", \"message\": \"执行完成，共 1 人次。\"}]', '', '', 'WITH \nmain_surgery AS (\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\n    SELECT \n        s.INHOS_NO,\n        s.OPRT_CD,\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\n    FROM FACT_MDC_RCD_HMPG_OPRT s\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\n        AND s.OPRT_CD IS NOT NULL\n        AND s.OPRT_CD != \'\'\n)\nSELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\nFROM main_surgery ms\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\nWHERE ms.surgery_4code IS NOT NULL \n    AND ms.surgery_4code != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\nORDER BY h.MDC_ORG_CD;', NULL, NULL, NULL, NULL, '', '', '{\"rows\": [{\"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\", \"手术四位码种类数\": 16}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"手术四位码种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"WITH \\nmain_surgery AS (\\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\\n    SELECT \\n        s.INHOS_NO,\\n        s.OPRT_CD,\\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\\n    FROM FACT_MDC_RCD_HMPG_OPRT s\\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\\n        AND s.OPRT_CD IS NOT NULL\\n        AND s.OPRT_CD != \'\'\\n)\\nSELECT \\n    h.MDC_ORG_CD AS \'医疗机构代码\',\\n    h.MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\\nFROM main_surgery ms\\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\\nWHERE ms.surgery_4code IS NOT NULL \\n    AND ms.surgery_4code != \'\'\\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\\nORDER BY h.MDC_ORG_CD;\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-17 16:39:11', 0.78, '[]', NULL, NULL, 'discharge', 0, '[]', NULL);
