0\"}, {\"住院号\": \"INH_20260517_000024\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-01-24 21:33:00\", \"出院日期时间\": \"2026-01-27 01:56:00\"}, {\"住院号\": \"INH_20260517_000025\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-01 09:45:00\", \"出院日期时间\": \"2026-03-10 14:16:00\"}, {\"住院号\": \"INH_20260517_000026\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-06 10:03:00\", \"出院日期时间\": \"2026-03-21 13:56:00\"}, {\"住院号\": \"INH_20260517_000027\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-05-15 14:03:00\", \"出院日期时间\": \"2026-05-22 20:03:00\"}, {\"住院号\": \"INH_20260517_000028\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-03-09 17:34:00\", \"出院日期时间\": \"2026-03-19 11:24:00\"}, {\"住院号\": \"INH_20260517_000029\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-28 18:31:00\", \"出院日期时间\": \"2026-03-05 01:19:00\"}, {\"住院号\": \"INH_20260517_000030\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-01-20 10:16:00\", \"出院日期时间\": \"2026-01-21 05:09:00\"}, {\"住院号\": \"INH_20260517_000031\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-02-21 10:50:00\", \"出院日期时间\": \"2026-03-07 19:28:00\"}, {\"住院号\": \"INH_20260517_000032\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-11 00:34:00\", \"出院日期时间\": \"2026-04-23 01:07:00\"}, {\"住院号\": \"INH_20260517_000033\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-01-26 03:48:00\", \"出院日期时间\": \"2026-02-05 17:47:00\"}, {\"住院号\": \"INH_20260517_000034\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2025-12-08 08:02:00\", \"出院日期时间\": \"2025-12-11 15:52:00\"}, {\"住院号\": \"INH_20260517_000035\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-07 04:14:00\", \"出院日期时间\": \"2026-04-18 15:14:00\"}, {\"住院号\": \"INH_20260517_000036\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-09 12:56:00\", \"出院日期时间\": \"2026-04-12 03:03:00\"}, {\"住院号\": \"INH_20260517_000037\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-01-02 15:02:00\", \"出院日期时间\": \"2026-01-05 21:48:00\"}, {\"住院号\": \"INH_20260517_000038\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2025-12-12 00:26:00\", \"出院日期时间\": \"2025-12-16 15:42:00\"}, {\"住院号\": \"INH_20260517_000039\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-11 06:10:00\", \"出院日期时间\": \"2026-03-12 18:42:00\"}], \"columns\": [\"住院号\", \"机构代码\", \"机构名称\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    MDC_ORG_CD,    \\n    MDC_ORG_NM,    \\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM,\\n    DSCG_DT_TM\\nFROM (\\n    SELECT\\n        t1.DSCG_DT_TM,\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1;\", \"count\": 3, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-17 17:13:40', 1.345, '[]', NULL, NULL, 'discharge', 0, '[]', NULL);
INSERT INTO `indicator_execution` VALUES (172, 2, '时空轨迹异常', 'manual', 'four', 'immediate', '全量', 'ratio', 'SQL录入', '时间阈值：半小时。审核范围：住院', '[{\"time\": \"17:32:02\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"17:32:02\", \"level\": \"error\", \"message\": \"执行失败：(1146, \\\"Table \'Hainan.DWD_FACT_OTPT_PSCP_INFMT\' doesn\'t exist\\\")\"}]', '', '', '-- 规则：同一医师（身份证号）30分钟内，在不同医疗机构出现诊疗记录\nWITH \n-- 1. 基础职工信息\nstaff AS ( \n    SELECT MDC_ORG_CD,\n           STFF_CD,\n           STFF_NM,\n           ID_CRD_NO\n    FROM DWD_DIM_STFF\n    WHERE INVLD_FLG = \'0\' \n),\n\n-- 2. 门诊处方事件\noutpatient AS ( \n    SELECT PSCP_NO          AS record_id,\n           MDC_ORG_CD,\n           PSCP_OPN_DCT_CD  AS stff_cd,\n           PSCP_OPN_DT      AS event_time,\n           \'门急诊\'         AS source_type,\n           OTPT_EMG_NO      AS otpt_emg_no,\n           PSCP_TP_NM       AS pscp_tp_nm,   -- 处方类型\n           PSCP_NO          AS pscp_no,\n           NULL             AS inhos_no,     -- 住院字段置空\n           NULL             AS odr_itm_nm    -- 医嘱内容置空\n    FROM DWD_FACT_OTPT_PSCP_INFMT\n    WHERE PSCP_OPN_DT >= \'2026-04-01 00:00:00\'\n      AND PSCP_OPN_DT <  \'2026-04-10 00:00:00\'\n      -- AND INVLD_FLG = \'0\'\n      AND RTRN_DRG_FLG = \'0\'                -- 排除退药处方\n),\n\n-- 3. 住院医嘱事件\ninpatient AS ( \n    SELECT ODR_NO          AS record_id,\n           MDC_ORG_CD,\n           ODR_OPN_DCT_CD  AS stff_cd,\n           ODR_OPN_DT_TM   AS event_time,\n           \'住院\'          AS source_type,\n           NULL            AS otpt_emg_no,\n           NULL            AS pscp_tp_nm,\n           NULL            AS pscp_no,\n           INHOS_NO        AS inhos_no,     -- 住院流水号\n           ODR_ITM_NM      AS odr_itm_nm    -- 医嘱内容\n    FROM FACT_INHOS_ODR_INFMT\n    WHERE ODR_OPN_DT_TM >= \'2026-04-01 00:00:00\'\n      AND ODR_OPN_DT_TM <  \'2026-04-10 00:00:00\'\n      -- AND INVLD_FLG = \'0\'\n      -- AND (ODR_CCL_FLG IS NULL OR ODR_CCL_FLG = \'0\')\n),\n\n-- 4. 合并所有事件，并关联职工表获取姓名和身份证号\nall_events AS ( \n    SELECT e.record_id,\n           e.MDC_ORG_CD,\n           e.stff_cd, \n           s.STFF_NM,\n           s.ID_CRD_NO,\n           e.event_time,\n           e.source_type,\n           e.otpt_emg_no,\n           e.pscp_tp_nm,\n           e.pscp_no,\n           e.inhos_no,\n           e.odr_itm_nm\n    FROM ( \n        SELECT * FROM outpatient\n        UNION ALL\n        SELECT * FROM inpatient \n    ) e\n    INNER JOIN staff s \n        ON e.MDC_ORG_CD = s.MDC_ORG_CD\n       AND e.stff_cd   = s.STFF_CD\n),\n\n-- 5. 主执业机构（备案表 t_docter）\nmain_practice AS ( \n    SELECT DOCTOR_IDCARD,\n           DOCTOR_UNITNAME AS main_org_name\n    FROM t_docter \n),\n\n-- 6. 事件关联主执业机构\nevents_with_practice AS ( \n    SELECT ae.*,\n           COALESCE(mp.main_org_name, \'/\') AS main_org_name\n    FROM all_events ae\n    LEFT JOIN main_practice mp \n        ON ae.ID_CRD_NO = mp.DOCTOR_IDCARD \n),\n\n-- 7. 使用窗口函数获取每个医生的上一条记录\nevents_with_prev AS ( \n    SELECT *,\n           LAG(MDC_ORG_CD)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_mdc_org_cd,\n           LAG(event_time)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_event_time,\n           LAG(stff_cd)     OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_stff_cd,    -- 上次开单医师工号\n           LAG(source_type) OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_source_type,\n           LAG(otpt_emg_no) OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_otpt_emg_no,\n           LAG(pscp_tp_nm)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_pscp_tp_nm, -- 上次处方分类类型\n           LAG(pscp_no)     OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_pscp_no\n    FROM events_with_practice \n)\n\n-- 8. 最终筛选违规记录，关联机构名称，输出目标字段\nSELECT e.ID_CRD_NO          AS 开单医师身份证号码,\n       e.STFF_NM            AS 开单医师姓名,\n       e.main_org_name      AS 主执业机构,\n       o1.MDC_ORG_NM        AS 本次开单机构名称,\n       e.stff_cd            AS 本次开单医师工号,\n       e.event_time         AS 本次开单时间,\n       e.source_type        AS 本次诊疗环节,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.otpt_emg_no  ELSE NULL END AS 本次门急诊编号,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.pscp_tp_nm   ELSE NULL END AS 本次处方分类类型,\n       CASE WHEN e.source_type = \'门急诊\' THEN e.pscp_no      ELSE NULL END AS 本次处方编号,\n       o2.MDC_ORG_NM        AS 上次开单机构名称,\n       e.prev_event_time    AS 上次开单时间,\n       e.prev_stff_cd       AS 上次开单医师工号,\n       e.prev_source_type   AS 上次诊疗环节,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_otpt_emg_no ELSE NULL END AS 上次门急诊编号,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_pscp_no     ELSE NULL END AS 上次处方编号,\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_pscp_tp_nm  ELSE NULL END AS 上次处方分类类型,\n       TIMESTAMPDIFF(MINUTE, e.prev_event_time, e.event_time) AS 两次时间差分钟\nFROM events_with_prev e\nLEFT JOIN DIM_MDC_ORG o1 ON e.MDC_ORG_CD      = o1.MDC_ORG_CD\nLEFT JOIN DIM_MDC_ORG o2 ON e.prev_mdc_org_cd = o2.MDC_ORG_CD\nWHERE e.event_time >= \'2026-04-07 00:00:00\'\n  AND e.event_time <  \'2026-04-10 00:00:00\'\n  AND e.prev_event_time IS NOT NULL\n  AND e.MDC_ORG_CD <> e.prev_mdc_org_cd\n  AND TIMESTAMPDIFF(MINUTE, e.prev_event_time, e.event_time) <= 30\nORDER BY e.ID_CRD_NO, e.event_time;', NULL, NULL, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '(1146, \"Table \'Hainan.DWD_FACT_OTPT_PSCP_INFMT\' doesn\'t exist\")', '', '', '[{\"sql\": \"-- 规则：同一医师（身份证号）30分钟内，在不同医疗机构出现诊疗记录\\nWITH \\n-- 1. 基础职工信息\\nstaff AS ( \\n    SELECT MDC_ORG_CD,\\n           STFF_CD,\\n           STFF_NM,\\n           ID_CRD_NO\\n    FROM DWD_DIM_STFF\\n    WHERE INVLD_FLG = \'0\' \\n),\\n\\n-- 2. 门诊处方事件\\noutpatient AS ( \\n    SELECT PSCP_NO          AS record_id,\\n           MDC_ORG_CD,\\n           PSCP_OPN_DCT_CD  AS stff_cd,\\n           PSCP_OPN_DT      AS event_time,\\n           \'门急诊\'         AS source_type,\\n           OTPT_EMG_NO      AS otpt_emg_no,\\n           PSCP_TP_NM       AS pscp_tp_nm,   -- 处方类型\\n           PSCP_NO          AS pscp_no,\\n           NULL             AS inhos_no,     -- 住院字段置空\\n           NULL             AS odr_itm_nm    -- 医嘱内容置空\\n    FROM DWD_FACT_OTPT_PSCP_INFMT\\n    WHERE PSCP_OPN_DT >= \'2026-04-01 00:00:00\'\\n      AND PSCP_OPN_DT <  \'2026-04-10 00:00:00\'\\n      -- AND INVLD_FLG = \'0\'\\n      AND RTRN_DRG_FLG = \'0\'                -- 排除退药处方\\n),\\n\\n-- 3. 住院医嘱事件\\ninpatient AS ( \\n    SELECT ODR_NO          AS record_id,\\n           MDC_ORG_CD,\\n           ODR_OPN_DCT_CD  AS stff_cd,\\n           ODR_OPN_DT_TM   AS event_time,\\n           \'住院\'          AS source_type,\\n           NULL            AS otpt_emg_no,\\n           NULL            AS pscp_tp_nm,\\n           NULL            AS pscp_no,\\n           INHOS_NO        AS inhos_no,     -- 住院流水号\\n           ODR_ITM_NM      AS odr_itm_nm    -- 医嘱内容\\n    FROM FACT_INHOS_ODR_INFMT\\n    WHERE ODR_OPN_DT_TM >= \'2026-04-01 00:00:00\'\\n      AND ODR_OPN_DT_TM <  \'2026-04-10 00:00:00\'\\n      -- AND INVLD_FLG = \'0\'\\n      -- AND (ODR_CCL_FLG IS NULL OR ODR_CCL_FLG = \'0\')\\n),\\n\\n-- 4. 合并所有事件，并关联职工表获取姓名和身份证号\\nall_events AS ( \\n    SELECT e.record_id,\\n           e.MDC_ORG_CD,\\n           e.stff_cd, \\n           s.STFF_NM,\\n           s.ID_CRD_NO,\\n           e.event_time,\\n           e.source_type,\\n           e.otpt_emg_no,\\n           e.pscp_tp_nm,\\n           e.pscp_no,\\n           e.inhos_no,\\n           e.odr_itm_nm\\n    FROM ( \\n        SELECT * FROM outpatient\\n        UNION ALL\\n        SELECT * FROM inpatient \\n    ) e\\n    INNER JOIN staff s \\n        ON e.MDC_ORG_CD = s.MDC_ORG_CD\\n       AND e.stff_cd   = s.STFF_CD\\n),\\n\\n-- 5. 主执业机构（备案表 t_docter）\\nmain_practice AS ( \\n    SELECT DOCTOR_IDCARD,\\n           DOCTOR_UNITNAME AS main_org_name\\n    FROM t_docter \\n),\\n\\n-- 6. 事件关联主执业机构\\nevents_with_practice AS ( \\n    SELECT ae.*,\\n           COALESCE(mp.main_org_name, \'/\') AS main_org_name\\n    FROM all_events ae\\n    LEFT JOIN main_practice mp \\n        ON ae.ID_CRD_NO = mp.DOCTOR_IDCARD \\n),\\n\\n-- 7. 使用窗口函数获取每个医生的上一条记录\\nevents_with_prev AS ( \\n    SELECT *,\\n           LAG(MDC_ORG_CD)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_mdc_org_cd,\\n           LAG(event_time)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_event_time,\\n           LAG(stff_cd)     OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_stff_cd,    -- 上次开单医师工号\\n           LAG(source_type) OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_source_type,\\n           LAG(otpt_emg_no) OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_otpt_emg_no,\\n           LAG(pscp_tp_nm)  OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_pscp_tp_nm, -- 上次处方分类类型\\n           LAG(pscp_no)     OVER (PARTITION BY ID_CRD_NO ORDER BY event_time, record_id) AS prev_pscp_no\\n    FROM events_with_practice \\n)\\n\\n-- 8. 最终筛选违规记录，关联机构名称，输出目标字段\\nSELECT e.ID_CRD_NO          AS 开单医师身份证号码,\\n       e.STFF_NM            AS 开单医师姓名,\\n       e.main_org_name      AS 主执业机构,\\n       o1.MDC_ORG_NM        AS 本次开单机构名称,\\n       e.stff_cd            AS 本次开单医师工号,\\n       e.event_time         AS 本次开单时间,\\n       e.source_type        AS 本次诊疗环节,\\n       CASE WHEN e.source_type = \'门急诊\' THEN e.otpt_emg_no  ELSE NULL END AS 本次门急诊编号,\\n       CASE WHEN e.source_type = \'门急诊\' THEN e.pscp_tp_nm   ELSE NULL END AS 本次处方分类类型,\\n       CASE WHEN e.source_type = \'门急诊\' THEN e.pscp_no      ELSE NULL END AS 本次处方编号,\\n       o2.MDC_ORG_NM        AS 上次开单机构名称,\\n       e.prev_event_time    AS 上次开单时间,\\n       e.prev_stff_cd       AS 上次开单医师工号,\\n       e.prev_source_type   AS 上次诊疗环节,\\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_otpt_emg_no ELSE NULL END AS 上次门急诊编号,\\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_pscp_no     ELSE NULL END AS 上次处方编号,\\n       CASE WHEN e.prev_source_type = \'门急诊\' THEN e.prev_pscp_tp_nm  ELSE NULL END AS 上次处方分类类型,\\n       TIMESTAMPDIFF(MINUTE, e.prev_event_time, e.event_time) AS 两次时间差分钟\\nFROM events_with_prev e\\nLEFT JOIN DIM_MDC_ORG o1 ON e.MDC_ORG_CD      = o1.MDC_ORG_CD\\nLEFT JOIN DIM_MDC_ORG o2 ON e.prev_mdc_org_cd = o2.MDC_ORG_CD\\nWHERE e.event_time >= \'2026-04-07 00:00:00\'\\n  AND e.event_time <  \'2026-04-10 00:00:00\'\\n  AND e.prev_event_time IS NOT NULL\\n  AND e.MDC_ORG_CD <> e.prev_mdc_org_cd\\n  AND TIMESTAMPDIFF(MINUTE, e.prev_event_time, e.event_time) <= 30\\nORDER BY e.ID_CRD_NO, e.event_time;\", \"count\": null, \"error\": \"(1146, \\\"Table \'Hainan.DWD_FACT_OTPT_PSCP_INFMT\' doesn\'t exist\\\")\", \"attempt\": 1}]', '', '', 0, '', '', 'failed', '2026-05-17 17:32:03', 3.64, '[]', NULL, NULL, 'discharge', 0, '[]', NULL);
INSERT INTO `indicator_execution` VALUES (173, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'immediate', '全量', 'ratio', 'SQL录入', '', '[{\"time\": \"23:32:54\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"23:32:55\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：0 条\"}, {\"time\": \"23:32:55\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：4963 条\"}, {\"time\": \"23:32:55\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 指标值：0.0%\"}, {\"time\": \"23:32:55\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"23:32:56\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：3 条\"}, {\"time\": \"23:32:56\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：5047 条\"}, {\"time\": \"23:32:56\", \"level\": \"info\", \"message\": \"[海南省示范医院] 指标值：0.0594%\"}, {\"time\": \"23:32:56\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：0.03%（3/10010）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT