INSERT INTO `indicator_execution` VALUES (201, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"14:51:28\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"14:51:28\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分子：0 条\"}, {\"time\": \"14:51:28\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 分母：None 条\"}, {\"time\": \"14:51:28\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"14:51:28\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分子：2 条\"}, {\"time\": \"14:51:28\", \"level\": \"info\", \"message\": \"[海南省示范医院] 分母：None 条\"}, {\"time\": \"14:51:28\", \"level\": \"info\", \"message\": \"汇总执行完成。总体指标值：None%（2/0）\"}]', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', '', '', 2, 0, NULL, NULL, '', '', '{\"rows\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}', '{\"rows\": [], \"columns\": []}', '部分医院执行失败', '', '', '[]', '', '', 0, '', '', 'failed', '2026-05-18 14:51:29', 0.467, '[\"HOS_002\", \"HOS_001\"]', NULL, NULL, 'discharge', 1, '[{\"error\": null, \"status\": \"failed\", \"preview_data\": [], \"hospital_code\": \"HOS_002\", \"hospital_name\": \"三亚市人民医院\", \"ratio_percent\": null, \"numerator_count