INSERT INTO `indicator_execution` VALUES (206, 52, '主要手术ICD-9-CM-3四位码种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"15:17:33\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"15:17:33\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 查询结果：None 条记录。\"}, {\"time\": \"15:17:33\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 执行完成，共 None 人次。\"}, {\"time\": \"15:17:33\", \"level\": \"error\", \"message\": \"[三亚市人民医院] 执行出错：(1054, \\\"Unknown column \'s.mdc_org_cd\' in \'where clause\'\\\")\"}, {\"time\": \"15:17:33\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"15:17:33\", \"level\": \"info\", \"message\": \"[海南省示范医院] 查询结果：None 条记录。\"}, {\"time\": \"15:17:33\", \"level\": \"info\", \"message\": \"[海南省示范医院] 执行完成，共 None 人次。\"}, {\"time\": \"15:17:33\", \"level\": \"error\", \"message\": \"[海南省示范医院] 执行出错：(1054, \\\"Unknown column \'s.mdc_org_cd\' in \'where clause\'\\\")\"}, {\"time\": \"15:17:33\", \"level\": \"info\", \"message\": \"汇总执行完成，共 0 人次。\"}]', '', '', 'WITH \nmain_surgery AS (\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\n    SELECT \n        s.INHOS_NO,\n        s.OPRT_CD,\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\n    FROM FACT_MDC_RCD_HMPG_OPRT s\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\n        AND s.OPRT_CD IS NOT NULL\n        AND s.OPRT_CD != \'\'\n)\nSELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\nFROM main_surgery ms\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\nWHERE ms.surgery_4code IS NOT NULL \n    AND ms.surgery_4code != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\nORDER BY h.MDC_ORG_CD;', 0, NULL, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '部分医院执行失败', '', '', '[]', '', '', 0, '', '', 'failed', '2026-05-18 15:17:33', 0.308, '[\"HOS_002\", \"HOS_001\"]', NULL, NULL, 'discharge', 1, '[{\"count\": null, \"error\": \"(1054, \\\"Unknown column \'s.mdc_org_cd\' in \'where clause\'\\\")\", \"status\": \"failed\", \"preview_data\": [], \"hospital_code\": \"HOS_002\", \"hospital_name\": \"三亚市人民医院\", \"numerator_count\": null, \"preview_columns\": []}, {\"count\": null, \"error\": \"(1054, \\\"Unknown column \'s.mdc_org_cd\' in \'where clause\'\\\")\", \"status\": \"failed\", \"preview_data\": [], \"hospital_code\": \"HOS_001\", \"hospital_name\": \"海南省示范医院\", \"numerator_count\": null, \"preview_columns\": []}]', NULL);
INSERT INTO `indicator_execution` VALUES (207, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"15:17:37\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"15:17:37\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 查询结果：0 条记录。\"}, {\"time\": \"15:17:37\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 执行完成，共 0 人次。\"}, {\"time\": \"15:17:37\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"15:17:38\", \"level\": \"info\", \"message\": \"[海南省示范医院] 查询结果：2 条记录。\"}, {\"time\": \"15:17:38\", \"level\": \"info\", \"message\": \"[海南省示范医院] 执行完成，共 2 人次。\"}, {\"time\": \"15:17:38\", \"level\": \"info\", \"message\": \"汇总执行完成，共 2 人次。\"}]', '', '', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', 2, NULL, NULL, NULL, '', '', '{\"rows\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[]', '', '', 0, '', '', 'success', '2026-05-18 15:17:38', 0.461, '[\"HOS_002\", \"HOS_001\"]', NULL, NULL, 'discharge', 1, '[{\"count\": 0, \"error\": null, \"status\": \"success\", \"preview_data\": [], \"hospital_code\": \"HOS_002\", \"hospital_name\": \"三亚市人民医院\", \"numerator_count\": 0, \"preview_columns\": []}, {\"count\": 2, \"error\": null, \"status\": \"success\", \"preview_data\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"hospital_code\": \"HOS_001\", \"hospital_name\": \"海南省示范医院\", \"numerator_count\": 2, \"preview_columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}]', NULL);
INSERT INTO `indicator_execution` VALUES (208, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"15:29:31\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"15:29:31\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 查询结果：0 条记录。\"}, {\"time\": \"15:29:31\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 执行完成，共 0 人次。\"}, {\"time\": \"15:29:31\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"15:29:31\", \"level\": \"info\", \"message\": \"[海南省示范医院] 查询结果：2 条记录。\"}, {\"time\": \"15:29:31\", \"level\": \"info\", \"message\": \"[海南省示范医院] 执行完成，共 2 人次。\"}, {\"time\": \"15:29:31\", \"level\": \"info\", \"message\": \"汇总执行完成，共 2 人次。\"}]', '', '', 'WITH \n-- 提取主要诊断并计算亚目键（取诊断代码去掉符号后的前4位）\nmain_diag_sub AS (\n    SELECT \n        MDC_ORG_CD,\n        MDC_ORG_NM,\n        -- 去除诊断代码中的非字母数字字符（如点、横线等），然后取前4位作为亚目\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS sub_category\n    FROM FACT_MDC_RCD_HMPG_DIAG\n    WHERE MAIN_DIAG_FLG = \'1\'   -- 主诊断标识\n        AND DIAG_CD IS NOT NULL\n        AND DIAG_CD != \'\'\n)\n-- 按医疗机构分组，统计不同亚目数量\nSELECT \n    MDC_ORG_CD AS \'医疗机构代码\',\n    MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT sub_category) AS \'亚目种类数\'\nFROM main_diag_sub\nWHERE sub_category IS NOT NULL \n    AND sub_category != \'\'\nGROUP BY MDC_ORG_CD, MDC_ORG_NM\nORDER BY MDC_ORG_CD;', 2, NULL, NULL, NULL, '', '', '{\"rows\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[]', '', '', 0, '', '', 'success', '2026-05-18 15:29:31', 0.491, '[\"HOS_002\", \"HOS_001\"]', NULL, NULL, 'discharge', 1, '[{\"count\": 0, \"error\": null, \"status\": \"success\", \"preview_data\": [], \"hospital_code\": \"HOS_002\", \"hospital_name\": \"三亚市人民医院\", \"numerator_count\": 0, \"preview_columns\": []}, {\"count\": 2, \"error\": null, \"status\": \"success\", \"preview_data\": [{\"亚目种类数\": 10, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": null}, {\"亚目种类数\": 8, \"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\"}], \"hospital_code\": \"HOS_001\", \"hospital_name\": \"海南省示范医院\", \"numerator_count\": 2, \"preview_columns\": [\"医疗机构代码\", \"医疗机构名称\", \"亚目种类数\"]}]', NULL);
INSERT INTO `indicator_execution` VALUES (209, 10, '未成年人高危预警', 'manual', 'four', 'immediate', '全量', 'count', 'SQL录入', '审核范围：未成年人', '[{\"time\": \"15:29:41\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"15:29:42\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 查询结果：5 条记录。\"}, {\"time\": \"15:29:42\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 执行完成，共 5 人次。\"}, {\"time\": \"15:29:42\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"15:29:42\", \"level\": \"info\", \"message\": \"[海南省示范医院] 查询结果：5 条记录。\"}, {\"time\": \"15:29:42\", \"level\": \"info\", \"message\": \"[海南省示范医院] 执行完成，共 5 人次。\"}, {\"time\": \"15:29:42\", \"level\": \"info\", \"message\": \"汇总执行完成，共 10 人次。\"}]', '', '', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        -- 时间限制（用的月份）\n        AND SUBSTR(v.VST_DT_TM, 1, 7) = \'2026-04\' \n        /* \n        也可以用“日”来筛选\n        AND v.VST_DT_TM >= \'2026-04-01 00:00:00\'\n        AND v.VST_DT_TM <  \'2026-05-01 00:00:00\'\n        */\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\'\n        OR d.DIAG_ICD10_CD LIKE \'B37.3%\'\n        OR d.DIAG_ICD10_CD LIKE \'N76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;', 10, NULL, NULL, NULL, '', '', '{\"rows\": [{\"年龄\": 16, \"出生日期\": \"2009-08-15 00:00:00\", \"就诊时间\": \"2026-04-02 14:15:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z30.0\", \"诊断名称\": \"一般避孕咨询\", \"挂号流水号\": \"RG_RISK_002\", \"门急诊编号\": \"MZ20260402002\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 16, \"出生日期\": \"2010-03-10 00:00:00\", \"就诊时间\": \"2026-04-05 16:40:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_004\", \"门急诊编号\": \"MZ20260405004\", \"就诊科室名称\": \"呼吸内科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 17, \"出生日期\": \"2008-12-01 00:00:00\", \"就诊时间\": \"2026-04-10 11:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A51.9\", \"诊断名称\": \"早期梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_006\", \"门急诊编号\": \"MZ20260410006\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 14, \"出生日期\": \"2011-06-30 00:00:00\", \"就诊时间\": \"2026-04-15 23:10:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_008\", \"门急诊编号\": \"MZ20260415008\", \"就诊科室名称\": \"急诊科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 13, \"出生日期\": \"2013-01-25 00:00:00\", \"就诊时间\": \"2026-04-20 13:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ult