日期时间\": \"2026-04-12 03:03:00\"}, {\"住院号\": \"INH_20260517_000037\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-01-02 15:02:00\", \"出院日期时间\": \"2026-01-05 21:48:00\"}, {\"住院号\": \"INH_20260517_000038\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2025-12-12 00:26:00\", \"出院日期时间\": \"2025-12-16 15:42:00\"}, {\"住院号\": \"INH_20260517_000039\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-11 06:10:00\", \"出院日期时间\": \"2026-03-12 18:42:00\"}], \"columns\": [\"住院号\", \"机构代码\", \"机构名称\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    MDC_ORG_CD,    \\n    MDC_ORG_NM,    \\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM,\\n    DSCG_DT_TM\\nFROM (\\n    SELECT\\n        t1.DSCG_DT_TM,\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1;\", \"count\": 3, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-18 17:16:12', 0.787, '[]', NULL, NULL, 'discharge', 0, '[]', NULL);
INSERT INTO `indicator_execution` VALUES (221, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'monthly', '2026年4月', 'ratio', 'SQL录入', '', '[{\"time\": \"17:16:51\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"17:16:51\", \"level\": \"info\", \"message\": \"分子结果：3 条记录。\"}, {\"time\": \"17:16:51\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"17:16:51\", \"level\": \"info\", \"message\": \"分母结果：1667 条记录。\"}, {\"time\": \"17:16:51\", \"level\": \"info\", \"message\": \"执行完成。指标值：0.18%（3/1667）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\' AND DATE(dscg_dt_tm) BETWEEN \'2026-04-01\' AND \'2026-04-30\'', '', 3, 1667, NULL, 0.18, '3/1667=0.18%', '', '{\"rows\": [{\"prm_key\": \"HMPG_20260405_04\", \"inhos_no\": \"INH_20260405_004\", \"admn_dt_tm\": \"2026-04-04 11:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\