INSERT INTO `indicator_execution` VALUES (234, 10, '未成年人高危预警', 'manual', 'four', 'monthly', '2026年4月', 'count', 'SQL录入', '审核范围：未成年人', '[{\"time\": \"13:17:42\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"13:17:43\", \"level\": \"info\", \"message\": \"[海南省示范医院] 查询结果：None 条记录。\"}, {\"time\": \"13:17:43\", \"level\": \"info\", \"message\": \"[海南省示范医院] 执行完成，共 None 人次。\"}, {\"time\": \"13:17:43\", \"level\": \"error\", \"message\": \"[海南省示范医院] 执行出错：(1054, \\\"Unknown column \'dscg_dt_tm\' in \'where clause\'\\\")\"}, {\"time\": \"13:17:43\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"13:17:43\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 查询结果：None 条记录。\"}, {\"time\": \"13:17:43\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 执行完成，共 None 人次。\"}, {\"time\": \"13:17:43\", \"level\": \"error\", \"message\": \"[三亚市人民医院] 执行出错：(1054, \\\"Unknown column \'dscg_dt_tm\' in \'where clause\'\\\")\"}, {\"time\": \"13:17:43\", \"level\": \"info\", \"message\": \"汇总执行完成，共 0 人次。\"}]', '', '', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        -- 时间限制（用的月份）\n        AND SUBSTR(v.VST_DT_TM, 1, 7) = \'2026-04\' \n        /* \n        也可以用“日”来筛选\n        AND v.VST_DT_TM >= \'2026-04-01 00:00:00\'\n        AND v.VST_DT_TM <  \'2026-05-01 00:00:00