76.5%\'\n        OR d.DIAG_ICD10_CD LIKE \'N39.0%\'\n        OR d.DIAG_ICD10_CD LIKE \'N72%\'\n        OR d.DIAG_ICD10_CD LIKE \'004%\'\n        OR d.DIAG_ICD10_CD LIKE \'005%\'\n        OR d.DIAG_ICD10_CD LIKE \'003%\'\n        OR d.DIAG_ICD10_CD LIKE \'008%\'\n        OR d.DIAG_ICD10_CD LIKE \'000%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z32%\'\n        OR d.DIAG_ICD10_CD LIKE \'Z30%\' ) \n        -- 年龄筛选\n        /*\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 14\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) >= 14\n        */\n        AND TIMESTAMPDIFF(YEAR, v.BTH_DT, v.VST_DT_TM) < 18;', 10, NULL, NULL, NULL, '', '', '{\"rows\": [{\"年龄\": 16, \"出生日期\": \"2009-08-15 00:00:00\", \"就诊时间\": \"2026-04-02 14:15:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z30.0\", \"诊断名称\": \"一般避孕咨询\", \"挂号流水号\": \"RG_RISK_002\", \"门急诊编号\": \"MZ20260402002\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 16, \"出生日期\": \"2010-03-10 00:00:00\", \"就诊时间\": \"2026-04-05 16:40:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_004\", \"门急诊编号\": \"MZ20260405004\", \"就诊科室名称\": \"呼吸内科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 17, \"出生日期\": \"2008-12-01 00:00:00\", \"就诊时间\": \"2026-04-10 11:00:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A51.9\", \"诊断名称\": \"早期梅毒, 未特指\", \"挂号流水号\": \"RG_RISK_006\", \"门急诊编号\": \"MZ20260410006\", \"就诊科室名称\": \"妇产科\", \"患者去向名称\": \"回家\"}, {\"年龄\": 14, \"出生日期\": \"2011-06-30 00:00:00\", \"就诊时间\": \"2026-04-15 23:10:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"A60.0\", \"诊断名称\": \"泌尿生殖系疱疹病毒感染\", \"挂号流水号\": \"RG_RISK_008\", \"门急诊编号\": \"MZ20260415008\", \"就诊科室名称\": \"急诊科\", \"患者去向名称\": \"住院\"}, {\"年龄\": 13, \"出生日期\": \"2013-01-25 00:00:00\", \"就诊时间\": \"2026-04-20 13:30:00\", \"年龄单位\": \"岁\", \"性别名称\": \"女\", \"机构名称\": \"三亚市人民医院\", \"诊断代码\": \"Z32.01\", \"诊断名称\": \"妊娠confirmed by ult