INSERT INTO `indicator_execution` VALUES (245, 10, '未成年人高危预警', 'manual', 'four', 'monthly', '2026年4月', 'count', 'SQL录入', '审核范围：未成年人', '[{\"time\": \"13:39:52\", \"level\": \"info\", \"message\": \"[海南省示范医院] 开始执行...\"}, {\"time\": \"13:39:52\", \"level\": \"info\", \"message\": \"[海南省示范医院] 查询结果：None 条记录。\"}, {\"time\": \"13:39:52\", \"level\": \"info\", \"message\": \"[海南省示范医院] 执行完成，共 None 人次。\"}, {\"time\": \"13:39:52\", \"level\": \"error\", \"message\": \"[海南省示范医院] 执行出错：(1054, \\\"Unknown column \'dscg_dt_tm\' in \'where clause\'\\\")\"}, {\"time\": \"13:39:52\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 开始执行...\"}, {\"time\": \"13:39:52\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 查询结果：None 条记录。\"}, {\"time\": \"13:39:52\", \"level\": \"info\", \"message\": \"[三亚市人民医院] 执行完成，共 None 人次。\"}, {\"time\": \"13:39:52\", \"level\": \"error\", \"message\": \"[三亚市人民医院] 执行出错：(1054, \\\"Unknown column \'dscg_dt_tm\' in \'where clause\'\\\")\"}, {\"time\": \"13:39:52\", \"level\": \"info\", \"message\": \"汇总执行完成，共 0 人次。\"}]', '', '', 'SELECT v.MDC_ORG_NM AS 机构名称,\n         v.OTPT_EMG_NO AS 门急诊编号,\n         v.RGST_NO AS 挂号流水号,\n         TIMESTAMPDIFF(YEAR,v.BTH_DT,v.VST_DT_TM) AS 年龄,\n         \'岁\' AS 年龄单位,\n         v.VST_DT_TM AS 就诊时间,\n         v.VST_DPT_NM AS 就诊科室名称,\n         v.GDR_NM AS 性别名称,\n         v.BTH_DT AS 出生日期,\n         d.DIAG_ICD10_CD AS 诊断代码,\n         d.DIAG_ICD10_NM AS 诊断名称,\n         v.PTT_WHRABT_NM AS 患者去向名称\nFROM FACT_OTPT_VST_INFMT v\nJOIN FACT_OTPT_DIAG_INFMT d\n    ON v.MDC_ORG_NM = d.MDC_ORG_NM\n        AND v.OTPT_EMG_NO = d.OTPT_EMG_NO\nWHERE (v.INVLD_FLG IS NULL\n        OR v.INVLD_FLG != \'1\')\n        AND (d.INVLD_FLG IS NULL\n        OR d.INVLD_FLG != \'1\')\n        AND v.BTH_DT IS NOT NULL\n        AND v.VST_DT_TM IS NOT NULL\n        AND ( d.DIAG_ICD10_CD LIKE \'A50%\'\n        OR d.DIAG_ICD10_CD LIKE \'A51%\'\n        OR d.DIAG_ICD10_CD LIKE \'A52%\'\n        OR d.DIAG_ICD10_CD LIKE \'A53%\'\n        OR d.DIAG_ICD10_CD LIKE \'A60%\