构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-03-27 08:57:00\", \"出院日期时间\": \"2026-04-07 16:18:00\"}, {\"住院号\": \"INH_20260517_000211\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-24 02:06:00\", \"出院日期时间\": \"2026-04-28 19:17:00\"}, {\"住院号\": \"INH_20260517_000215\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-16 21:52:00\", \"出院日期时间\": \"2026-04-28 04:42:00\"}, {\"住院号\": \"INH_20260517_000230\", \"机构代码\": \"HOS_002\", \"机构名称\": \"三亚市人民医院\", \"入院日期时间\": \"2026-04-08 12:54:00\", \"出院日期时间\": \"2026-04-09 07:32:00\"}], \"columns\": [\"住院号\", \"机构代码\", \"机构名称\", \"入院日期时间\", \"出院日期时间\"]}', '', '', '', '[{\"sql\": \"SELECT \\n    PRM_KEY,\\n    INHOS_NO,\\n    MDC_ORG_CD,    \\n    MDC_ORG_NM,    \\n    ADMN_DT_TM,\\n    ODR_OPN_DT_TM,\\n    ODR_ITM_TP_NM,\\n    DSCG_DT_TM\\nFROM (\\n    SELECT\\n        t1.DSCG_DT_TM,\\n        t1.PRM_KEY,\\n        t1.INHOS_NO,\\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\\n        t1.ADMN_DT_TM,\\n        t2.ODR_OPN_DT_TM,\\n        t2.ODR_ITM_TP_NM,\\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\\n        ON t2.INVLD_FLG = \'0\'\\n        AND t2.INHOS_NO = t1.INHOS_NO\\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \\n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\\n    WHERE t1.INVLD_FLG = \'0\'\\n) temp\\nWHERE rn = 1;\", \"count\": 3, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-25 21:56:18', 0.676, '[]', 'monthly', '2026-04', 'discharge', 0, '[]', NULL);
INSERT INTO `indicator_execution` VALUES (274, 54, '住院患者死亡疾病谱', 'manual', 'core18', 'monthly', '2026年1月', 'count', 'SQL录入', '', '[{\"time\": \"22:53:12\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"22:53:12\", \"level\": \"error\", \"message\": \"执行失败：(1064, \\\"You have an error in your SQL syntax; check the manual that corresponds to your MySQL server version for the right syntax to use near \'death_type IS NOT NULL\\\\nGROUP BY mdc_org_cd, DIAG_SUBCAT_CD, death_type\\\\nORDER BY \' at line 26\\\")\"}]', '', '', 'SELECT \n    MDC_ORG_CD,\n    DIAG_SUBCAT_CD,\n    death_type,\n    COUNT(DISTINCT INHOS_NO) AS DEATH_PATIENT_CNT\nFROM (\n    SELECT \n        t1.MDC_ORG_CD,\n        t1.INHOS_NO,\n        REGEXP_REPLACE(SUBSTRING(t2.DIAG_CD, 1, 4), \'[^A-Z0-9]\', \'\') AS DIAG_SUBCAT_CD,\n        CASE\n            WHEN t1.DSCG_WAY_NM LIKE \'%死亡%\' THEN \'离院方式死亡\'\n            WHEN t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM = \'非医嘱离院\' THEN \'转归情况死亡\'\n            ELSE NULL\n        END AS death_type\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n        ON t1.INHOS_NO = t2.INHOS_NO\n        AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n    WHERE t2.MAIN_DIAG_FLG = \'1\'\n        AND (t1.DSCG_WAY_NM LIKE \'%死亡%\'\n             OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM = \'非医嘱离院\'))\n        -- ↑ 这里留空，后端会自动追加 AND MDC_ORG_CD IN (...) AND DATE(dscg_dt_tm) BETWEEN ...\n) t\nWHERE death_type IS NOT NULL\n AND DATE(dscg_dt_tm) BETWEEN \'2026-01-01\' AND \'2026-01-31\' death_type IS NOT NULL\nGROUP BY MDC_ORG_CD, DIAG_SUBCAT_CD, death_type\nORDER BY MDC_ORG_CD, DIAG_SUBCAT_CD, death_type', NULL, NULL, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '(1064, \"You have an error in your SQL syntax; check the manual that corresponds to your MySQL server version for the right syntax to use near \'death_type IS NOT NULL\\nGROUP BY mdc_org_cd, DIAG_SUBCAT_CD, death_type\\nORDER BY \' at line 26\")', '', '', '[{\"sql\": \"SELECT \\n    MDC_ORG_CD,\\n    DIAG_SUBCAT_CD,\\n    death_type,\\n    COUNT(DISTINCT INHOS_NO) AS DEATH_PATIENT_CNT\\nFROM (\\n    SELECT \\n        t1.MDC_ORG_CD,\\n        t1.INHOS_NO,\\n        REGEXP_REPLACE(SUBSTRING(t2.DIAG_CD, 1, 4), \'[^A-Z0-9]\', \'\') AS DIAG_SUBCAT_CD,\\n        CASE\\n            WHEN t1.DSCG_WAY_NM LIKE \'%死亡%\' THEN \'离院方式死亡\'\\n            WHEN t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM = \'非医嘱离院\' THEN \'转归情况死亡\'\\n            ELSE NULL\\n        END AS death_type\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\\n        ON t1.INHOS_NO = t2.INHOS_NO\\n        AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\\n    WHERE t2.MAIN_DIAG_FLG = \'1\'\\n        AND (t1.DSCG_WAY_NM LIKE \'%死亡%\'\\n             OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM = \'非医嘱离院\'))\\n        -- ↑ 这里留空，后端会自动追加 AND MDC_ORG_CD IN (...) AND DATE(dscg_dt_tm) BETWEEN ...\\n) t\\nWHERE death_type IS NOT NULL\\n AND DATE(dscg_dt_tm) BETWEEN \'2026-01-01\' AND \'2026-01-31\' death_type IS NOT NULL\\nGROUP BY MDC_ORG_CD, DIAG_SUBCAT_CD, death_type\\nORDER BY MDC_ORG_CD, DIAG_SUBCAT_CD, death_type\", \"count\": null, \"error\": \"(1064, \\\"You have an error in your SQL syntax; check the manual that corresponds to your MySQL server version for the right syntax to use near \'death_type IS NOT NULL\\\\nGROUP BY mdc_org_cd, DIAG_SUBCAT_CD, death_type\\\\nORDER BY \' at line 26\\\")\", \"attempt\": 1}]', '', '', 0, '', '', 'failed', '2026-05-25 22:53:13', 0.189, '[]', 'monthly', '2026-01', 'discharge', 0, '[]', NULL);
INSERT INTO `indicator_execution` VALUES (275, 54, '住院患者死亡疾病谱', 'manual', 'core18', 'immediate', '全量', 'count', 'SQL录入', '', '[{\"time\": \"22:54:05\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"22:54:05\", \"level\": \"info\", \"message\": \"查询结果：0 条记录。\"}, {\"time\": \"22:54:05\", \"level\": \"info\", \"message\": \"执行完成，共 0 人次。\"}]', '', '', 'SELECT \n    MDC_ORG_CD,\n    DIAG_SUBCAT_CD,\n    death_type,\n    COUNT(DISTINCT INHOS_NO) AS DEATH_PATIENT_CNT\nFROM (\n    SELECT \n        t1.MDC_ORG_CD,\n        t1.INHOS_NO,\n        REGEXP_REPLACE(SUBSTRING(t2.DIAG_CD, 1, 4), \'[^A-Z0-9]\', \'\') AS DIAG_SUBCAT_CD,\n        CASE\n            WHEN t1.DSCG_WAY_NM LIKE \'%死亡%\' THEN \'离院方式死亡\'\n            WHEN t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM = \'非医嘱离院\' THEN \'转归情况死亡\'\n            ELSE NULL\n        END AS death_type\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n        ON t1.INHOS_NO = t2.INHOS_NO\n        AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n    WHERE t2.MAIN_DIAG_FLG = \'1\'\n        AND (t1.DSCG_WAY_NM LIKE \'%死亡%\'\n             OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM = \'非医嘱离院\'))) t\nWHERE death_type IS NOT NULL\nGROUP BY MDC_ORG_CD, DIAG_SUBCAT_CD, death_type\nORDER BY MDC_ORG_CD, DIAG_SUBCAT_CD, death_type;', NULL, NULL, NULL, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"SELECT \\n    MDC_ORG_CD,\\n    DIAG_SUBCAT_CD,\\n    death_type,\\n    COUNT(DISTINCT INHOS_NO) AS DEATH_PATIENT_CNT\\nFROM (\\n    SELECT \\n        t1.MDC_ORG_CD,\\n        t1.INHOS_NO,\\n        REGEXP_REPLACE(SUBSTRING(t2.DIAG_CD, 1, 4), \'[^A-Z0-9]\', \'\') AS DIAG_SUBCAT_CD,\\n        CASE\\n            WHEN t1.DSCG_WAY_NM LIKE \'%死亡%\' THEN \'离院方式死亡\'\\n            WHEN t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM = \'非医嘱离院\' THEN \'转归情况死亡\'\\n            ELSE NULL\\n        END AS death_type\\n    FROM FACT_MDC_RCD_HMPG t1\\n    INNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\\n        ON t1.INHOS_NO = t2.INHOS_NO\\n        AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\\n    WHERE t2.MAIN_DIAG_FLG = \'1\'\\n        AND (t1.DSCG_WAY_NM LIKE \'%死亡%\'\\n             OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM = \'非医嘱离院\'))) t\\nWHERE death_type IS NOT NULL\\nGROUP BY MDC_ORG_CD, DIAG_SUBCAT_CD, death_type\\nORDER BY MDC_ORG_CD, DIAG_SUBCAT_CD, death_type;\", \"count\": 0, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-25 22:54:06', 0.359, '[]', NULL, NULL, 'discharge', 0, '[]', NULL);
INSERT INTO `indicator_execution` VALUES (278, 21, '患者入院 8 小时内查房率', 'manual', 'core18', 'monthly', '2026年4月', 'ratio', 'SQL录入', '', '[{\"time\": \"02:25:23\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"02:25:23\", \"level\": \"info\", \"message\": \"分子结果：3 条记录。\"}, {\"time\": \"02:25:23\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"02:25:23\", \"level\": \"info\", \"message\": \"分母结果：1667 条记录。\"}, {\"time\": \"02:25:23\", \"level\": \"info\", \"message\": \"执行完成。指标值：0.18%（3/1667）\"}]', 'SELECT \n    PRM_KEY,\n    INHOS_NO,\n    MDC_ORG_CD,    \n    MDC_ORG_NM,    \n    ADMN_DT_TM,\n    ODR_OPN_DT_TM,\n    ODR_ITM_TP_NM,\n    DSCG_DT_TM\nFROM (\n    SELECT\n        t1.DSCG_DT_TM,\n        t1.PRM_KEY,\n        t1.INHOS_NO,\n        t2.MDC_ORG_CD, -- 内层：从 t2 医嘱表查出机构代码\n        t2.MDC_ORG_NM, -- 内层：从 t2 医嘱表查出机构名称\n        t1.ADMN_DT_TM,\n        t2.ODR_OPN_DT_TM,\n        t2.ODR_ITM_TP_NM,\n        ROW_NUMBER() OVER (PARTITION BY t1.INHOS_NO ORDER BY t2.ODR_OPN_DT_TM ASC) as rn\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_INHOS_ODR_INFMT t2\n        ON t2.INVLD_FLG = \'0\'\n        AND t2.INHOS_NO = t1.INHOS_NO\n        AND t2.ODR_OPN_DT_TM BETWEEN t1.ADMN_DT_TM \n                                  AND DATE_ADD(t1.ADMN_DT_TM, INTERVAL 8 HOUR)\n        AND (t2.ODR_ITM_TP_NM LIKE \'%检查%\' OR t2.ODR_ITM_TP_NM LIKE \'%治疗%\')\n    WHERE t1.INVLD_FLG = \'0\'\n) temp\nWHERE rn = 1;', 'SELECT DISTINCT\n    t1.INHOS_NO AS \'住院号\',\n    t1.MDC_ORG_CD AS \'机构代码\',   \n    t1.MDC_ORG_NM AS \'机构名称\',  \n    t1.ADMN_DT_TM AS \'入院日期时间\',\n    t1.DSCG_DT_TM AS \'出院日期时间\'\nFROM FACT_ADMN_MDC_HTR_RCD t1\nWHERE t1.INVLD_FLG = \'0\' AND DATE(dscg_dt_tm) BETWEEN \'2026-04-01\' AND \'2026-04-30\'', '', 3, 1667, NULL, 0.18, '3/1667=0.18%', '', '{\"rows\": [{\"prm_key\": \"HMPG_20260405_04\", \"inhos_no\": \"INH_20260405_004\", \"admn_dt_tm\": \"2026-04-04 11:00:00\", \"dscg_dt_tm\": null, \"mdc_org_cd\": \"HOS_001\", \"mdc_org_nm\": \"海南省示范医院\