, \"入院日期时间\": \"2026-04-02 09:30:00\", \"出院日期时间\": \"2026-04-04 14:00:00\"}, {\"住院号\": \"INH_20260405_003\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-03 10:30:00\", \"出院日期时间\": \"2026-04-08 09:00:00\"}, {\"住院号\": \"INH_20260405_004\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-04 11:30:00\", \"出院日期时间\": \"2026-04-10 16:00:00\"}, {\"住院号\": \"INH_20260405_005\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-05 12:30:00\", \"出院日期时间\": \"2026-04-06 11:00:00\"}, {\"住院号\": \"INH_20260405_006\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-01 13:30:00\", \"出院日期时间\": \"2026-04-07 10:00:00\"}, {\"住院号\": \"INH_20260405_007\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-02 14:30:00\", \"出院日期时间\": \"2026-04-09 15:00:00\"}, {\"住院号\": \"INH_20260405_008\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-03 15:30:00\", \"出院日期时间\": \"2026-04-04 09:00:00\"}, {\"住院号\": \"INH_20260405_009\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-04 16:30:00\", \"出院日期时间\": \"2026-04-11 14:00:00\"}, {\"住院号\": \"INH_20260405_010\", \"机构代码\": \"HOS_001\", \"机构名称\": \"海南省示范医院\", \"入院日期时间\": \"2026-04-05 17:30:00\", \"出院日期时间\": \"2026-04-08 10:00:00\"}]}]', NULL);
INSERT INTO `indicator_execution` VALUES (287, 52, '主要手术ICD-9-CM-3四位码种类数', 'manual', 'core18', 'monthly', '2026年4月', 'count', 'SQL录入', '', '[{\"time\": \"02:26:58\", \"level\": \"info\", \"message\": \"执行 SQL...\"}, {\"time\": \"02:26:58\", \"level\": \"info\", \"message\": \"查询结果：1 条记录。\"}, {\"time\": \"02:26:58\", \"level\": \"info\", \"message\": \"执行完成，共 1 人次。\"}]', '', '', 'WITH \nmain_surgery AS (\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\n    SELECT \n        s.INHOS_NO,\n        s.OPRT_CD,\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\n    FROM FACT_MDC_RCD_HMPG_OPRT s\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\n        AND s.OPRT_CD IS NOT NULL\n        AND s.OPRT_CD != \'\'\n)\nSELECT \n    h.MDC_ORG_CD AS \'医疗机构代码\',\n    h.MDC_ORG_NM AS \'医疗机构名称\',\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\nFROM main_surgery ms\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\nWHERE ms.surgery_4code IS NOT NULL \n    AND ms.surgery_4code != \'\'\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\nORDER BY h.MDC_ORG_CD;', NULL, NULL, 1, NULL, '', '', '{\"rows\": [{\"医疗机构代码\": \"HOS_001\", \"医疗机构名称\": \"海南省示范医院\", \"手术四位码种类数\": 16}], \"columns\": [\"医疗机构代码\", \"医疗机构名称\", \"手术四位码种类数\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[{\"sql\": \"WITH \\nmain_surgery AS (\\n    -- 提取主手术记录，并计算四位码键（去除点、横线、空格后取前4位）\\n    SELECT \\n        s.INHOS_NO,\\n        s.OPRT_CD,\\n        UPPER(LEFT(REPLACE(s.OPRT_CD, \'.\', \'\'), 4)) AS surgery_4code\\n    FROM FACT_MDC_RCD_HMPG_OPRT s\\n    WHERE s.MAIN_OPRT_FLG = \'1\'   -- 主手术标识，\\n        AND s.OPRT_CD IS NOT NULL\\n        AND s.OPRT_CD != \'\'\\n)\\nSELECT \\n    h.MDC_ORG_CD AS \'医疗机构代码\',\\n    h.MDC_ORG_NM AS \'医疗机构名称\',\\n    COUNT(DISTINCT ms.surgery_4code) AS \'手术四位码种类数\'\\nFROM main_surgery ms\\nINNER JOIN FACT_MDC_RCD_HMPG h ON ms.INHOS_NO = h.INHOS_NO\\nWHERE ms.surgery_4code IS NOT NULL \\n    AND ms.surgery_4code != \'\'\\nGROUP BY h.MDC_ORG_CD, h.MDC_ORG_NM\\nORDER BY h.MDC_ORG_CD;\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-27 02:26:59', 0.35, '[]', 'monthly', '2026-04', 'discharge', 0, '[]', NULL);
INSERT INTO `indicator_execution` VALUES (288, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'monthly', '2026年4月', 'count', 'SQL录入', '', '[{\"time\": \"16:22:33\", \"level\": \"info\", \"message\": \"执行复合计数型指标 SQL...\"}, {\"time\": \"16:22:33\", \"level\": \"info\", \"message\": \"SQL 执行完成，共 6 条记录。\"}, {\"time\": \"16:22:33\", \"level\": \"info\", \"message\": \"总数量：6，TOP20排行已生成。\"}]', '', '', 'SELECT\n    UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 5)) AS sub_category,\n    COUNT(DISTINCT UPPER(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'))) AS disease_cnt\nFROM FACT_MDC_RCD_HMPG t1\nINNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n    ON t1.INHOS_NO = t2.INHOS_NO\n   AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t2.MAIN_DIAG_FLG = \'1\'\n  AND t2.DIAG_CD NOT IN (\'\', \'-\')\n  AND t1.DSCG_DT_TM IS NOT NULL AND DATE(dscg_dt_tm) BETWEEN \'2026-04-01\' AND \'2026-04-30\' GROUP BY sub_category\nORDER BY disease_cnt DESC\nLIMIT 50', 6, NULL, 6, NULL, '', '', '{\"rows\": [{\"disease_cnt\": 1, \"sub_category\": \"A099\"}, {\"disease_cnt\": 1, \"sub_category\": \"F510\"}, {\"disease_cnt\": 1, \"sub_category\": \"I251\"}, {\"disease_cnt\": 1, \"sub_category\": \"I639\"}, {\"disease_cnt\": 1, \"sub_category\": \"J189\"}, {\"disease_cnt\": 1, \"sub_category\": \"M069\"}], \"columns\": [\"sub_category\", \"disease_cnt\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[]', '', '', 0, '', '', 'success', '2026-05-27 16:22:34', 0.199, '[]', 'monthly', '2026-04', 'discharge', 0, '[]', '[{\"disease_cnt\": 1, \"ranking_key\": \"A099\", \"sub_category\": \"A099\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"F510\", \"sub_category\": \"F510\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"I251\", \"sub_category\": \"I251\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"I639\", \"sub_category\": \"I639\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"J189\", \"sub_category\": \"J189\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"M069\", \"sub_category\": \"M069\", \"ranking_value\": 1.0}]');
INSERT INTO `indicator_execution` VALUES (289, 54, '住院患者死亡疾病谱', 'manual', 'core18', 'monthly', '2026年4月', 'count', 'SQL录入', '', '[{\"time\": \"16:25:36\", \"level\": \"info\", \"message\": \"执行复合计数型指标 SQL...\"}, {\"time\": \"16:25:36\", \"level\": \"info\", \"message\": \"SQL 执行完成，共 0 条记录。\"}, {\"time\": \"16:25:36\", \"level\": \"info\", \"message\": \"总数量：0，TOP20排行已生成。\"}]', '', '', 'SELECT\n    UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 5)) AS sub_category,\n    CASE\n        WHEN t1.DSCG_WAY_NM LIKE \'%死亡%\' THEN \'离院方式死亡\'\n        WHEN t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱%\' THEN \'转归死亡\'\n        ELSE NULL\n    END AS death_type,\n    COUNT(DISTINCT t1.INHOS_NO) AS death_patient_cnt\nFROM FACT_MDC_RCD_HMPG t1\nINNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n    ON t1.INHOS_NO = t2.INHOS_NO\n   AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t2.MAIN_DIAG_FLG = \'1\'\n  AND t2.DIAG_CD NOT IN (\'\',\'-\')\n  AND (\n      t1.DSCG_WAY_NM LIKE \'%死亡%\'\n      OR (t1.TNOVR_CDT_NM LIKE \'%死亡%\' AND t1.DSCG_WAY_NM LIKE \'%非医嘱%\')\n  )\nGROUP BY sub_category, death_type\nHAVING death_type IS NOT NULL\nORDER BY death_patient_cnt DESC\nLIMIT 50', 0, NULL, 0, NULL, '', '', '{\"rows\": [], \"columns\": []}', '{\"rows\": [], \"columns\": []}', '', '', '', '[]', '', '', 0, '', '', 'success', '2026-05-27 16:25:37', 0.17, '[]', 'monthly', '2026-04', 'discharge', 0, '[]', '[]');
