INSERT INTO `indicator_execution` VALUES (298, 51, '主要诊断ICD-10编码亚目种类数', 'manual', 'core18', 'monthly', '2026年4月', 'count', 'SQL录入', '', '[{\"time\": \"16:44:39\", \"level\": \"info\", \"message\": \"[HOS_001] 开始执行...\"}, {\"time\": \"16:44:39\", \"level\": \"info\", \"message\": \"[HOS_001] SQL完成，共 6 条记录。\"}, {\"time\": \"16:44:39\", \"level\": \"info\", \"message\": \"[HOS_001] 总数：6，排行TOP20已生成。\"}, {\"time\": \"16:44:39\", \"level\": \"info\", \"message\": \"全省汇总：总数量=6，全局TOP20排行已生成。\"}]', '', '', 'SELECT\n    UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 5)) AS sub_category,\n    COUNT(DISTINCT UPPER(REPLACE(REPLACE(REPLACE(t2.DIAG_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'))) AS disease_cnt\nFROM FACT_MDC_RCD_HMPG t1\nINNER JOIN FACT_MDC_RCD_HMPG_DIAG t2\n    ON t1.INHOS_NO = t2.INHOS_NO\n   AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t2.MAIN_DIAG_FLG = \'1\'\n  AND t2.DIAG_CD NOT IN (\'\', \'-\')\n  AND t1.DSCG_DT_TM IS NOT NULL\nGROUP BY sub_category\nORDER BY disease_cnt DESC\nLIMIT 50', 6, NULL, 6, NULL, '', '', '{\"rows\": [{\"disease_cnt\": 1, \"sub_category\": \"A099\"}, {\"disease_cnt\": 1, \"sub_category\": \"F510\"}, {\"disease_cnt\": 1, \"sub_category\": \"I251\"}, {\"disease_cnt\": 1, \"sub_category\": \"I639\"}, {\"disease_cnt\": 1, \"sub_category\": \"J189\"}, {\"disease_cnt\": 1, \"sub_category\": \"M069\"}], \"columns\": [\"sub_category\", \"disease_cnt\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[]', '', '', 0, '', '', 'success', '2026-05-27 16:44:40', 0.178, '[\"HOS_001\"]', 'monthly', '2026-04', 'discharge', 1, '[{\"count\": 6, \"error\": null, \"status\": \"success\", \"preview_data\": [{\"disease_cnt\": 1, \"sub_category\": \"A099\"}, {\"disease_cnt\": 1, \"sub_category\": \"F510\"}, {\"disease_cnt\": 1, \"sub_category\": \"I251\"}, {\"disease_cnt\": 1, \"sub_category\": \"I639\"}, {\"disease_cnt\": 1, \"sub_category\": \"J189\"}, {\"disease_cnt\": 1, \"sub_category\": \"M069\"}], \"subitem_data\": [{\"disease_cnt\": 1, \"ranking_key\": \"A099\", \"sub_category\": \"A099\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"F510\", \"sub_category\": \"F510\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"I251\", \"sub_category\": \"I251\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"I639\", \"sub_category\": \"I639\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"J189\", \"sub_category\": \"J189\", \"ranking_value\": 1.0}, {\"disease_cnt\": 1, \"ranking_key\": \"M069\", \"sub_category\": \"M069\", \"ranking_value\": 1.0}], \"hospital_code\": \"HOS_001\", \"hospital_name\": \"HOS_001\", \"numerator_count\": 6, \"preview_columns\": [\"sub_category\", \"disease_cnt\"]}]', '[{\"ranking_key\": \"A099\", \"ranking_value\": 1.0}, {\"ranking_key\": \"F510\", \"ranking_value\": 1.0}, {\"ranking_key\": \"I251\", \"ranking_value\": 1.0}, {\"ranking_key\": \"I639\", \"ranking_value\": 1.0}, {\"ranking_key\": \"J189\", \"ranking_value\": 1.0}, {\"ranking_key\": \"M069\", \"ranking_value\": 1.0}]');
INSERT INTO `indicator_execution` VALUES (299, 52, '主要手术ICD-9-CM-3四位码种类数', 'manual', 'core18', 'monthly', '2026年4月', 'count', 'SQL录入', '', '[{\"time\": \"16:46:19\", \"level\": \"info\", \"message\": \"执行复合计数型指标 SQL...\"}, {\"time\": \"16:46:19\", \"level\": \"info\", \"message\": \"SQL 执行完成，共 5 条记录。\"}, {\"time\": \"16:46:19\", \"level\": \"info\", \"message\": \"总数量：5，TOP20排行已生成。\"}]', '', '', 'SELECT\n    four_digit_code,\n    SUM(disease_cnt) AS surgery_cnt\nFROM (\n    SELECT\n        UPPER(LEFT(REPLACE(REPLACE(REPLACE(t2.OPRT_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'), 4)) AS four_digit_code,\n        COUNT(DISTINCT UPPER(REPLACE(REPLACE(REPLACE(t2.OPRT_CD, \'.\', \'\'), \'-\', \'\'), \' \', \'\'))) AS disease_cnt\n    FROM FACT_MDC_RCD_HMPG t1\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT t2\n        ON t1.INHOS_NO = t2.INHOS_NO\n       AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\n    WHERE t1.DSCG_DT_TM IS NOT NULL\n      AND t2.MAIN_OPRT_FLG = \'1\'\n      AND t2.OPRT_CD NOT IN (\'\',\'-\') AND DATE(dscg_dt_tm) BETWEEN \'2026-04-01\' AND \'2026-04-30\' GROUP BY four_digit_code\n) AS all_surgeries\nGROUP BY four_digit_code\nORDER BY surgery_cnt DESC\nLIMIT 50', 5, NULL, 5, NULL, '', '', '{\"rows\": [{\"surgery_cnt\": 1.0, \"four_digit_code\": \"0152\"}, {\"surgery_cnt\": 1.0, \"four_digit_code\": \"064\"}, {\"surgery_cnt\": 1.0, \"four_digit_code\": \"4901\"}, {\"surgery_cnt\": 1.0, \"four_digit_code\": \"5300\"}, {\"surgery_cnt\": 1.0, \"four_digit_code\": \"6662\"}], \"columns\": [\"four_digit_code\", \"surgery_cnt\"]}', '{\"rows\": [], \"columns\": []}', '', '', '', '[]', '', '', 0, '', '', 'success', '2026-05-27 16:46:19', 0.177, '[]', 'monthly', '2026-04', 'discharge', 0, '[]', '[{\"ranking_key\": \"0152\", \"surgery_cnt\": 1.0, \"ranking_value\": 1.0, \"four_digit_code\": \"0152\"}, {\"ranking_key\": \"064\", \"surgery_cnt\": 1.0, \"ranking_value\": 1.0, \"four_digit_code\": \"064\"}, {\"ranking_key\": \"4901\", \"surgery_cnt\": 1.0, \"ranking_value\": 1.0, \"four_digit_code\": \"4901\"}, {\"ranking_key\": \"5300\", \"surgery_cnt\": 1.0, \"ranking_value\": 1.0, \"four_digit_code\": \"5300\"}, {\"ranking_key\": \"6662\", \"surgery_cnt\": 1.0, \"ranking_value\": 1.0, \"four_digit_code\": \"6662\"}]');
INSERT INTO `indicator_execution` VALUES (300, 59, '住院患者围手术期死亡率', 'manual', 'core18', 'monthly', '2026年4月', 'ratio', 'SQL录入', '', '[{\"time\": \"22:57:34\", \"level\": \"info\", \"message\": \"执行分子 SQL...\"}, {\"time\": \"22:57:34\", \"level\": \"info\", \"message\": \"分子结果：1 条记录。\"}, {\"time\": \"22:57:34\", \"level\": \"info\", \"message\": \"执行分母 SQL...\"}, {\"time\": \"22:57:34\", \"level\": \"info\", \"message\": \"分母结果：7 条记录。\"}, {\"time\": \"22:57:34\", \"level\": \"info\", \"message\": \"执行完成。指标值：14.2857%（1/7）\"}]', 'WITH\ndenominator_base AS (\n    SELECT DISTINCT h.INHOS_NO, h.MDC_ORG_CD\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL\n      AND TRIM(o.OPRT_CD) <> \'\'\n),\ndeath_record_time AS (\n    SELECT\n        s.INHOS_NO,\n        s.MDC_ORG_CD,\n        STR_TO_DATE(\n            REGEXP_REPLACE(\n                REGEXP_REPLACE(\n                    REGEXP_REPLACE(\n                        REGEXP_REPLACE(\n                            REGEXP_REPLACE(\n                                REGEXP_SUBSTR(s.ITM_VLU,\n                                    \'死亡时间[:：][[:space:]]*[0-9]{4}年[0-9]{1,2}月[0-9]{1,2}日[[:space:]]*[0-9]{1,2}时[0-9]{2}分|死亡时间[:：][[:space:]]*[0-9]{4}-[0-9]{1,2}-[0-9]{1,2}[[:space:]]+[0-9]{1,2}:[0-9]{2}\'),\n                                \'日[[:space:]]*\', \' \'\n                            ),\n                            \'[年月]\', \'-\'\n                        ),\n                        \'死亡时间[:：][[:space:]]*\', \'\'\n                    ),\n                    \'时\', \':\'\n                ),\n                \'分\', \'\'\n            ),\n            \'%Y-%m-%d %H:%i\'\n        ) AS DEATH_DT_TM\n    FROM FACT_INHOS_CRS_RCD_S s\n    WHERE s.RCD_TP_NM LIKE \'%死亡记录%\'\n      AND s.ITM_NM = \'文本主体\'\n      AND s.ITM_VLU LIKE \'%死亡时间%\'\n),\nclear_death_with_surgery AS (\n    SELECT\n        h.INHOS_NO,\n        h.MDC_ORG_CD,\n        o.OPRT_DT,\n        d.DEATH_DT_TM,\n        CASE WHEN DATE(d.DEATH_DT_TM) = DATE(o.OPRT_DT) THEN 1 ELSE 0 END AS death_same_day,\n        CASE WHEN d.DEATH_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, d.DEATH_DT_TM) <= 24\n            THEN 1 ELSE 0 END AS death_within_24h,\n        CASE WHEN d.DEATH_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, d.DEATH_DT_TM) <= 48\n            THEN 1 ELSE 0 END AS death_within_48h\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    INNER JOIN death_record_time d\n        ON h.INHOS_NO = d.INHOS_NO AND h.MDC_ORG_CD = d.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL AND TRIM(o.OPRT_CD) <> \'\'\n      AND h.DSCG_WAY_NM = \'死亡\'\n      AND d.DEATH_DT_TM IS NOT NULL\n      AND o.OPRT_DT IS NOT NULL\n),\nproxy_death_with_surgery AS (\n    SELECT\n        h.INHOS_NO,\n        h.MDC_ORG_CD,\n        o.OPRT_DT,\n        h.DSCG_DT_TM AS DEATH_DT_TM,\n        CASE WHEN DATE(h.DSCG_DT_TM) = DATE(o.OPRT_DT) THEN 1 ELSE 0 END AS death_same_day,\n        CASE WHEN h.DSCG_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, h.DSCG_DT_TM) <= 24\n            THEN 1 ELSE 0 END AS death_within_24h,\n        CASE WHEN h.DSCG_DT_TM >= o.OPRT_DT\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, h.DSCG_DT_TM) <= 48\n            THEN 1 ELSE 0 END AS death_within_48h\n    FROM FACT_MDC_RCD_HMPG h\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\n    WHERE h.DSCG_DT_TM IS NOT NULL\n      AND o.OPRT_CD IS NOT NULL AND TRIM(o.OPRT_CD) <> \'\'\n      AND h.TNOVR_CDT_NM = \'死亡\'\n      AND h.DSCG_WAY_NM = \'非医嘱离院\'\n      AND o.OPRT_DT IS NOT NULL\n),\npatient_flags AS (\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        MAX(death_same_day) AS clear_death_same_day,\n        MAX(death_within_24h) AS clear_death_within_24h,\n        MAX(death_within_48h) AS clear_death_within_48h,\n        0 AS proxy_death_same_day,\n        0 AS proxy_death_within_24h,\n        0 AS proxy_death_within_48h\n    FROM clear_death_with_surgery\n    GROUP BY INHOS_NO, MDC_ORG_CD\n    UNION ALL\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        0, 0, 0,\n        MAX(death_same_day),\n        MAX(death_within_24h),\n        MAX(death_within_48h)\n    FROM proxy_death_with_surgery\n    GROUP BY INHOS_NO, MDC_ORG_CD\n),\npatient_agg AS (\n    SELECT\n        INHOS_NO,\n        MDC_ORG_CD,\n        MAX(clear_death_same_day) AS clear_same_day,\n        MAX(clear_death_within_24h) AS clear_24h,\n        MAX(clear_death_within_48h) AS clear_48h,\n        MAX(proxy_death_same_day) AS proxy_same_day,\n        MAX(proxy_death_within_24h) AS proxy_24h,\n        MAX(proxy_death_within_48h) AS proxy_48h\n    FROM patient_flags\n    GROUP BY INHOS_NO, MDC_ORG_CD\n)\nSELECT\n    COUNT(DISTINCT d.INHOS_NO, d.MDC_ORG_CD) AS denominator_surgery_patients,\n\n    SUM(COALESCE(a.clear_same_day, 0)) AS numerator_clear_death_same_day,\n    SUM(COALESCE(a.clear_24h, 0))       AS numerator_clear_death_24h,\n    SUM(COALESCE(a.clear_48h, 0))       AS numerator_clear_death_48h,\n\n    SUM(COALESCE(a.proxy_same_day, 0))  AS numerator_proxy_death_same_day,\n    SUM(COALESCE(a.proxy_24h, 0))       AS numerator_proxy_death_24h,\n    SUM(COALESCE(a.proxy_48h, 0))       AS numerator_proxy_death_48h\nFROM denominator_base d\nLEFT JOIN patient_agg a\n    ON d.INHOS_NO = a.INHOS_NO AND d.MDC_ORG_CD = a.MDC_ORG_CD', 'SELECT t1.INHOS_NO, t1.MDC_ORG_CD, t2.OPRT_DT, t1.DSCG_DT_TM\nFROM FACT_MDC_RCD_HMPG t1\nJOIN (\n    SELECT INHOS_NO, MDC_ORG_CD, OPRT_DT\n    FROM (\n        SELECT INHOS_NO, MDC_ORG_CD, OPRT_DT, ROW_NUMBER() OVER (PARTITION BY INHOS_NO ORDER BY OPRT_DT DESC) rn\n        FROM FACT_MDC_RCD_HMPG_OPRT\n        WHERE INVLD_FLG = \'0\'\n    ) t_sub\n    WHERE rn = 1\n) t2 ON t1.INHOS_NO = t2.INHOS_NO AND t1.MDC_ORG_CD = t2.MDC_ORG_CD\nWHERE t1.INVLD_FLG = \'0\'\n  AND t1.DSCG_DT_TM IS NOT NULL AND DATE(dscg_dt_tm) BETWEEN \'2026-04-01\' AND \'2026-04-30\'', '', 1, 7, NULL, 14.2857, '1/7=14.2857%', '', '{\"rows\": [{\"numerator_clear_death_24h\": 0.0, \"numerator_clear_death_48h\": 0.0, \"numerator_proxy_death_24h\": 0.0, \"numerator_proxy_death_48h\": 0.0, \"denominator_surgery_patients\": 5, \"numerator_clear_death_same_day\": 0.0, \"numerator_proxy_death_same_day\": 0.0}], \"columns\": [\"denominator_surgery_patients\", \"numerator_clear_death_same_day\", \"numerator_clear_death_24h\", \"numerator_clear_death_48h\", \"numerator_proxy_death_same_day\", \"numerator_proxy_death_24h\", \"numerator_proxy_death_48h\"]}', '{\"rows\": [{\"oprt_dt\": \"2026-04-03 08:30:00\", \"inhos_no\": \"INH_20260405_022\", \"dscg_dt_tm\": \"2026-04-03 19:00:00\", \"mdc_org_cd\": \"HOS_001\"}, {\"oprt_dt\": \"2026-04-01 22:30:00\", \"inhos_no\": \"INH_20260405_029\", \"dscg_dt_tm\": \"2026-04-02 02:15:00\", \"mdc_org_cd\": \"HOS_001\"}, {\"oprt_dt\": \"2026-04-03 08:30:00\", \"inhos_no\": \"INH_20260405_022\", \"dscg_dt_tm\": \"2026-04-15 09:00:00\", \"mdc_org_cd\": \"HOS_001\"}, {\"oprt_dt\": \"2026-04-01 22:30:00\", \"inhos_no\": \"INH_20260405_029\", \"dscg_dt_tm\": \"2026-04-19 15:00:00\", \"mdc_org_cd\": \"HOS_001\"}, {\"oprt_dt\": \"2026-04-07 09:00:00\", \"inhos_no\": \"INH_20260407_019\", \"dscg_dt_tm\": \"2026-04-10 09:00:00\", \"mdc_org_cd\": \"HOS_001\"}, {\"oprt_dt\": \"2026-04-07 09:00:00\", \"inhos_no\": \"INH_20260407_020\", \"dscg_dt_tm\": \"2026-04-11 11:00:00\", \"mdc_org_cd\": \"HOS_001\"}, {\"oprt_dt\": \"2026-04-07 15:20:00\", \"inhos_no\": \"INH_20260407_022\", \"dscg_dt_tm\": \"2026-04-09 10:00:00\", \"mdc_org_cd\": \"HOS_001\"}], \"columns\": [\"inhos_no\", \"mdc_org_cd\", \"oprt_dt\", \"dscg_dt_tm\"]}', '', '', '', '[{\"sql\": \"WITH\\ndenominator_base AS (\\n    SELECT DISTINCT h.INHOS_NO, h.MDC_ORG_CD\\n    FROM FACT_MDC_RCD_HMPG h\\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\\n    WHERE h.DSCG_DT_TM IS NOT NULL\\n      AND o.OPRT_CD IS NOT NULL\\n      AND TRIM(o.OPRT_CD) <> \'\'\\n),\\ndeath_record_time AS (\\n    SELECT\\n        s.INHOS_NO,\\n        s.MDC_ORG_CD,\\n        STR_TO_DATE(\\n            REGEXP_REPLACE(\\n                REGEXP_REPLACE(\\n                    REGEXP_REPLACE(\\n                        REGEXP_REPLACE(\\n                            REGEXP_REPLACE(\\n                                REGEXP_SUBSTR(s.ITM_VLU,\\n                                    \'死亡时间[:：][[:space:]]*[0-9]{4}年[0-9]{1,2}月[0-9]{1,2}日[[:space:]]*[0-9]{1,2}时[0-9]{2}分|死亡时间[:：][[:space:]]*[0-9]{4}-[0-9]{1,2}-[0-9]{1,2}[[:space:]]+[0-9]{1,2}:[0-9]{2}\'),\\n                                \'日[[:space:]]*\', \' \'\\n                            ),\\n                            \'[年月]\', \'-\'\\n                        ),\\n                        \'死亡时间[:：][[:space:]]*\', \'\'\\n                    ),\\n                    \'时\', \':\'\\n                ),\\n                \'分\', \'\'\\n            ),\\n            \'%Y-%m-%d %H:%i\'\\n        ) AS DEATH_DT_TM\\n    FROM FACT_INHOS_CRS_RCD_S s\\n    WHERE s.RCD_TP_NM LIKE \'%死亡记录%\'\\n      AND s.ITM_NM = \'文本主体\'\\n      AND s.ITM_VLU LIKE \'%死亡时间%\'\\n),\\nclear_death_with_surgery AS (\\n    SELECT\\n        h.INHOS_NO,\\n        h.MDC_ORG_CD,\\n        o.OPRT_DT,\\n        d.DEATH_DT_TM,\\n        CASE WHEN DATE(d.DEATH_DT_TM) = DATE(o.OPRT_DT) THEN 1 ELSE 0 END AS death_same_day,\\n        CASE WHEN d.DEATH_DT_TM >= o.OPRT_DT\\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, d.DEATH_DT_TM) <= 24\\n            THEN 1 ELSE 0 END AS death_within_24h,\\n        CASE WHEN d.DEATH_DT_TM >= o.OPRT_DT\\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, d.DEATH_DT_TM) <= 48\\n            THEN 1 ELSE 0 END AS death_within_48h\\n    FROM FACT_MDC_RCD_HMPG h\\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\\n    INNER JOIN death_record_time d\\n        ON h.INHOS_NO = d.INHOS_NO AND h.MDC_ORG_CD = d.MDC_ORG_CD\\n    WHERE h.DSCG_DT_TM IS NOT NULL\\n      AND o.OPRT_CD IS NOT NULL AND TRIM(o.OPRT_CD) <> \'\'\\n      AND h.DSCG_WAY_NM = \'死亡\'\\n      AND d.DEATH_DT_TM IS NOT NULL\\n      AND o.OPRT_DT IS NOT NULL\\n),\\nproxy_death_with_surgery AS (\\n    SELECT\\n        h.INHOS_NO,\\n        h.MDC_ORG_CD,\\n        o.OPRT_DT,\\n        h.DSCG_DT_TM AS DEATH_DT_TM,\\n        CASE WHEN DATE(h.DSCG_DT_TM) = DATE(o.OPRT_DT) THEN 1 ELSE 0 END AS death_same_day,\\n        CASE WHEN h.DSCG_DT_TM >= o.OPRT_DT\\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, h.DSCG_DT_TM) <= 24\\n            THEN 1 ELSE 0 END AS death_within_24h,\\n        CASE WHEN h.DSCG_DT_TM >= o.OPRT_DT\\n             AND TIMESTAMPDIFF(HOUR, o.OPRT_DT, h.DSCG_DT_TM) <= 48\\n            THEN 1 ELSE 0 END AS death_within_48h\\n    FROM FACT_MDC_RCD_HMPG h\\n    INNER JOIN FACT_MDC_RCD_HMPG_OPRT o\\n        ON h.INHOS_NO = o.INHOS_NO AND h.MDC_ORG_CD = o.MDC_ORG_CD\\n    WHERE h.DSCG_DT_TM IS NOT NULL\\n      AND o.OPRT_CD IS NOT NULL AND TRIM(o.OPRT_CD) <> \'\'\\n      AND h.TNOVR_CDT_NM = \'死亡\'\\n      AND h.DSCG_WAY_NM = \'非医嘱离院\'\\n      AND o.OPRT_DT IS NOT NULL\\n),\\npatient_flags AS (\\n    SELECT\\n        INHOS_NO,\\n        MDC_ORG_CD,\\n        MAX(death_same_day) AS clear_death_same_day,\\n        MAX(death_within_24h) AS clear_death_within_24h,\\n        MAX(death_within_48h) AS clear_death_within_48h,\\n        0 AS proxy_death_same_day,\\n        0 AS proxy_death_within_24h,\\n        0 AS proxy_death_within_48h\\n    FROM clear_death_with_surgery\\n    GROUP BY INHOS_NO, MDC_ORG_CD\\n    UNION ALL\\n    SELECT\\n        INHOS_NO,\\n        MDC_ORG_CD,\\n        0, 0, 0,\\n        MAX(death_same_day),\\n        MAX(death_within_24h),\\n        MAX(death_within_48h)\\n    FROM proxy_death_with_surgery\\n    GROUP BY INHOS_NO, MDC_ORG_CD\\n),\\npatient_agg AS (\\n    SELECT\\n        INHOS_NO,\\n        MDC_ORG_CD,\\n        MAX(clear_death_same_day) AS clear_same_day,\\n        MAX(clear_death_within_24h) AS clear_24h,\\n        MAX(clear_death_within_48h) AS clear_48h,\\n        MAX(proxy_death_same_day) AS proxy_same_day,\\n        MAX(proxy_death_within_24h) AS proxy_24h,\\n        MAX(proxy_death_within_48h) AS proxy_48h\\n    FROM patient_flags\\n    GROUP BY INHOS_NO, MDC_ORG_CD\\n)\\nSELECT\\n    COUNT(DISTINCT d.INHOS_NO, d.MDC_ORG_CD) AS denominator_surgery_patients,\\n\\n    SUM(COALESCE(a.clear_same_day, 0)) AS numerator_clear_death_same_day,\\n    SUM(COALESCE(a.clear_24h, 0))       AS numerator_clear_death_24h,\\n    SUM(COALESCE(a.clear_48h, 0))       AS numerator_clear_death_48h,\\n\\n    SUM(COALESCE(a.proxy_same_day, 0))  AS numerator_proxy_death_same_day,\\n    SUM(COALESCE(a.proxy_24h, 0))       AS numerator_proxy_death_24h,\\n    SUM(COALESCE(a.proxy_48h, 0))       AS numerator_proxy_death_48h\\nFROM denominator_base d\\nLEFT JOIN patient_agg a\\n    ON d.INHOS_NO = a.INHOS_NO AND d.MDC_ORG_CD = a.MDC_ORG_CD\", \"count\": 1, \"error\": null, \"attempt\": 1}]', '', '', 0, '', '', 'success', '2026-05-27 22:57:34', 0.839, '[]', 'monthly', '2026-04', 'discharge', 0, '[]', 'null');

